function shiftDate(deltaDays){
  const d = new Date();
  d.setDate(d.getDate()+deltaDays);
  return d.toISOString().slice(0,10);
}

let DB = null;
let SESSION = null; // {username, role}
let currentPage = 'dashboard';
const charts = {}; // chart.js instances

// ---------- PERSISTENCE ----------
function loadDB(){
  const raw = localStorage.getItem(STORAGE_KEY);
  if(raw){
    try{
      DB = JSON.parse(raw);
      // backfill any missing top-level keys for forward-compat
      const def = defaultData();
      for(const k in def){ if(!(k in DB)) DB[k] = def[k]; }
      // backfill missing seq keys
      for(const k in def.seq){ if(!(k in DB.seq)) DB.seq[k] = def.seq[k]; }
      // MIGRASI: jika jenisSamping kosong tapi jenisBeras masih punya Menir/Bekatul/Sekam,
      // pindahkan ke jenisSamping (data lama sebelum pemisahan master)
      if(!DB.jenisSamping || DB.jenisSamping.length === 0){
        DB.jenisSamping = ['Bekatul','Menir','Sekam'];
      }
      if(!DB.jenisBahanBaku) DB.jenisBahanBaku = ['Pecah Kulit Ciherang','Pecah Kulit IR64','Pecah Kulit Inpari','Pecah Kulit Logawa'];

      // ============================================================
      // MIGRASI KRITIS: Hapus double-entry kasbank dari bug lama.
      // Bug: savePembelian mencatat DP dua kali:
      //   (1) entry utama 'Pembelian Gabah' (sourceId=id, keluar=dp)
      //   (2) entry 'DP Pembelian'          (refId=id,    keluar=dp)
      // Fix: set keluar entry utama (sourceId) menjadi 0 jika ada entry DP/Pelunasan terkait.
      // ============================================================
      const pembelianIds = new Set((DB.pembelian||[]).map(p=>p.id));
      const dpCategories = new Set(['DP Pembelian','Pelunasan Hutang Supplier']);
      // Faktur yang punya entry refId (DP atau Pelunasan)
      const refIdSets = new Set();
      (DB.kasbank||[]).forEach(k=>{ if(dpCategories.has(k.kategori) && k.refId) refIdSets.add(k.refId); });
      // Entry utama (sourceId) yang punya refId duplicate — set keluar=0
      let fixCount = 0;
      (DB.kasbank||[]).forEach(k=>{
        if(k.sourceId && pembelianIds.has(k.sourceId) && refIdSets.has(k.sourceId)){
          if(Number(k.keluar||0) > 0){
            k.keluar = 0;
            fixCount++;
          }
        }
      });
      if(fixCount > 0){
        console.log(`[loadDB] Fixed ${fixCount} double-entry kasbank records.`);
      }

      // Status Belum Lunas tapi sudah bayar penuh → update status Lunas
      (DB.pembelian||[]).forEach(p=>{
        if(p.status !== 'Belum Lunas') return;
        const via_kb = (DB.kasbank||[])
          .filter(k=>(k.kategori==='Pelunasan Hutang Supplier'||k.kategori==='DP Pembelian') && k.refId===p.id)
          .reduce((s,k)=>s+Number(k.keluar||0), 0);
        const dp_kb = (DB.kasbank||[]).filter(k=>k.kategori==='DP Pembelian' && k.refId===p.id).reduce((s,k)=>s+Number(k.keluar||0), 0);
        const legacy_dp = dp_kb===0 ? Number(p.dp||0) : 0;
        const total_bayar = via_kb + legacy_dp;
        if(total_bayar >= Number(p.total||0) && Number(p.total||0) > 0){
          p.status = 'Lunas';
        }
      });
      // MIGRASI: Pastikan struktur Backup Enterprise Sprint 10 ada
      if(!DB.backupHistory) DB.backupHistory = [];

      // MIGRASI: Pastikan struktur Dokumen Sprint 9 ada
      if(!DB.purchaseOrder) DB.purchaseOrder = [];
      if(!DB.seq.doc) DB.seq.doc = {};

      // MIGRASI: Pastikan struktur Gudang Sprint 8 ada
      if(!DB.lotStok) DB.lotStok = [];
      if(!DB.stockOpname) DB.stockOpname = [];
      if(!DB.stokMinimumMaster) DB.stokMinimumMaster = {};
      if(!DB.seq.opname) DB.seq.opname = 0;
      if(!DB.seq.lot)    DB.seq.lot    = 0;
      // Default stok minimum untuk item utama jika belum diset
      const defaultMin = {
        'Premium':500, 'Medium':500, 'Menir':100, 'Bekatul':100, 'Sekam':50, 'PK':300,
      };
      Object.keys(defaultMin).forEach(k=>{
        if(!(k in DB.stokMinimumMaster)) DB.stokMinimumMaster[k] = defaultMin[k];
      });
      (DB.jenisGabah||[]).forEach(j=>{
        if(!(j in DB.stokMinimumMaster)) DB.stokMinimumMaster[j] = 1000;
      });

      // MIGRASI: Pastikan DB.mesin dan DB.serviceLog ada (Sprint 7)
      if(!DB.mesin || !DB.mesin.length){
        DB.mesin = [
          {id:'msn-1',kode:'MSN-001',nama:'Husker',   tipe:'Husker',   statusUnit:'Aktif',jamOperasi:0,jamServiceInterval:500, jamTerakhirService:0,tglServiceBerikutnya:'',lokasi:'Ruang Giling A',catatan:''},
          {id:'msn-2',kode:'MSN-002',nama:'Polisher',  tipe:'Polisher', statusUnit:'Aktif',jamOperasi:0,jamServiceInterval:400, jamTerakhirService:0,tglServiceBerikutnya:'',lokasi:'Ruang Giling A',catatan:''},
          {id:'msn-3',kode:'MSN-003',nama:'Separator', tipe:'Separator',statusUnit:'Aktif',jamOperasi:0,jamServiceInterval:600, jamTerakhirService:0,tglServiceBerikutnya:'',lokasi:'Ruang Giling B',catatan:''},
          {id:'msn-4',kode:'MSN-004',nama:'Elevator',  tipe:'Elevator', statusUnit:'Aktif',jamOperasi:0,jamServiceInterval:800, jamTerakhirService:0,tglServiceBerikutnya:'',lokasi:'Area Penerimaan',catatan:''},
          {id:'msn-5',kode:'MSN-005',nama:'Destoner',  tipe:'Destoner', statusUnit:'Aktif',jamOperasi:0,jamServiceInterval:1000,jamTerakhirService:0,tglServiceBerikutnya:'',lokasi:'Ruang Giling A',catatan:''},
        ];
      }
      if(!DB.serviceLog) DB.serviceLog = [];
      if(!DB.seq.service) DB.seq.service = 0;
      // Backfill field baru pada mesin lama
      (DB.mesin||[]).forEach(m=>{
        if(m.jamOperasi        === undefined) m.jamOperasi        = 0;
        if(m.jamTerakhirService=== undefined) m.jamTerakhirService= 0;
        if(m.jamServiceInterval=== undefined) m.jamServiceInterval= 500;
        if(m.statusUnit        === undefined) m.statusUnit        = 'Aktif';
        if(m.tglServiceBerikutnya===undefined)m.tglServiceBerikutnya='';
        if(m.lokasi            === undefined) m.lokasi            = '';
        if(m.catatan           === undefined) m.catatan           = '';
      });

      // MIGRASI: Pastikan DB.jurnal ada (Sprint 5)
      if(!DB.jurnal) DB.jurnal = [];

      // MIGRASI: Pastikan DB.maklon ada (Sprint 2)
      if(!DB.maklon) DB.maklon = [];
      if(!DB.seq.maklon) DB.seq.maklon = 0;
      // Backfill field baru pada record maklon lama
      (DB.maklon||[]).forEach(m=>{
        if(m.sekam   === undefined) m.sekam   = 0;
        if(m.menir   === undefined) m.menir   = 0;
        if(m.status  === undefined) m.status  = 'Selesai';
        if(m.kasEntry=== undefined) m.kasEntry= null;
      });

      // MIGRASI: Tambah field pk & sekam pada batch produksi lama yang belum punya
      // (backward compat — batch lama hanya punya gabah, premium, medium, menir, bekatul)
      let migrasiProduksi = 0;
      (DB.produksi||[]).forEach(r=>{
        if(r.pk === undefined){ r.pk = 0; migrasiProduksi++; }
        if(r.sekam === undefined){ r.sekam = 0; migrasiProduksi++; }
        if(r.hppBahanBaku === undefined) r.hppBahanBaku = 0;
        if(!r.sumberGabah) r.sumberGabah = [];
        if(!r.tipeBahan) r.tipeBahan = 'Gabah';
      });
      if(migrasiProduksi > 0){
        console.warn(`[loadDB] Migrasi: ${migrasiProduksi} field produksi (pk/sekam) diinisialisasi.`);
      }

      const sampingItems = ['Bekatul','Menir','Sekam'];
      sampingItems.forEach(s=>{
        if(DB.jenisBeras && DB.jenisBeras.includes(s)){
          DB.jenisBeras = DB.jenisBeras.filter(j=>j!==s);
          if(!DB.jenisSamping.includes(s)) DB.jenisSamping.push(s);
        }
      });

      // SINKRONISASI OTOMATIS: jika ada transaksi (pembelian/penjualan/produksi)
      // tapi jurnal double-entry masih kosong (data lama dari sebelum Sprint 5,
      // atau jurnal belum pernah di-generate), rebuild otomatis agar laporan
      // legacy (Laba Rugi, Neraca lama) dan laporan jurnal (Sprint 5) selalu
      // menampilkan angka yang konsisten satu sama lain.
      const adaTransaksi = (DB.pembelian||[]).length>0 || (DB.penjualan||[]).length>0 || (DB.produksi||[]).length>0;
      const jurnalKosong = !DB.jurnal || DB.jurnal.length===0;
      if(adaTransaksi && jurnalKosong && typeof rebuildSemuaJurnal === 'function'){
        try{
          rebuildSemuaJurnal();
          console.info(`[loadDB] Auto-sync: jurnal double-entry di-generate otomatis dari ${DB.pembelian.length+DB.penjualan.length+DB.produksi.length} transaksi yang ada.`);
        }catch(e){ console.warn('[loadDB] Auto-sync jurnal gagal (tidak fatal, halaman Jurnal Umum tetap bisa di-rebuild manual)', e); }
      }

      return;
    }catch(e){ console.warn('Gagal memuat data, menggunakan default', e); }
  }
  DB = defaultData();
  saveDB();
}
function saveDB(){
  localStorage.setItem(STORAGE_KEY, JSON.stringify(DB));
}

// ---------- UTIL ----------
function fmtRp(n){
  n = Number(n)||0;
  const neg = n < 0;
  n = Math.abs(Math.round(n));
  const s = 'Rp ' + n.toLocaleString('id-ID');
  return neg ? '(' + s + ')' : s;
}
function fmtNum(n){
  return Number(n||0).toLocaleString('id-ID');
}

// Formatted money input: displays with thousand-separator dots, parses on read
function fmtInputRp(id, val){
  // Set a text input to display formatted Rp value
  const el = document.getElementById(id);
  if(!el) return;
  el.value = Number(val||0).toLocaleString('id-ID');
}
function readInputRp(id){
  // Read a formatted text input, strip dots/spaces, return number
  const el = document.getElementById(id);
  if(!el) return 0;
  return Number(String(el.value).replace(/\./g,'').replace(/,/g,'.').replace(/[^\d.]/g,''))||0;
}
function onInputRpFormat(el){
  // Called oninput on formatted fields — keeps cursor stable
  const raw = String(el.value).replace(/\./g,'').replace(/[^\d]/g,'');
  const num = Number(raw)||0;
  el.value = num===0 ? '' : num.toLocaleString('id-ID');
}
function fmtDate(d){
  if(!d) return '-';
  const dt = new Date(d);
  if(isNaN(dt)) return d;
  return dt.toLocaleDateString('id-ID', {day:'2-digit', month:'short', year:'numeric'});
}
function todayStr(){
  return new Date().toISOString().slice(0,10);
}
function uid(){
  return 'id'+Date.now().toString(36)+Math.random().toString(36).slice(2,7);
}
function nextCode(seqKey, prefix, pad=4){
  const n = DB.seq[seqKey] || 1;
  DB.seq[seqKey] = n+1;
  return prefix + '-' + String(n).padStart(pad,'0');
}
function showToast(msg){
  const t = document.getElementById('toast');
  t.textContent = msg;
  t.classList.add('show');
  clearTimeout(window._toastTimer);
  window._toastTimer = setTimeout(()=>t.classList.remove('show'), 2400);
}

/* ============================================================
   ACTION SHEET — popup aksi saat klik baris tabel
   Memanggil: showActionSheet(event, title, items)
   items: [{label, icon, action, danger}]
   ============================================================ */
function showActionSheet(e, title, items){
  e.stopPropagation();
  const sheet = document.getElementById('actionSheet');
  const overlay = document.getElementById('asOverlay');

  // Build content
  const btns = items.map(item=>`
    <button class="${item.danger?'danger':''}" onclick="closeActionSheet();(${item.action})()">
      ${item.icon||''} ${esc(item.label)}
    </button>
  `).join('');
  sheet.innerHTML = `<div class="action-sheet-title">${esc(title)}</div>${btns}`;

  // Position near click, keep within viewport
  overlay.style.display = 'block';
  sheet.style.display = 'block';
  const rect = sheet.getBoundingClientRect();
  let x = e.clientX, y = e.clientY + 8;
  const W = window.innerWidth, H = window.innerHeight;
  if(x + 200 > W) x = W - 210;
  if(y + rect.height + 20 > H) y = e.clientY - rect.height - 8;
  sheet.style.left = Math.max(8, x) + 'px';
  sheet.style.top  = Math.max(8, y) + 'px';
}
function closeActionSheet(){
  document.getElementById('actionSheet').style.display = 'none';
  document.getElementById('asOverlay').style.display = 'none';
}
function esc(s){
  return String(s==null?'':s).replace(/[&<>"']/g, c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
}

