// Injects a mirror scroll bar ABOVE each .table-wrap so user can scroll
// horizontally without having to reach the bottom of a long table.
// Registry listener resize aktif, agar bisa dibersihkan saat halaman berganti
// (mencegah penumpukan listener window setiap kali pindah halaman/tabel baru muncul)
let _dualScrollResizeListeners = [];

function initDualScroll(){
  // Bersihkan listener resize dari render halaman sebelumnya
  _dualScrollResizeListeners.forEach(fn => window.removeEventListener('resize', fn));
  _dualScrollResizeListeners = [];

  document.querySelectorAll('.table-wrap').forEach(wrap=>{
    // Skip if already has dual scroll, or table isn't actually wider than container
    if(wrap.dataset.dualScrollDone) return;
    wrap.dataset.dualScrollDone = '1';

    const top = document.createElement('div');
    top.className = 'table-scroll-top';
    top.style.cssText = 'overflow-x:auto; overflow-y:hidden; height:12px; margin-bottom:2px;';

    const inner = document.createElement('div');
    inner.style.height = '1px';
    top.appendChild(inner);
    wrap.parentNode.insertBefore(top, wrap);

    // Set inner width to match the actual table scroll width
    function syncWidth(){
      inner.style.width = wrap.scrollWidth + 'px';
      // Hide top bar if no horizontal scroll needed
      top.style.display = wrap.scrollWidth > wrap.clientWidth ? 'block' : 'none';
    }
    syncWidth();

    // Sync scroll positions bidirectionally
    let syncing = false;
    top.addEventListener('scroll', ()=>{
      if(syncing) return;
      syncing = true;
      wrap.scrollLeft = top.scrollLeft;
      syncing = false;
    });
    wrap.addEventListener('scroll', ()=>{
      if(syncing) return;
      syncing = true;
      top.scrollLeft = wrap.scrollLeft;
      syncing = false;
    });

    // Re-sync width on window resize — listener didaftarkan ke registry agar
    // bisa dibersihkan saat render halaman berikutnya (cegah memory leak).
    window.addEventListener('resize', syncWidth, {passive:true});
    _dualScrollResizeListeners.push(syncWidth);
  });
}

