// ---------- PWA: SERVICE WORKER & INSTALL PROMPT ----------
let deferredInstallPrompt = null;

function registerServiceWorker(){
  if('serviceWorker' in navigator){
    // Service workers require https or localhost; silently no-op on file:// or unsupported contexts
    if(location.protocol === 'file:'){
      console.info('Service worker dilewati: buka aplikasi via http/https (atau "Install" dari browser) untuk dukungan offline penuh.');
      return;
    }
    navigator.serviceWorker.register('./sw.js').catch((err)=>{
      console.warn('Gagal mendaftarkan service worker:', err);
    });
  }
}

/* ============================================================
   SPRINT 12 — DARK MODE
   CSS variabel override [data-theme="dark"] sudah tersedia di
   index.html sejak awal; bagian yang hilang HANYA logika toggle
   ini. Preferensi disimpan di localStorage agar persisten lintas
   sesi, dengan fallback otomatis ke prefers-color-scheme sistem
   operasi pada kunjungan pertama (sebelum user pernah memilih).
   ============================================================ */
const DARK_MODE_KEY = 'erp_padi_dark_mode';

function _applyDarkModePreference(isDark){
  document.documentElement.setAttribute('data-theme', isDark ? 'dark' : 'light');
  const btn = document.getElementById('darkModeToggle');
  if(btn) btn.textContent = isDark ? '☀️ Mode Terang' : '🌙 Mode Gelap';
  const meta = document.querySelector('meta[name="theme-color"]');
  if(meta) meta.setAttribute('content', isDark ? '#15181F' : '#16A34A');
}

function initDarkMode(){
  let saved = null;
  try{ saved = localStorage.getItem(DARK_MODE_KEY); }catch(e){}
  let isDark;
  if(saved === 'dark' || saved === 'light'){
    isDark = saved === 'dark';
  } else {
    // Belum pernah dipilih user: ikuti preferensi sistem operasi
    isDark = window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches;
  }
  _applyDarkModePreference(isDark);
}

function toggleDarkMode(){
  const isDarkNow = document.documentElement.getAttribute('data-theme') === 'dark';
  const next = !isDarkNow;
  _applyDarkModePreference(next);
  try{ localStorage.setItem(DARK_MODE_KEY, next ? 'dark' : 'light'); }catch(e){}
  showToast(next ? 'Mode Gelap diaktifkan.' : 'Mode Terang diaktifkan.');
}

/** Sinkronkan label tombol toggle dengan tema yang sedang aktif (dipanggil ulang
 *  setelah sidebar/topbar baru selesai dirender, mis. setelah login). */
function updateDarkModeButtonLabel(){
  const isDark = document.documentElement.getAttribute('data-theme') === 'dark';
  const btn = document.getElementById('darkModeToggle');
  if(btn) btn.textContent = isDark ? '☀️ Mode Terang' : '🌙 Mode Gelap';
}

window.addEventListener('beforeinstallprompt', (e)=>{
  e.preventDefault();
  deferredInstallPrompt = e;
  const btn = document.getElementById('installAppBtn');
  const btnLogin = document.getElementById('installAppBtnLogin');
  if(btn) btn.style.display = 'block';
  if(btnLogin) btnLogin.style.display = 'block';
});

function installApp(){
  if(!deferredInstallPrompt){
    showToast('Aplikasi sudah terpasang, atau gunakan menu "Install App" pada browser.');
    return;
  }
  deferredInstallPrompt.prompt();
  deferredInstallPrompt.userChoice.then((choice)=>{
    if(choice.outcome === 'accepted'){
      showToast('Aplikasi sedang dipasang...');
    }
    deferredInstallPrompt = null;
    const btn = document.getElementById('installAppBtn');
    const btnLogin = document.getElementById('installAppBtnLogin');
    if(btn) btn.style.display = 'none';
    if(btnLogin) btnLogin.style.display = 'none';
  });
}

window.addEventListener('appinstalled', ()=>{
  showToast('Aplikasi berhasil dipasang.');
  const btn = document.getElementById('installAppBtn');
  const btnLogin = document.getElementById('installAppBtnLogin');
  if(btn) btn.style.display = 'none';
  if(btnLogin) btnLogin.style.display = 'none';
});

// ---------- EXPORT / IMPORT ----------
function exportData(){
  const blob = new Blob([JSON.stringify(DB,null,2)], {type:'application/json'});
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = 'erp_padi_data_'+todayStr()+'.json';
  a.click();
  URL.revokeObjectURL(url);
  showToast('Data berhasil diekspor.');
}
function importData(ev){
  const file = ev.target.files[0];
  if(!file) return;
  const reader = new FileReader();
  reader.onload = (e)=>{
    try{
      const data = JSON.parse(e.target.result);
      if(!data.users || !data.pembelian){ throw new Error('Format tidak valid'); }
      DB = data;
      saveDB();
      showToast('Data berhasil diimpor.');
      navigateTo(currentPage);
    }catch(err){
      alert('Gagal mengimpor data: file tidak valid.');
    }
  };
  reader.readAsText(file);
  ev.target.value = '';
}

