function renderSimpleList(kind, target){
  target = target || document.getElementById('pageInner');
  const cfg = SIMPLE_LIST_CONFIG[kind];
  const list = DB[cfg.listKey];
  const canEdit = SESSION.role !== 'KASIR';

  const rowsHtml = list.length===0
    ? `<tr><td colspan="2"><div class="empty-state"><div class="stamp">∅</div><div>Belum ada data.</div></div></td></tr>`
    : list.map((j,i)=>`
      <tr>
        <td>${esc(j)}</td>
        <td>
          ${canEdit ? `
            <button class="btn btn-sm btn-secondary" onclick="editSimpleList('${kind}',${i})">Ubah</button>
            <button class="btn btn-sm btn-danger" onclick="deleteSimpleList('${kind}',${i})">Hapus</button>
          ` : '<span style="color:var(--ink-soft); font-size:0.78rem;">Lihat saja</span>'}
        </td>
      </tr>
    `).join('');

  target.innerHTML = `
    <div class="card">
      <h3>${cfg.title} <span class="tag">${list.length} ${cfg.unitLabel}</span></h3>
      <p class="help-text" style="margin-top:-4px;">${cfg.desc}</p>
      ${canEdit ? `<button class="btn btn-primary" style="width:auto;" onclick="editSimpleList('${kind}',-1)">+ Tambah</button>` : ''}
      <div class="table-wrap" style="margin-top:14px; max-width:420px;">
        <table>
          <thead><tr><th>${cfg.colLabel}</th><th>Aksi</th></tr></thead>
          <tbody>${rowsHtml}</tbody>
        </table>
      </div>
    </div>
  `;
}
function editSimpleList(kind, idx){
  const cfg = SIMPLE_LIST_CONFIG[kind];
  const isNew = idx===-1;
  const val = isNew ? '' : DB[cfg.listKey][idx];
  openModal(`
    <h2>${isNew?'Tambah':'Ubah'} ${cfg.colLabel}</h2>
    <div class="field">
      <label>${cfg.colLabel}</label>
      <input type="text" id="sl_name" value="${esc(val)}">
    </div>
    <div class="form-actions">
      <button class="btn btn-primary" style="width:auto;" onclick="saveSimpleList('${kind}', ${idx})">Simpan</button>
      <button class="btn btn-secondary" onclick="closeModal()">Batal</button>
    </div>
  `);
}
function saveSimpleList(kind, idx){
  const cfg = SIMPLE_LIST_CONFIG[kind];
  const val = document.getElementById('sl_name').value.trim();
  if(!val){ alert('Nama wajib diisi.'); return; }
  if(idx===-1) DB[cfg.listKey].push(val);
  else DB[cfg.listKey][idx] = val;
  saveDB();
  closeModal();
  renderSimpleList(kind);
  showToast('Tersimpan.');
}
function deleteSimpleList(kind, idx){
  const cfg = SIMPLE_LIST_CONFIG[kind];
  if(!confirm('Hapus data ini?')) return;
  DB[cfg.listKey].splice(idx,1);
  saveDB();
  renderSimpleList(kind);
  showToast('Dihapus.');
}

