function renderKendaraan(target){
  target = target || document.getElementById('pageInner');
  const rows = DB.kendaraan;
  const canEdit = SESSION.role !== 'KASIR';

  const rowsHtml = rows.length===0
    ? `<tr><td colspan="6"><div class="empty-state"><div class="stamp">🚚</div><div>Belum ada data kendaraan.</div></div></td></tr>`
    : rows.map((k,i)=>`
      <tr>
        <td class="mono">${esc(k.kode)}</td>
        <td>${esc(k.nopol)}</td>
        <td>${esc(k.jenis)}</td>
        <td>${esc(k.sopir||'-')}</td>
        <td><span class="badge ${k.status==='Aktif'?'lunas':'belum'}">${esc(k.status)}</span></td>
        <td>
          ${canEdit ? `
            <button class="btn btn-sm btn-secondary" onclick="editKendaraan(${i})">Ubah</button>
            <button class="btn btn-sm btn-danger" onclick="deleteKendaraan(${i})">Hapus</button>
          ` : '<span style="color:var(--ink-soft); font-size:0.78rem;">Lihat saja</span>'}
        </td>
      </tr>
    `).join('');

  target.innerHTML = `
    <div class="card">
      <h3>Master Kendaraan Angkut <span class="tag">${rows.length} unit</span></h3>
      <p class="help-text" style="margin-top:-4px;">Daftar ini menjadi pilihan dropdown Kendaraan pada Form Pengiriman/Distribusi.</p>
      ${canEdit ? `<button class="btn btn-primary" style="width:auto;" onclick="editKendaraan(-1)">+ Tambah Kendaraan</button>` : ''}
      <div class="table-wrap" style="margin-top:14px;">
        <table>
          <thead><tr><th>Kode</th><th>No. Polisi</th><th>Jenis Kendaraan</th><th>Sopir</th><th>Status</th><th>Aksi</th></tr></thead>
          <tbody>${rowsHtml}</tbody>
        </table>
      </div>
    </div>
  `;
}
function editKendaraan(idx){
  const isNew = idx===-1;
  const k = isNew ? {kode:'', nopol:'', jenis:'Truk Engkel', sopir:'', status:'Aktif'} : DB.kendaraan[idx];
  openModal(`
    <h2>${isNew?'Tambah':'Ubah'} Kendaraan</h2>
    <div class="modal-sub">${isNew?'Kode akan dibuat otomatis.':'Kode: '+esc(k.kode)}</div>
    <div class="form-row">
      <div class="field">
        <label>No. Polisi</label>
        <input type="text" id="kd_nopol" value="${esc(k.nopol)}" placeholder="contoh: B 1234 ABC">
      </div>
      <div class="field">
        <label>Jenis Kendaraan</label>
        <select id="kd_jenis">
          <option value="Truk Engkel" ${k.jenis==='Truk Engkel'?'selected':''}>Truk Engkel</option>
          <option value="Truk Fuso" ${k.jenis==='Truk Fuso'?'selected':''}>Truk Fuso</option>
          <option value="Pickup" ${k.jenis==='Pickup'?'selected':''}>Pickup</option>
          <option value="Mobil Box" ${k.jenis==='Mobil Box'?'selected':''}>Mobil Box</option>
          <option value="Lainnya" ${k.jenis==='Lainnya'?'selected':''}>Lainnya</option>
        </select>
      </div>
    </div>
    <div class="form-row">
      <div class="field">
        <label>Nama Sopir</label>
        <input type="text" id="kd_sopir" value="${esc(k.sopir)}">
      </div>
      <div class="field">
        <label>Status</label>
        <select id="kd_status">
          <option value="Aktif" ${k.status==='Aktif'?'selected':''}>Aktif</option>
          <option value="Nonaktif" ${k.status==='Nonaktif'?'selected':''}>Nonaktif (Perbaikan/Tidak Dipakai)</option>
        </select>
      </div>
    </div>
    <div class="form-actions">
      <button class="btn btn-primary" style="width:auto;" onclick="saveKendaraan(${idx})">Simpan</button>
      <button class="btn btn-secondary" onclick="closeModal()">Batal</button>
    </div>
  `);
}
function saveKendaraan(idx){
  const nopol = document.getElementById('kd_nopol').value.trim();
  const jenis = document.getElementById('kd_jenis').value;
  const sopir = document.getElementById('kd_sopir').value.trim();
  const status = document.getElementById('kd_status').value;
  if(!nopol){ alert('No. Polisi wajib diisi.'); return; }
  if(idx===-1){
    const kode = 'KND-' + String(DB.kendaraan.length+1).padStart(3,'0');
    DB.kendaraan.push({kode, nopol, jenis, sopir, status});
  } else {
    Object.assign(DB.kendaraan[idx], {nopol, jenis, sopir, status});
  }
  saveDB();
  closeModal();
  renderKendaraan();
  showToast('Tersimpan.');
}
function deleteKendaraan(idx){
  if(!confirm('Hapus data kendaraan ini?')) return;
  DB.kendaraan.splice(idx,1);
  saveDB();
  renderKendaraan();
  showToast('Dihapus.');
}


