function editPembelian(id){
  const isNew = id===null;
  const row = isNew ? {
    id: uid(), tanggal: todayStr(), noFaktur: nextCode('faktur','PB',4),
    supplier:'', kategori:'Gabah', jenisGabah:'', qty:0, harga:0, angkut:0, dp:0, status:'Lunas'
  } : DB.pembelian.find(r=>r.id===id);
  if(!isNew) DB.seq.faktur = DB.seq.faktur; // no-op, keep seq monotonic
  if(!row.kategori) row.kategori = 'Gabah'; // backward-compat for old records

  const supplierOpts = DB.suppliers.map(s=>`<option value="${esc(s.nama)}" ${row.supplier===s.nama?'selected':''}>${esc(s.nama)}</option>`).join('');

  openModal(`
    <h2>${isNew?'Transaksi Pembelian Baru':'Ubah Transaksi Pembelian'}</h2>
    <div class="modal-sub">No. Faktur: <span class="mono">${esc(row.noFaktur)}</span> ${isNew?'(otomatis)':''}</div>
    <div class="form-row">
      <div class="field">
        <label>Tanggal</label>
        <input type="date" id="pb_tanggal" value="${esc(row.tanggal)}">
      </div>
      <div class="field">
        <label>Supplier</label>
        <select id="pb_supplier" onchange="autoFillHargaPembelian()">
          <option value="">-- Pilih Supplier --</option>
          ${supplierOpts}
        </select>
      </div>
      <div class="field">
        <label>Kategori Barang</label>
        <select id="pb_kategori" onchange="updatePembelianJenisOptions()">
          <option value="Gabah" ${row.kategori==='Gabah'?'selected':''}>Gabah (bahan baku, untuk digiling)</option>
          <option value="Beras" ${row.kategori==='Beras'?'selected':''}>Beras Utama (beli langsung)</option>
          <option value="Produk Samping" ${row.kategori==='Produk Samping'?'selected':''}>Produk Samping (Bekatul, Menir, Sekam, dll)</option>
          <option value="Bahan Baku" ${row.kategori==='Bahan Baku'?'selected':''}>Bahan Baku (Beras Pecah Kulit, dll)</option>
        </select>
      </div>
    </div>
    <div class="form-row">
      <div class="field">
        <label id="pb_jenis_label">Jenis Gabah</label>
        <select id="pb_jenis" onchange="autoFillHargaPembelian()">${getPembelianJenisOptions(row.kategori, row.jenisGabah)}</select>
      </div>
      <div class="field">
        <label id="pb_qty_label">Qty Gabah (Kg)</label>
        <input type="text" id="pb_qty" value="${fmtNum(row.qty)}" placeholder="0" oninput="onInputRpFormat(this);calcPembelianTotal()" inputmode="numeric">
      </div>
      <div class="field">
        <label>Harga / Kg (Rp)</label>
        <input type="text" id="pb_harga" value="${fmtNum(row.harga)}" placeholder="0" oninput="onInputRpFormat(this);calcPembelianTotal()" inputmode="numeric">
        <p class="help-text" id="pb_harga_hint" style="margin-top:5px; margin-bottom:0;"></p>
      </div>
    </div>
    <div class="form-row">
      <div class="field">
        <label>Biaya Angkut (Rp)</label>
        <input type="text" id="pb_angkut" value="${fmtNum(row.angkut)}" placeholder="0" oninput="onInputRpFormat(this);calcPembelianTotal()" inputmode="numeric">
      </div>
      <div class="field">
        <label>DP / Pembayaran Awal (Rp)</label>
        <input type="text" id="pb_dp" value="${fmtNum(row.dp)}" placeholder="0" oninput="onInputRpFormat(this)" inputmode="numeric" oninput="calcPembelianTotal()">
        <p id="pb_uangmuka_hint" class="help-text" style="margin-top:5px;margin-bottom:0;background:var(--gold-soft);padding:6px 10px;border-radius:6px;display:none;"></p>
      </div>
      <div class="field">
        <label>Status Pembayaran</label>
        <select id="pb_status" onchange="syncDpDenganStatus()">
          <option value="Lunas" ${row.status==='Lunas'?'selected':''}>Lunas</option>
          <option value="Belum Lunas" ${row.status==='Belum Lunas'?'selected':''}>Belum Lunas</option>
        </select>
      </div>
    </div>
    <div class="field">
      <label>Total (Qty x Harga + Angkut)</label>
      <input type="text" id="pb_total_display" value="${fmtRp((row.qty*row.harga)+row.angkut)}" readonly style="font-weight:700; font-family:'JetBrains Mono',monospace;">
    </div>
    <p class="help-text" id="pb_kategori_note" style="margin-top:8px;"></p>
    <div class="form-actions">
      <button class="btn btn-primary" style="width:auto;" onclick="savePembelian('${row.id}', ${isNew})">Simpan</button>
      <button class="btn btn-secondary" onclick="closeModal()">Batal</button>
    </div>
  `);
  updatePembelianKategoriNote();
  if(isNew) autoFillHargaPembelian(); // pre-fill if jenis is already set somehow
  // Sinkronkan DP dengan status saat form dibuka
  setTimeout(syncDpDenganStatus, 50);
}
function getPembelianJenisOptions(kategori, selected){
  let list, placeholder;
  if(kategori==='Beras'){
    list = DB.jenisBeras||[]; placeholder='-- Pilih Jenis Beras --';
  } else if(kategori==='Produk Samping'){
    list = DB.jenisSamping||[]; placeholder='-- Pilih Produk Samping --';
  } else if(kategori==='Bahan Baku'){
    list = DB.jenisBahanBaku||[]; placeholder='-- Pilih Bahan Baku --';
  } else {
    list = DB.jenisGabah||[]; placeholder='-- Pilih Jenis Gabah --';
  }
  return `<option value="">${placeholder}</option>` + list.map(j=>{
    const label = kategori==='Beras' ? (j==='Premium'?'Beras Premium':j==='Medium'?'Beras Medium':j) : j;
    return `<option value="${esc(j)}" ${j===selected?'selected':''}>${esc(label)}</option>`;
  }).join('');
}
function updatePembelianJenisOptions(){
  const kategori = document.getElementById('pb_kategori').value;
  document.getElementById('pb_jenis').innerHTML = getPembelianJenisOptions(kategori, null);
  document.getElementById('pb_jenis_label').textContent =
    kategori==='Beras' ? 'Jenis Beras' :
    kategori==='Produk Samping' ? 'Produk Samping' :
    kategori==='Bahan Baku' ? 'Jenis Bahan Baku' : 'Jenis Gabah';
  document.getElementById('pb_qty_label').textContent =
    kategori==='Beras' ? 'Qty Beras (Kg)' :
    kategori==='Produk Samping' ? 'Qty (Kg)' :
    kategori==='Bahan Baku' ? 'Qty Bahan Baku (Kg)' : 'Qty Gabah (Kg)';
  autoFillHargaPembelian();
  updatePembelianKategoriNote();
}
// Cari harga pembelian terakhir berdasarkan kategori + jenis, dengan dua level:
//   1. Prioritas: harga terakhir dari supplier yang sama
//   2. Fallback: harga terakhir dari supplier manapun
function getHargaBeliBelakang(kategori, jenis, supplier){
  const matching = DB.pembelian.filter(r=>{
    const kat = r.kategori || 'Gabah';
    return kat === kategori && r.jenisGabah === jenis;
  }).sort((a,b)=>b.tanggal.localeCompare(a.tanggal));
  if(matching.length === 0) return null;
  // try same supplier first
  const sameSupplier = matching.find(r=>r.supplier===supplier);
  return sameSupplier || matching[0];
}
function autoFillHargaPembelian(){
  const kategori = document.getElementById('pb_kategori').value;
  const jenis    = document.getElementById('pb_jenis').value;
  const supplier = document.getElementById('pb_supplier').value;
  const hintEl   = document.getElementById('pb_harga_hint');
  if(!jenis){ if(hintEl) hintEl.textContent=''; return; }

  // Tampilkan hint uang muka jika tersedia untuk supplier ini
  const umHintEl = document.getElementById('pb_uangmuka_hint');
  if(umHintEl && supplier){
    const sisaUM = (getUangMukaPerSupplier())[supplier] || 0;
    if(sisaUM > 0){
      umHintEl.innerHTML = `💰 <b>Uang muka tersedia: ${fmtRp(sisaUM)}</b> dari kelebihan bayar sebelumnya. Masukkan di kolom DP — otomatis berkurang saat disimpan.`;
      umHintEl.style.display = 'block';
    } else {
      umHintEl.style.display = 'none';
    }
  }

  const ref = getHargaBeliBelakang(kategori, jenis, supplier);
  if(!ref){
    if(hintEl) hintEl.textContent = 'Belum ada riwayat pembelian untuk jenis ini.';
    return;
  }
  document.getElementById('pb_harga').value = Number(ref.harga||0).toLocaleString('id-ID');
  calcPembelianTotal();
  if(hintEl){
    const sameSupplierText = (supplier && ref.supplier===supplier) ? 'supplier ini' : `supplier lain (${esc(ref.supplier)})`;
    hintEl.innerHTML = `Rekomendasi dari pembelian terakhir — <b>${fmtRp(ref.harga)}/kg</b> dari ${sameSupplierText} pada ${fmtDate(ref.tanggal)} (${esc(ref.noFaktur)}). Angkut terakhir: <b>${fmtRp(ref.angkut)}</b>. Bisa diubah manual.`;
  }
}
function updatePembelianKategoriNote(){
  const kategori = document.getElementById('pb_kategori').value;
  const note = document.getElementById('pb_kategori_note');
  note.textContent =
    kategori==='Beras' ? 'Pembelian beras utama langsung (tanpa giling). Menambah stok Beras Utama.' :
    kategori==='Produk Samping' ? 'Pembelian produk samping (bekatul, menir, sekam, dll). Menambah stok Produk Samping.' :
    kategori==='Bahan Baku' ? 'Pembelian bahan baku giling (beras pecah kulit, dll). Menambah stok Bahan Baku yang bisa dipakai di Form Produksi.' :
    'Pembelian gabah (bahan baku) untuk digiling. Stok gabah bertambah dan bisa dipilih sebagai sumber di Form Produksi.';
}
function calcPembelianTotal(){
  const qty = readInputRp('pb_qty');
  const harga = readInputRp('pb_harga');
  const angkut = readInputRp('pb_angkut');
  const total = (qty*harga)+angkut;
  document.getElementById('pb_total_display').value = fmtRp(total);
  // Jika status Lunas, pastikan DP ikut menyesuaikan
  syncDpDenganStatus();
}

// Jika status Lunas → DP otomatis terisi = Total (bayar penuh)
// Jika kembali ke Belum Lunas → DP dikosongkan agar user isi manual
function syncDpDenganStatus(){
  const status = document.getElementById('pb_status')?.value;
  const dpEl = document.getElementById('pb_dp');
  if(!status || !dpEl) return;
  if(status === 'Lunas'){
    const qty = readInputRp('pb_qty');
    const harga = readInputRp('pb_harga');
    const angkut = readInputRp('pb_angkut');
    const total = (qty*harga)+angkut;
    dpEl.value = Number(total).toLocaleString('id-ID');
    dpEl.setAttribute('readonly', 'true');
    dpEl.style.background = 'var(--gold-soft)';
  } else {
    dpEl.removeAttribute('readonly');
    dpEl.style.background = '';
    // Hanya kosongkan jika isinya sama dengan total (artinya di-auto-fill)
    const qty = readInputRp('pb_qty');
    const harga = readInputRp('pb_harga');
    const angkut = readInputRp('pb_angkut');
    const total = (qty*harga)+angkut;
    if(readInputRp('pb_dp') === total) dpEl.value = '';
  }
}

function savePembelian(id, isNew){
  const tanggal = document.getElementById('pb_tanggal').value;
  const supplier = document.getElementById('pb_supplier').value;
  const kategori = document.getElementById('pb_kategori').value;
  const jenisGabah = document.getElementById('pb_jenis').value;
  const qty = readInputRp('pb_qty');
  const harga = readInputRp('pb_harga');
  const angkut = readInputRp('pb_angkut');
  const dp = readInputRp('pb_dp');
  const status = document.getElementById('pb_status').value;

  if(!tanggal || !supplier || !jenisGabah || qty<=0){
    alert(`Tanggal, Supplier, Jenis ${kategori==='Beras'?'Beras':kategori==='Produk Samping'?'Produk Samping':'Gabah'}, dan Qty wajib diisi dengan benar.`);
    return;
  }
  const total = (qty*harga)+angkut;

  let row;
  if(isNew){
    row = {id, tanggal, noFaktur: nextCode('faktur','PB',4), supplier, kategori, jenisGabah, qty, harga, angkut, dp, total, status};
    DB.pembelian.push(row);
  } else {
    row = DB.pembelian.find(r=>r.id===id);
    Object.assign(row, {tanggal, supplier, kategori, jenisGabah, qty, harga, angkut, dp, total, status});
  }

  // Sync ke Kas & Bank:
  // Entry UTAMA (sourceId) hanya sebagai referensi/header transaksi — keluar=0
  // DP dan pelunasan dicatat TERPISAH via refId entries
  const labelBarang = kategori==='Beras' ? (jenisGabah==='Premium'?'Beras Premium':jenisGabah==='Medium'?'Beras Medium':jenisGabah) : kategori==='Produk Samping' ? jenisGabah : `gabah ${esc(jenisGabah)}`;
  const kasKategoriPembelian = kategori==='Beras' ? 'Pembelian Beras/Barang Jadi' : kategori==='Produk Samping' ? 'Pembelian Beras/Barang Jadi' : 'Pembelian Gabah';

  // Entry utama: selalu keluar=0 (hanya penanda; pembayaran dicatat via DP/Pelunasan)
  syncKasBankEntry('pembelian', row.id, {
    tanggal, keterangan:`Pembelian ${labelBarang} dari ${esc(supplier)} (${row.noFaktur})`,
    masuk:0, keluar:0, kategori: kasKategoriPembelian
  });

  // Bersihkan DP Pembelian lama untuk faktur ini (hindari duplikat saat edit)
  DB.kasbank = DB.kasbank.filter(k=>!(k.kategori==='DP Pembelian' && k.refId===row.id));
  DB.kasbank = DB.kasbank.filter(k=>!(k.kategori==='Uang Muka Dipakai' && k.refId===row.id));

  if(status === 'Lunas'){
    // BUG FIX (Sinkronisasi Hutang Supplier): SEBELUMNYA, setiap kali status
    // 'Lunas' dipilih (apa pun nilai dp), sistem mencatat 'DP Pembelian' = total
    // PENUH (lunas tunai) — LALU, secara terpisah dan TANPA SYARAT, juga mencoba
    // memakai uang muka yang tersedia dan mencatatnya SEBAGAI TAMBAHAN
    // 'Uang Muka Dipakai'. Untuk faktur yang sudah dicatat lunas tunai 100%
    // (dp===0, keluar:total), uang muka yang "dipakai" ini TIDAK PERNAH
    // benar-benar dibutuhkan — total yang tercatat "dibayar" untuk faktur itu
    // jadi (total + dipakaiDariUM), LEBIH BESAR dari nilai faktur sesungguhnya.
    // Akibatnya uang muka yang seharusnya tetap tersedia untuk mengurangi
    // hutang faktur LAIN yang benar-benar belum lunas malah "menguap" — dipakai
    // keliru untuk faktur yang sebenarnya tidak membutuhkannya sama sekali.
    // Uang muka sekarang HANYA dipakai jika faktur DIBAYAR SEBAGIAN via dp
    // (dp>0 tapi dp<total) — sisanya (total-dp) yang ditutup dari uang muka,
    // BUKAN ditambahkan di atas pembayaran tunai penuh yang sudah tercatat.
    if(dp <= 0 || dp >= total){
      // Lunas tunai murni: catat pembayaran penuh, TIDAK perlu uang muka sama sekali.
      DB.kasbank.push({
        id: uid(), sumber:'pembelian', tanggal,
        keterangan:`Pembayaran lunas ${labelBarang} dari ${esc(supplier)} (${row.noFaktur})`,
        masuk:0, keluar:total, kategori:'DP Pembelian', refId:row.id
      });
    } else {
      // Lunas SEBAGIAN via dp, sisanya (total-dp) ditutup dari uang muka jika tersedia.
      DB.kasbank.push({
        id: uid(), sumber:'pembelian', tanggal,
        keterangan:`Pembayaran tunai ${labelBarang} dari ${esc(supplier)} (${row.noFaktur})`,
        masuk:0, keluar:dp, kategori:'DP Pembelian', refId:row.id
      });
      const sisaSetelahDp = total - dp;
      const sisaUangMuka = (getUangMukaPerSupplier())[supplier] || 0;
      if(sisaUangMuka > 0 && sisaSetelahDp > 0){
        const dipakaiDariUM = Math.min(sisaSetelahDp, sisaUangMuka);
        DB.kasbank.push({
          id: uid(), sumber:'pembelian', tanggal,
          keterangan:`Uang muka ${esc(supplier)} dipakai untuk pelunasan sisa (${row.noFaktur})`,
          masuk:dipakaiDariUM, keluar:0,
          kategori:'Uang Muka Dipakai', refSupplier:supplier, refId:row.id
        });
      }
    }
  } else if(dp > 0){
    // Belum Lunas dengan DP
    DB.kasbank.push({
      id: uid(), sumber:'pembelian', tanggal,
      keterangan:`DP pembelian ${labelBarang} dari ${esc(supplier)} (${row.noFaktur})`,
      masuk:0, keluar:dp, kategori:'DP Pembelian', refId:row.id
    });
    // Cek uang muka
    const sisaUangMuka = (getUangMukaPerSupplier())[supplier] || 0;
    if(sisaUangMuka > 0){
      const dipakaiDariUM = Math.min(dp, sisaUangMuka);
      DB.kasbank.push({
        id: uid(), sumber:'pembelian', tanggal,
        keterangan:`Uang muka ${esc(supplier)} dipakai sebagai DP (${row.noFaktur})`,
        masuk:dipakaiDariUM, keluar:0,
        kategori:'Uang Muka Dipakai', refSupplier:supplier, refId:row.id
      });
    }
  }

  // ── POST JURNAL OTOMATIS ─────────────────────────────────
  if(row.status === 'Lunas' && !(row.dp>0)){
    postPembelianTunai(row);
  } else if(Number(row.dp||0)>0){
    postPembelianDP(row);
  } else {
    postPembelianKredit(row);
  }
  saveDB();
  closeModal();
  showToast('Transaksi pembelian tersimpan.');
  renderPembelian();
}

function deletePembelian(id){
  if(!confirm('Hapus transaksi pembelian ini? Semua catatan kas terkait (DP, pelunasan) juga akan dihapus.')) return;
  DB.pembelian = DB.pembelian.filter(r=>r.id!==id);
  // Hapus: (1) entry utama pembelian (sumber='pembelian', sourceId=id)
  DB.kasbank = DB.kasbank.filter(k=>!(k.sumber==='pembelian' && k.sourceId===id));
  // Hapus: (2) entry DP Pembelian yang terhubung via refId
  DB.kasbank = DB.kasbank.filter(k=>!(k.kategori==='DP Pembelian' && k.refId===id));
  // Hapus: (3) entry Pelunasan Hutang Supplier yang terhubung via refId
  DB.kasbank = DB.kasbank.filter(k=>!(k.kategori==='Pelunasan Hutang Supplier' && k.refId===id));
  // Hapus: (4) entry Uang Muka Dipakai yang terhubung via refId
  DB.kasbank = DB.kasbank.filter(k=>!(k.kategori==='Uang Muka Dipakai' && k.refId===id));
  rebuildSemuaJurnal(); // Sprint 12: sinkronkan jurnal setelah penghapusan
  saveDB();
  renderPembelian();
  showToast('Transaksi dan semua catatan kas terkait dihapus.');
}

