/* ============================================================
   FORM PRODUKSI (GILING)
   Columns: Batch, Mulai, Selesai, Operator, Jenis Gabah, Gabah,
            Premium, Medium, Menir, Bekatul, Rendemen (Premium+Medium)/Gabah
   ============================================================ */
function renderProduksi(target){
  target = target || document.getElementById('pageInner');
  const rows = DB.produksi.slice().sort((a,b)=> b.mulai.localeCompare(a.mulai) || b.batch.localeCompare(a.batch));

  // ── KPI Aggregat ──────────────────────────────────────────────
  const totalGabah   = DB.produksi.reduce((s,r)=>s+Number(r.gabah||0), 0);
  const totalPK      = DB.produksi.reduce((s,r)=>s+Number(r.pk||0), 0);
  const totalSekam   = DB.produksi.reduce((s,r)=>s+Number(r.sekam||0), 0);
  const totalBeras   = DB.produksi.reduce((s,r)=>s+Number(r.premium||0)+Number(r.medium||0), 0);
  const totalMenir   = DB.produksi.reduce((s,r)=>s+Number(r.menir||0), 0);
  const totalBekatul = DB.produksi.reduce((s,r)=>s+Number(r.bekatul||0), 0);
  // Rendemen Tahap 1: PK / Gabah
  const rendemenT1   = totalGabah>0 ? totalPK/totalGabah : 0;
  // Rendemen Tahap 2: Beras / PK (hanya batch yang punya field pk)
  const batchDgPK    = DB.produksi.filter(r=>Number(r.pk||0)>0);
  const pkMasukT2    = batchDgPK.reduce((s,r)=>s+Number(r.pk||0), 0);
  const rendemenT2   = pkMasukT2>0 ? totalBeras/pkMasukT2 : 0;
  // Rendemen total: Beras / Gabah
  const rendemenTotal = totalGabah>0 ? totalBeras/totalGabah : 0;
  const totalHppNilai = getTotalHPPProduksi();
  const totalOutputT2 = totalBeras+totalMenir+totalBekatul;
  const avgHppPerKgBeras = totalOutputT2>0 ? totalHppNilai/totalOutputT2 : 0;

  // ── Baris Tabel ────────────────────────────────────────────────
  let rowsHtml = '';
  if(rows.length===0){
    rowsHtml = `<tr><td colspan="14"><div class="empty-state"><div class="stamp">⚙</div><div>Belum ada batch produksi. Klik "+ Batch Baru" untuk mencatat proses giling.</div></div></td></tr>`;
  } else {
    rowsHtml = rows.map(r=>{
      const hasPK       = Number(r.pk||0) > 0;
      const renT1       = r.gabah>0 && hasPK ? (r.pk/r.gabah*100).toFixed(1)+'%' : '-';
      const renT2       = hasPK && r.pk>0 ? ((Number(r.premium||0)+Number(r.medium||0))/r.pk*100).toFixed(1)+'%' : '-';
      const renTotal    = r.gabah>0 ? ((Number(r.premium||0)+Number(r.medium||0))/r.gabah*100).toFixed(1)+'%' : '0.0%';
      const hpp         = getHppBatch(r);
      const hppGabahStr = hpp.totalQtySumber>0
        ? `${fmtRp(hpp.hppPerKgGabah)}/kg${!hpp.lengkap?' <span title="Sumber gabah belum mencakup seluruh qty" style="color:var(--gold);">⚠</span>':''}`
        : (r.tipeBahan==='Bahan Baku'&&r.hppBahanBaku>0 ? fmtRp(r.hppBahanBaku)+'/kg (BB)' : '<span style="color:var(--ink-soft);">-</span>');
      const hppBerasStr = hpp.hppPerKgBeras>0 ? fmtRp(hpp.hppPerKgBeras)+'/kg' : '-';
      const actionItems = `[{label:'Ubah',icon:'✏️',action:()=>editProduksi('${r.id}')}${SESSION.role!=='KASIR'?`,{label:'Hapus',icon:'🗑',action:()=>deleteProduksi('${r.id}'),danger:true}`:``}]`;
      return `
      <tr class="tr-clickable" onclick="showActionSheet(event,'${esc(r.batch)} — ${esc(r.jenisGabah)}',${actionItems})">
        <td class="mono">${esc(r.batch)}</td>
        <td>${fmtDate(r.mulai)}${r.selesai&&r.selesai!==r.mulai?`<br><span style="font-size:0.75rem;color:var(--ink-soft);">s/d ${fmtDate(r.selesai)}</span>`:''}</td>
        <td>${esc(r.operator||'-')}</td>
        <td>${esc(r.jenisGabah)}</td>
        <td class="num-cell">${fmtNum(r.gabah)}</td>
        <td class="num-cell">${hasPK?fmtNum(r.pk):'<span style="color:var(--ink-soft);">-</span>'}</td>
        <td class="num-cell">${Number(r.sekam||0)>0?fmtNum(r.sekam):'<span style="color:var(--ink-soft);">-</span>'}</td>
        <td class="num-cell">${fmtNum(r.premium)}</td>
        <td class="num-cell">${fmtNum(r.medium)}</td>
        <td class="num-cell">${fmtNum(Number(r.menir||0))}</td>
        <td class="num-cell">${fmtNum(Number(r.bekatul||0))}</td>
        <td class="num-cell" title="Rendemen Tahap 1: PK/Gabah | Tahap 2: Beras/PK | Total: Beras/Gabah">
          ${hasPK?`<span style="color:var(--ink-soft);font-size:0.72rem;">T1: ${renT1}<br>T2: ${renT2}<br></span>`:''}
          <b>${renTotal}</b>
        </td>
        <td class="num-cell">${hppGabahStr}</td>
      </tr>
    `;}).join('');
  }

  target.innerHTML = `
    <div class="grid grid-4" style="margin-bottom:12px;">
      <div class="kpi">
        <div class="label">Total Batch</div>
        <div class="value">${rows.length}</div>
      </div>
      <div class="kpi gold">
        <div class="label">Gabah Digiling</div>
        <div class="value">${fmtNum(totalGabah)} <span style="font-size:0.9rem;">kg</span></div>
      </div>
      <div class="kpi">
        <div class="label">PK Dihasilkan</div>
        <div class="value">${fmtNum(totalPK)} <span style="font-size:0.9rem;">kg</span></div>
        <div class="sub">Rendemen T1: ${rendemenT1>0?(rendemenT1*100).toFixed(1)+'%':'-'}</div>
      </div>
      <div class="kpi">
        <div class="label">Beras Dihasilkan</div>
        <div class="value">${fmtNum(totalBeras)} <span style="font-size:0.9rem;">kg</span></div>
        <div class="sub">Rendemen T2: ${rendemenT2>0?(rendemenT2*100).toFixed(1)+'%':'-'} · Total: ${(rendemenTotal*100).toFixed(1)}%</div>
      </div>
    </div>
    <div class="grid grid-4" style="margin-bottom:20px;">
      <div class="kpi" style="border-left-color:var(--ink-soft);">
        <div class="label">Sekam</div>
        <div class="value">${fmtNum(totalSekam)} <span style="font-size:0.9rem;">kg</span></div>
        <div class="sub">Hasil Tahap 1</div>
      </div>
      <div class="kpi" style="border-left-color:#0EA5E9;">
        <div class="label">Menir</div>
        <div class="value">${fmtNum(totalMenir)} <span style="font-size:0.9rem;">kg</span></div>
        <div class="sub">Hasil Tahap 2</div>
      </div>
      <div class="kpi" style="border-left-color:var(--red);">
        <div class="label">Bekatul</div>
        <div class="value">${fmtNum(totalBekatul)} <span style="font-size:0.9rem;">kg</span></div>
        <div class="sub">Hasil Tahap 2</div>
      </div>
      <div class="kpi gold">
        <div class="label">Rata-rata HPP/Kg Beras</div>
        <div class="value" style="font-size:1.1rem;">${avgHppPerKgBeras>0?fmtRp(avgHppPerKgBeras):'-'}</div>
        <div class="sub">Nilai gabah ÷ total output T2</div>
      </div>
    </div>
    <div class="card">
      <h3>Riwayat Produksi — 2 Tahap Giling <span class="tag">${rows.length} batch</span></h3>
      <p class="help-text" style="margin-top:-4px;">
        <b>Tahap 1 (Husker):</b> Gabah → PK + Sekam &nbsp;|&nbsp;
        <b>Tahap 2 (Polisher):</b> PK → Beras Premium + Beras Medium + Menir + Bekatul.<br>
        Rendemen Beras = (Premium + Medium) ÷ Gabah Masuk. HPP dihitung dari sumber gabah yang dipilih (rata-rata tertimbang). Tanda ⚠ = sumber gabah belum lengkap.
      </p>
      <button class="btn btn-primary" style="width:auto;" onclick="editProduksi(null)">+ Batch Baru</button>
      <button class="btn btn-secondary" style="width:auto;" onclick="printReport('printProduksi','Riwayat Produksi (Giling 2 Tahap)','Total '+${rows.length}+' batch')">🖨 Cetak</button>
      ${dlMenuReport('printProduksi','Riwayat Produksi (Giling 2 Tahap)','Total '+rows.length+' batch')}
      <button class="btn btn-secondary" style="width:auto;" onclick="exportTableToExcel('printProduksi','riwayat_produksi','Produksi')">📊 Excel</button>
      <div class="m-card-wrap">
        <div class="table-wrap" style="margin-top:14px;" id="printProduksi">
          <table>
            <thead>
              <tr>
                <th rowspan="2">Batch</th>
                <th rowspan="2">Tgl</th>
                <th rowspan="2">Operator</th>
                <th rowspan="2">Varietas</th>
                <th rowspan="2">Gabah (Kg)</th>
                <th colspan="2" style="text-align:center;background:rgba(124,58,237,0.12);color:#7C3AED;">Tahap 1</th>
                <th colspan="4" style="text-align:center;background:rgba(22,163,74,0.08);color:var(--rice-green-dark);">Tahap 2</th>
                <th rowspan="2">Rendemen</th>
                <th rowspan="2">HPP/Kg Gabah</th>
              </tr>
              <tr>
                <th style="background:rgba(124,58,237,0.08);">PK (Kg)</th>
                <th style="background:rgba(124,58,237,0.08);">Sekam (Kg)</th>
                <th style="background:rgba(22,163,74,0.05);">Premium</th>
                <th style="background:rgba(22,163,74,0.05);">Medium</th>
                <th style="background:rgba(22,163,74,0.05);">Menir</th>
                <th style="background:rgba(22,163,74,0.05);">Bekatul</th>
              </tr>
            </thead>
            <tbody>${rowsHtml}</tbody>
          </table>
        </div>
        <div class="m-cards">
          ${rows.length===0?`<div class="empty-state"><div class="stamp">⚙</div><div>Belum ada batch produksi.</div></div>`:
            rows.map(r=>{
              const hasPK    = Number(r.pk||0) > 0;
              const hpp      = getHppBatch(r);
              const renTotal = r.gabah>0?((Number(r.premium||0)+Number(r.medium||0))/r.gabah*100).toFixed(1)+'%':'0.0%';
              return `
              <div class="m-card">
                <div class="m-card-head">
                  <div>
                    <div class="m-card-ref">${fmtDate(r.mulai)}${r.selesai&&r.selesai!==r.mulai?' → '+fmtDate(r.selesai):''}</div>
                    <div class="m-card-name">${esc(r.batch)}</div>
                    <div style="margin-top:4px;font-size:0.8rem;color:var(--ink-soft);">${esc(r.jenisGabah)} · ${esc(r.operator||'-')}</div>
                  </div>
                  <div style="text-align:right;">
                    <div class="m-card-amount">${fmtNum(r.gabah)} kg</div>
                    <div style="font-size:0.8rem;color:var(--ink-soft);">gabah masuk</div>
                  </div>
                </div>
                <div class="m-card-rows">
                  ${hasPK?`<b>T1:</b> PK ${fmtNum(r.pk)} kg · Sekam ${fmtNum(r.sekam||0)} kg<br>`:''}
                  <b>T2:</b> Premium ${fmtNum(r.premium)} kg · Medium ${fmtNum(r.medium)} kg · Menir ${fmtNum(r.menir||0)} kg · Bekatul ${fmtNum(r.bekatul||0)} kg<br>
                  Rendemen: <b>${renTotal}</b>${hpp.totalQtySumber>0?` · HPP: ${fmtRp(hpp.hppPerKgGabah)}/kg gabah`:''}
                </div>
                <div class="m-card-actions">
                  <button class="btn btn-sm btn-secondary" onclick="editProduksi('${r.id}')">Ubah</button>
                  ${SESSION.role!=='KASIR'?`<button class="btn btn-sm btn-danger" onclick="deleteProduksi('${r.id}')">Hapus</button>`:''}
                </div>
              </div>`;
            }).join('')
          }
        </div>
      </div>
    </div>
    <div class="card">
      <h3>Stok Hasil Produksi Saat Ini</h3>
      <div id="stokProduksiBox"></div>
    </div>
  `;
  renderStokProduksi(target.querySelector('#stokProduksiBox'));
}

function renderStokProduksi(box){
  const stok = getStokProduk();
  // Tahap 1: intermediary
  const t1Items = [
    {label:'PK (Pecah Kulit)',  key:'PK',    color:'#7C3AED', sub:'Stok antara Tahap 1→2'},
    {label:'Sekam',             key:'Sekam',  color:'var(--ink-soft)', sub:'Hasil Tahap 1'},
  ];
  // Tahap 2: produk akhir
  const t2Items = [
    {label:'Beras Premium', key:'Premium', color:'var(--rice-green)', sub:'Hasil Tahap 2'},
    {label:'Beras Medium',  key:'Medium',  color:'var(--gold)',       sub:'Hasil Tahap 2'},
    {label:'Menir',         key:'Menir',   color:'#0EA5E9',           sub:'Hasil Tahap 2'},
    {label:'Bekatul',       key:'Bekatul', color:'var(--red)',        sub:'Hasil Tahap 2'},
  ];
  box.innerHTML = `
    <div style="font-size:0.78rem;font-weight:700;text-transform:uppercase;letter-spacing:0.06em;color:var(--ink-soft);margin-bottom:8px;">
      Tahap 1 — Gabah → PK + Sekam
    </div>
    <div class="grid grid-4" style="margin-bottom:16px;">
      ${t1Items.map(it=>`
        <div class="kpi" style="border-left-color:${it.color};">
          <div class="label">${it.label}</div>
          <div class="value" style="font-size:1.25rem;">${fmtNum(stok[it.key]||0)} <span style="font-size:0.85rem;">kg</span></div>
          <div class="sub">${it.sub}</div>
        </div>
      `).join('')}
    </div>
    <div style="font-size:0.78rem;font-weight:700;text-transform:uppercase;letter-spacing:0.06em;color:var(--ink-soft);margin-bottom:8px;">
      Tahap 2 — PK → Beras + Menir + Bekatul
    </div>
    <div class="grid grid-4">
      ${t2Items.map(it=>`
        <div class="kpi" style="border-left-color:${it.color};">
          <div class="label">${it.label}</div>
          <div class="value" style="font-size:1.25rem;">${fmtNum(stok[it.key]||0)} <span style="font-size:0.85rem;">kg</span></div>
          <div class="sub">${it.sub}</div>
        </div>
      `).join('')}
    </div>
  `;
}

// Compute current stock = total produced - total sold, per product
function getStokProduk(){
  const items = {};
  DB.jenisBeras.forEach(j=>{ items[j] = 0; });
  (DB.jenisSamping||[]).forEach(j=>{ if(!(j in items)) items[j] = 0; });
  // Produk tetap (selalu dilacak)
  ['Premium','Medium','Menir','Bekatul','PK','Sekam'].forEach(j=>{ if(!(j in items)) items[j] = 0; });

  DB.produksi.forEach(r=>{
    // Tahap 1: Gabah → PK + Sekam
    if('PK' in items)    items.PK    += Number(r.pk||0);
    if('Sekam' in items) items.Sekam += Number(r.sekam||0);
    // Tahap 2: PK → Beras + Menir + Bekatul
    // Jika batch pakai mode Bahan Baku (PK sudah jadi), PK-nya tidak dari field pk
    if(r.tipeBahan === 'Bahan Baku'){
      // masuk dari stok PK yang sudah dibeli sebagai bahan baku
      items.PK -= Number(r.gabah||0); // PK keluar dipakai produksi
    } else if(Number(r.pk||0) > 0){
      // Jika ada field pk: PK hasil Tahap 1 langsung masuk Tahap 2 (bersih)
      // PK masuk = r.pk (dari Tahap 1), PK keluar ke Tahap 2 = total output Tahap 2
      const outputTahap2 = Number(r.premium||0)+Number(r.medium||0)+Number(r.menir||0)+Number(r.bekatul||0);
      // PK yang tersisa di gudang = pk - outputTahap2 (bisa 0 jika langsung diproses)
      // Untuk backward compat: jika tidak ada field pk, tidak kurangi PK
      // Kurangi PK sebesar total output Tahap 2 (PK terpakai di Tahap 2)
      items.PK -= Math.min(Number(r.pk||0), outputTahap2);
    }
    if('Premium' in items) items.Premium += Number(r.premium||0);
    if('Medium' in items)  items.Medium  += Number(r.medium||0);
    if('Menir' in items)   items.Menir   += Number(r.menir||0);
    if('Bekatul' in items) items.Bekatul += Number(r.bekatul||0);
  });
  // direct purchase of finished goods (beli beras langsung) or produk samping
  DB.pembelian.forEach(r=>{
    if(r.kategori==='Beras' || r.kategori==='Produk Samping'){
      if(!items.hasOwnProperty(r.jenisGabah)) items[r.jenisGabah] = 0;
      items[r.jenisGabah] += Number(r.qty||0);
    }
  });
  // sales of finished goods (Beras Utama + Produk Samping, skip Gabah)
  DB.penjualan.forEach(r=>{
    if(r.kategori==='Gabah') return; // gabah sales tracked in getStokGabah
    if(!items.hasOwnProperty(r.produk)) return;
    if(r.kirimBertahap){
      // Stock is only reduced as shipments are actually delivered ("Terkirim"),
      // since the sale was paid/recorded upfront but goods leave the warehouse in trips.
      const terkirim = getQtyTerkirim(r.id);
      items[r.produk] -= terkirim;
    } else {
      items[r.produk] -= Number(r.qty||0);
    }
  });
  // Maklon: produk yang jadi milik CV (Tipe B: bekatul; Tipe C: bagi hasil beras)
  (DB.maklon||[]).forEach(m=>{
    if(m.status !== 'Selesai') return;
    if(m.tipe === 'B'){
      // Bekatul milik CV
      if(!items.hasOwnProperty('Bekatul')) items.Bekatul = 0;
      items.Bekatul += Number(m.bekatul||0);
      // Menir juga milik CV pada beberapa perjanjian (jika ada field menir)
      if(Number(m.menir||0)>0){
        if(!items.hasOwnProperty('Menir')) items.Menir = 0;
        items.Menir += Number(m.menir||0);
      }
      // Sekam milik CV
      if(Number(m.sekam||0)>0){
        if(!items.hasOwnProperty('Sekam')) items.Sekam = 0;
        items.Sekam += Number(m.sekam||0);
      }
    } else if(m.tipe === 'C'){
      // Bagi hasil: bagian beras CV
      const beras = Number(m.gabahMasuk||0) * Number(m.berbagiHasilPct||0) / 100;
      if(beras > 0){
        if(!items.hasOwnProperty('Medium')) items.Medium = 0;
        items.Medium += beras;
      }
      // Bekatul + Menir juga milik CV pada tipe C
      if(Number(m.bekatul||0)>0){
        if(!items.hasOwnProperty('Bekatul')) items.Bekatul = 0;
        items.Bekatul += Number(m.bekatul||0);
      }
      if(Number(m.menir||0)>0){
        if(!items.hasOwnProperty('Menir')) items.Menir = 0;
        items.Menir += Number(m.menir||0);
      }
    }
  });
  // manual mutasi adjustments (Masuk = +, Keluar = -)
  DB.mutasi.forEach(m=>{
    if(m.kategori === 'Gabah') return;
    if(!items.hasOwnProperty(m.item)) items[m.item] = 0;
    items[m.item] += (m.jenis==='Masuk' ? 1 : -1) * Number(m.qty||0);
  });
  return items;
}

// Gabah (raw paddy) stock: total purchased minus total used in production minus direct
// gabah sales, plus manual mutasi
function getStokGabah(){
  const stok = {};
  DB.jenisGabah.forEach(j=>{ stok[j] = 0; });
  DB.pembelian.forEach(r=>{
    if(r.kategori==='Beras' || r.kategori==='Produk Samping' || r.kategori==='Bahan Baku') return;
    if(!stok.hasOwnProperty(r.jenisGabah)) stok[r.jenisGabah] = 0;
    stok[r.jenisGabah] += Number(r.qty||0);
  });
  DB.produksi.forEach(r=>{
    if(!stok.hasOwnProperty(r.jenisGabah)) stok[r.jenisGabah] = 0;
    stok[r.jenisGabah] -= Number(r.gabah||0);
  });
  // direct sales of raw gabah (jual gabah langsung tanpa giling)
  DB.penjualan.forEach(r=>{
    if(r.kategori !== 'Gabah') return;
    if(!stok.hasOwnProperty(r.produk)) stok[r.produk] = 0;
    stok[r.produk] -= Number(r.qty||0);
  });
  DB.mutasi.forEach(m=>{
    if(m.kategori !== 'Gabah') return;
    if(!stok.hasOwnProperty(m.item)) stok[m.item] = 0;
    stok[m.item] += (m.jenis==='Masuk' ? 1 : -1) * Number(m.qty||0);
  });
  return stok;
}

// Stok Bahan Baku (Beras Pecah Kulit dll) — masuk dari pembelian 'Bahan Baku',
// keluar saat dipakai sebagai bahan produksi (tipeBahan='Bahan Baku')
function getStokBahanBaku(){
  const stok = {};
  (DB.jenisBahanBaku||[]).forEach(j=>{ stok[j] = 0; });
  DB.pembelian.forEach(r=>{
    if(r.kategori !== 'Bahan Baku') return;
    if(!stok.hasOwnProperty(r.jenisGabah)) stok[r.jenisGabah] = 0;
    stok[r.jenisGabah] += Number(r.qty||0);
  });
  DB.produksi.forEach(r=>{
    if(r.tipeBahan !== 'Bahan Baku') return;
    if(!stok.hasOwnProperty(r.jenisBahanBaku)) stok[r.jenisBahanBaku] = 0;
    stok[r.jenisBahanBaku] -= Number(r.gabah||0);
  });
  return stok;
}

/* ============================================================
   SERVICE FUNCTIONS — DASHBOARD SPRINT 4
   Stok Gabah · PK · Beras · Bekatul · Sekam
   Profit Batch · Rendemen Bulan · Forecast Gabah
   ============================================================ */

/** Total gabah milik CV di gudang (semua jenis, agregat kg) */
function getStokGabahTotal(){
  const s = getStokGabah();
  return Object.values(s).reduce((sum,v)=>sum+v, 0);
}

/** Stok PK bersih: PK hasil produksi dikurangi PK yang sudah diproses ke Tahap 2 */
function getStokPKTotal(){
  return Math.max(0, (getStokProduk().PK || 0));
}

/** Total beras di gudang (Premium + Medium) */
function getStokBerasTotal(){
  const s = getStokProduk();
  return Math.max(0, (s.Premium||0) + (s.Medium||0));
}

/** Stok Bekatul */
function getStokBekatulTotal(){
  return Math.max(0, getStokProduk().Bekatul||0);
}

/** Stok Sekam */
function getStokSekamTotal(){
  return Math.max(0, getStokProduk().Sekam||0);
}

/**
 * Profit per batch produksi (estimasi).
 * Profit = nilai output (qty × harga_jual_avg per produk) − HPP_batch
 * Harga jual rata-rata diambil dari DB.penjualan per jenis produk.
 * @returns Array [{batch, gabah, hpp, pendapatan, profit, margin}]
 */
function getProfitBatch(){
  // Hitung harga jual rata-rata per produk dari seluruh history penjualan
  const hargaAvg = {};
  const hargaCount = {};
  DB.penjualan.forEach(r=>{
    if(!r.produk || !r.harga) return;
    hargaAvg[r.produk]   = (hargaAvg[r.produk]||0)   + Number(r.harga||0);
    hargaCount[r.produk] = (hargaCount[r.produk]||0) + 1;
  });
  Object.keys(hargaAvg).forEach(k=>{ hargaAvg[k] = hargaAvg[k]/hargaCount[k]; });

  // Harga fallback jika belum ada history penjualan
  const H_DEFAULT = { Premium:12500, Medium:10500, Menir:4500, Bekatul:3500, Sekam:500 };
  const harga = (produk) => hargaAvg[produk] || H_DEFAULT[produk] || 0;

  return DB.produksi.map(r=>{
    const hpp = getHppBatch(r);
    const premium = Number(r.premium||0), medium = Number(r.medium||0);
    const menir   = Number(r.menir||0),   bekatul= Number(r.bekatul||0);
    const sekam   = Number(r.sekam||0);
    const pendapatan =
      premium  * harga('Premium')  +
      medium   * harga('Medium')   +
      menir    * harga('Menir')    +
      bekatul  * harga('Bekatul')  +
      sekam    * harga('Sekam');
    const biaya   = hpp.totalNilai > 0 ? hpp.totalNilai : 0;
    const profit  = pendapatan - biaya;
    const margin  = pendapatan > 0 ? (profit / pendapatan * 100) : 0;
    return {
      id: r.id, batch: r.batch, tgl: r.selesai||r.mulai,
      gabah: Number(r.gabah||0), hpp: biaya,
      pendapatan, profit, margin,
      premium, medium, menir, bekatul, sekam,
      hppPerKgBeras: hpp.hppPerKgBeras,
    };
  }).sort((a,b)=>b.tgl.localeCompare(a.tgl));
}

/**
 * Rendemen beras (Premium+Medium / Gabah) untuk bulan berjalan.
 * @returns {pct, inputKg, outputKg, batches}
 */
function getRendemenBulanIni(){
  const bulan = todayStr().slice(0,7);
  const batches = DB.produksi.filter(r=>(r.selesai||r.mulai).startsWith(bulan));
  const inputKg  = batches.reduce((s,r)=>s+Number(r.gabah||0), 0);
  const outputKg = batches.reduce((s,r)=>s+Number(r.premium||0)+Number(r.medium||0), 0);
  return {
    pct    : inputKg>0 ? outputKg/inputKg*100 : 0,
    inputKg, outputKg,
    batches: batches.length,
    bulan,
  };
}

/**
 * Forecast kebutuhan gabah — moving average 3 bulan terakhir.
 * Proyeksikan kebutuhan bulan depan berdasarkan rata-rata produksi 3 bulan.
 * Hitung juga stok hari yang tersedia dengan kapasitas saat ini.
 * @returns {avg3Bulan, forecast30Hari, forecast7Hari, stokCukupHari, kapasitasHarian}
 */
function getForecastGabah(){
  const today = todayStr();
  const bulanIni  = today.slice(0,7);
  // Ambil 3 bulan terakhir (tidak termasuk bulan berjalan jika baru mulai)
  const recap = getMonthlyRecap();
  const tiga  = recap.filter(r=>r.bulan < bulanIni).slice(-3);
  const kapasitasHarian = 18500; // kg/hari default (bisa dikonfigurasi)
  if(tiga.length === 0){
    // Fallback: pakai bulan berjalan jika belum ada 3 bulan historis
    const berjalan = recap.find(r=>r.bulan===bulanIni);
    const hariKerja = new Date().getDate(); // hari ke-berapa bulan ini
    const rataHarian = berjalan && hariKerja>0
      ? berjalan.produksiGabah / hariKerja
      : 0;
    return {
      avg3Bulan     : rataHarian * 30,
      forecast30Hari: rataHarian * 30,
      forecast7Hari : rataHarian * 7,
      stokCukupHari : rataHarian>0 ? Math.floor(getStokGabahTotal()/rataHarian) : 0,
      kapasitasHarian,
      rataHarian    : Math.round(rataHarian),
      dataBulan     : berjalan ? 1 : 0,
      metode        : 'harian',
    };
  }
  const totalGabah3Bln = tiga.reduce((s,r)=>s+r.produksiGabah, 0);
  const avg3Bulan      = totalGabah3Bln / tiga.length;          // rata-rata per bulan
  const rataHarian     = avg3Bulan / 26;                        // ~26 hari kerja/bulan
  const stokSekarang   = getStokGabahTotal();
  const stokCukupHari  = rataHarian>0 ? Math.floor(stokSekarang/rataHarian) : 0;
  return {
    avg3Bulan,
    forecast30Hari: avg3Bulan,
    forecast7Hari : rataHarian * 7,
    stokCukupHari,
    kapasitasHarian,
    rataHarian    : Math.round(rataHarian),
    dataBulan     : tiga.length,
    metode        : '3bln',
  };
}

/* ============================================================
   HPP PER BATCH PRODUKSI (weighted-average cost from multiple
   supplier purchases used as raw material for a batch)
   ============================================================ */
// Effective cost per kg for a pembelian record = harga + (angkut allocated per kg)
function getHargaEfektifPembelian(p){
  const angkutPerKg = Number(p.qty||0) > 0 ? Number(p.angkut||0) / Number(p.qty||0) : 0;
  return Number(p.harga||0) + angkutPerKg;
}

// Total qty from a pembelian already allocated to produksi batches (across all batches,
// optionally excluding one batch id for use while editing that batch)
function getQtyTerpakaiPembelian(pembelianId, excludeBatchId){
  let used = 0;
  DB.produksi.forEach(r=>{
    if(r.id === excludeBatchId) return;
    (r.sumberGabah||[]).forEach(s=>{
      if(s.pembelianId === pembelianId) used += Number(s.qty||0);
    });
  });
  return used;
}

// Remaining (unallocated) qty for a pembelian record
function getSisaPembelian(pembelianId, excludeBatchId){
  const p = DB.pembelian.find(x=>x.id===pembelianId);
  if(!p) return 0;
  return Number(p.qty||0) - getQtyTerpakaiPembelian(pembelianId, excludeBatchId);
}

// ============================================================
// STOK TITIPAN MAKLON — Gabah dan Beras milik pelanggan
// yang sedang dalam proses atau menunggu pengambilan.
// Terpisah total dari stok CV.
// ============================================================

// Stok gabah titipan pelanggan per transaksi maklon
// Gabah masuk saat maklon dicatat, keluar saat selesai (sudah jadi beras)
function getStokMaklon(){
  // {pelanggan → {gabahMasuk, berasKembali, berasMenunggu, status, tipe, records[]}}
  const map = {};
  (DB.maklon||[]).forEach(m=>{
    if(!map[m.pelanggan]) map[m.pelanggan] = {
      gabahTotal: 0, berasKembali: 0, berasMenunggu: 0,
      bekatul: 0, menir: 0, sekam: 0, records: []
    };
    const p = map[m.pelanggan];
    p.gabahTotal += Number(m.gabahMasuk||0);
    p.records.push(m);
    if(m.status === 'Selesai'){
      // Tipe A: semua beras kembali ke pelanggan
      // Tipe C: hanya bagian pelanggan yang kembali
      if(m.tipe === 'A'){
        const totalBeras = Number(m.premium||0)+Number(m.medium||0)+Number(m.menir||0);
        p.berasKembali += totalBeras;
      } else if(m.tipe === 'B'){
        // Beras milik pelanggan (bekatul/menir/sekam = CV)
        p.berasKembali += Number(m.premium||0)+Number(m.medium||0);
      } else if(m.tipe === 'C'){
        // Bagian pelanggan
        const pct = Number(m.berbagiHasilPct||0);
        const berasTotal = Number(m.premium||0)+Number(m.medium||0);
        p.berasKembali += berasTotal * (100-pct) / 100;
      }
    } else {
      // Dalam proses: beras belum jadi, gabah masih di gudang
      p.berasMenunggu += Number(m.gabahMasuk||0);
    }
  });
  return map;
}

// Ringkasan agregat stok titipan maklon
function getStokMaklonAgregat(){
  let gabahTitipan = 0, berasTitipan = 0, dalamProses = 0;
  (DB.maklon||[]).forEach(m=>{
    if(m.status !== 'Selesai'){
      gabahTitipan += Number(m.gabahMasuk||0);
      dalamProses++;
    } else {
      // Beras yang menunggu diambil pelanggan
      if(m.tipe === 'A'){
        berasTitipan += Number(m.premium||0)+Number(m.medium||0)+Number(m.menir||0);
      } else if(m.tipe === 'B'){
        berasTitipan += Number(m.premium||0)+Number(m.medium||0);
      } else if(m.tipe === 'C'){
        const pct = Number(m.berbagiHasilPct||0);
        berasTitipan += (Number(m.premium||0)+Number(m.medium||0)) * (100-pct) / 100;
      }
    }
  });
  return {gabahTitipan, berasTitipan, dalamProses};
}

// ============================================================
// HPP for a single batch: total cost of allocated gabah, and derived per-kg metrics
function getHppBatch(batch){
  const sumber = batch.sumberGabah || [];
  let totalNilai = 0, totalQtySumber = 0;
  sumber.forEach(s=>{
    totalNilai += Number(s.qty||0) * Number(s.harga||0);
    totalQtySumber += Number(s.qty||0);
  });
  // Fallback HPP dari hppBahanBaku (mode Bahan Baku)
  if(totalQtySumber === 0 && batch.tipeBahan === 'Bahan Baku' && batch.hppBahanBaku > 0){
    totalNilai = Number(batch.hppBahanBaku||0) * Number(batch.gabah||0);
    totalQtySumber = Number(batch.gabah||0);
  }
  const gabah   = Number(batch.gabah||0);
  const pk      = Number(batch.pk||0);
  const sekam   = Number(batch.sekam||0);
  const premium = Number(batch.premium||0);
  const medium  = Number(batch.medium||0);
  const menir   = Number(batch.menir||0);
  const bekatul = Number(batch.bekatul||0);
  // Tahap 1 output = pk + sekam
  const totalOutputTahap1 = pk + sekam;
  // Tahap 2 output = premium + medium + menir + bekatul
  const totalOutputTahap2 = premium + medium + menir + bekatul;
  // Total beras utama (rendemen beras)
  const totalBeras = premium + medium;
  // HPP per Kg PK = totalNilai / totalOutputTahap1 (jika ada pk, jika tidak pakai gabah)
  const hppPerKgPK = (totalOutputTahap1 > 0 && totalNilai > 0) ? totalNilai / totalOutputTahap1 : 0;
  // Nilai PK yang mengalir ke Tahap 2 = proporsi nilai gabah yang menjadi PK
  // (BUKAN seluruh nilai gabah — sebagian nilai sudah "keluar" sebagai Sekam di Tahap 1).
  // QA Sprint Final: rumus lama keliru memakai totalNilai (nilai gabah utuh) untuk
  // menghitung HPP per kg Beras, sehingga nilai sekam ikut terhitung dobel ke beras.
  // Disamakan dengan logika postProduksiTahap2() (jurnal akuntansi) yang sudah benar.
  const nilaiPKKeTahap2 = totalOutputTahap1 > 0 ? totalNilai * (pk / totalOutputTahap1) : totalNilai;
  // HPP per Kg Beras = nilai PK yang masuk Tahap 2 / total output Tahap 2
  const hppPerKgBeras = (totalOutputTahap2 > 0 && nilaiPKKeTahap2 > 0) ? nilaiPKKeTahap2 / totalOutputTahap2 : 0;
  // HPP per Kg Gabah (legacy / overall, dipertahankan untuk kompatibilitas mode Bahan Baku)
  const hppPerKgGabah = gabah > 0 && totalNilai > 0 ? totalNilai / gabah : 0;
  return {
    totalNilai,
    totalQtySumber,
    gabah,
    pk,
    sekam,
    premium,
    medium,
    menir,
    bekatul,
    totalOutputTahap1,
    totalOutputTahap2,
    totalBeras,
    hppPerKgGabah,
    hppPerKgPK,
    hppPerKgBeras,
    lengkap: totalQtySumber >= gabah && gabah > 0,
  };
}

// Total HPP across all batches (sum of allocated gabah cost, with fallback for batches
// without sumber gabah data) - kept as alias of getTotalHPP for consistency.
function getTotalHPPProduksi(){
  // Alias getTotalHPP - HPP dari gabah yang terpakai produksi
  // Catatan: getTotalHPP() mencakup HPP beras terjual + gabah terjual juga.
  // Untuk laporan produksi, kita hanya ingin HPP dari gabah yang masuk produksi.
  let total = 0;
  DB.produksi.forEach(r=>{
    const hpp = getHppBatch(r);
    if(hpp.totalQtySumber > 0){
      total += hpp.totalNilai;
    } else if(r.tipeBahan === 'Bahan Baku' && r.hppBahanBaku > 0){
      total += Number(r.hppBahanBaku||0) * Number(r.gabah||0);
    } else {
      // Fallback: rata-rata harga beli gabah jenis ini
      const matching = DB.pembelian.filter(p=>p.kategori!=='Beras' && p.jenisGabah===r.jenisGabah);
      if(matching.length > 0){
        const avgHarga = matching.reduce((s,p)=>s+getHargaEfektifPembelian(p),0)/matching.length;
        total += avgHarga * Number(r.gabah||0);
      }
    }
  });
  return total;
}

/* ============================================================
   MANAJEMEN GUDANG & STOK
   Shows current stock for gabah (raw paddy) and beras/finished
   goods, plus a full mutation history (auto from transactions +
   manual adjustments for losses, corrections, etc).
   ============================================================ */
function getMutasiHistory(){
  const rows = [];
  DB.pembelian.forEach(r=>{
    rows.push({tanggal:r.tanggal, item:r.jenisGabah, kategori:'Gabah', jenis:'Masuk', qty:r.qty, keterangan:`Pembelian gabah dari ${r.supplier} (${r.noFaktur})`, sumber:'pembelian'});
  });
  DB.produksi.forEach(r=>{
    const tgl = r.selesai||r.mulai;
    const hasPK = Number(r.pk||0) > 0;
    // Tahap 1: Gabah → PK + Sekam
    rows.push({tanggal:tgl, item:r.jenisGabah, kategori:'Gabah', jenis:'Keluar', qty:r.gabah,
      keterangan:`Tahap 1 Giling: Gabah masuk pada batch ${r.batch}`, sumber:'produksi'});
    if(hasPK){
      rows.push({tanggal:tgl, item:'PK', kategori:'Produk Samping', jenis:'Masuk', qty:r.pk,
        keterangan:`Tahap 1 Hasil: PK dari batch ${r.batch}`, sumber:'produksi'});
    }
    if(Number(r.sekam||0)>0){
      rows.push({tanggal:tgl, item:'Sekam', kategori:'Produk Samping', jenis:'Masuk', qty:r.sekam,
        keterangan:`Tahap 1 Hasil: Sekam dari batch ${r.batch}`, sumber:'produksi'});
    }
    // Tahap 2: PK → Beras + Menir + Bekatul
    if(hasPK){
      const outputTahap2 = Number(r.premium||0)+Number(r.medium||0)+Number(r.menir||0)+Number(r.bekatul||0);
      rows.push({tanggal:tgl, item:'PK', kategori:'Produk Samping', jenis:'Keluar',
        qty: Math.min(Number(r.pk||0), outputTahap2),
        keterangan:`Tahap 2: PK diproses sosoh pada batch ${r.batch}`, sumber:'produksi'});
    }
    if(Number(r.premium||0)>0) rows.push({tanggal:tgl, item:'Premium', kategori:'Beras', jenis:'Masuk', qty:r.premium, keterangan:`Tahap 2 Hasil: Beras Premium dari batch ${r.batch}`, sumber:'produksi'});
    if(Number(r.medium||0)>0)  rows.push({tanggal:tgl, item:'Medium',  kategori:'Beras', jenis:'Masuk', qty:r.medium,  keterangan:`Tahap 2 Hasil: Beras Medium dari batch ${r.batch}`,  sumber:'produksi'});
    if(Number(r.menir||0)>0)   rows.push({tanggal:tgl, item:'Menir',   kategori:'Beras', jenis:'Masuk', qty:r.menir,   keterangan:`Tahap 2 Hasil: Menir dari batch ${r.batch}`,          sumber:'produksi'});
    if(Number(r.bekatul||0)>0) rows.push({tanggal:tgl, item:'Bekatul', kategori:'Beras', jenis:'Masuk', qty:r.bekatul, keterangan:`Tahap 2 Hasil: Bekatul dari batch ${r.batch}`,         sumber:'produksi'});
  });
  DB.penjualan.forEach(r=>{
    const kategoriBarang = r.kategori==='Gabah' ? 'Gabah' : 'Beras';
    if(r.kirimBertahap){
      // Staged delivery: each "Terkirim" shipment is its own stock-out event, dated
      // on the shipment date rather than the sale date.
      DB.pengiriman.filter(p=>p.penjualanId===r.id && p.status==='Terkirim').forEach(p=>{
        rows.push({tanggal:p.tanggal, item:r.produk, kategori:kategoriBarang, jenis:'Keluar', qty:p.qty, keterangan:`Pengiriman ${p.noResi} untuk penjualan kepada ${r.pelanggan} (${r.invoice})`, sumber:'penjualan'});
      });
    } else {
      rows.push({tanggal:r.tanggal, item:r.produk, kategori:kategoriBarang, jenis:'Keluar', qty:r.qty, keterangan:`Penjualan kepada ${r.pelanggan} (${r.invoice})`, sumber:'penjualan'});
    }
  });
  // Maklon: catat mutasi titipan gabah masuk dan beras keluar
  (DB.maklon||[]).forEach(m=>{
    const label = `[Maklon-${m.tipe}] ${esc(m.noMaklon||'')} — ${esc(m.pelanggan||'')}`;
    // Gabah titipan masuk ke gudang
    rows.push({tanggal:m.tgl, item:m.jenisGabah, kategori:'Maklon-Titipan',
      jenis:'Masuk', qty:m.gabahMasuk||0,
      keterangan:`Gabah titipan masuk (${label})`, sumber:'maklon', id:m.id});
    if(m.status === 'Selesai'){
      // Gabah titipan keluar (digiling)
      rows.push({tanggal:m.tglSelesai||m.tgl, item:m.jenisGabah, kategori:'Maklon-Titipan',
        jenis:'Keluar', qty:m.gabahMasuk||0,
        keterangan:`Gabah titipan selesai digiling (${label})`, sumber:'maklon', id:m.id});
      // Produk yang kembali ke pelanggan
      const berasPel = m.tipe==='A'
        ? (Number(m.premium||0)+Number(m.medium||0)+Number(m.menir||0))
        : m.tipe==='B'
          ? (Number(m.premium||0)+Number(m.medium||0))
          : (Number(m.premium||0)+Number(m.medium||0))*(100-Number(m.berbagiHasilPct||0))/100;
      if(berasPel > 0){
        rows.push({tanggal:m.tglSelesai||m.tgl, item:'Beras Titipan',
          kategori:'Maklon-Titipan', jenis:'Keluar', qty:berasPel,
          keterangan:`Beras dikembalikan ke pelanggan (${label})`, sumber:'maklon', id:m.id});
      }
      // Produk CV dari maklon B
      if(m.tipe==='B'){
        if(Number(m.bekatul||0)>0) rows.push({tanggal:m.tglSelesai||m.tgl, item:'Bekatul',
          kategori:'Beras', jenis:'Masuk', qty:m.bekatul,
          keterangan:`Bekatul milik CV dari ${label}`, sumber:'maklon', id:m.id});
        if(Number(m.menir||0)>0)  rows.push({tanggal:m.tglSelesai||m.tgl, item:'Menir',
          kategori:'Beras', jenis:'Masuk', qty:m.menir,
          keterangan:`Menir milik CV dari ${label}`, sumber:'maklon', id:m.id});
        if(Number(m.sekam||0)>0)  rows.push({tanggal:m.tglSelesai||m.tgl, item:'Sekam',
          kategori:'Produk Samping', jenis:'Masuk', qty:m.sekam,
          keterangan:`Sekam milik CV dari ${label}`, sumber:'maklon', id:m.id});
      }
      // Produk CV dari maklon C (bagi hasil)
      if(m.tipe==='C'){
        const pct = Number(m.berbagiHasilPct||0);
        const berasCV = (Number(m.premium||0)+Number(m.medium||0)) * pct / 100;
        if(berasCV > 0) rows.push({tanggal:m.tglSelesai||m.tgl, item:'Medium',
          kategori:'Beras', jenis:'Masuk', qty:berasCV,
          keterangan:`Bagi hasil ${pct}% milik CV dari ${label}`, sumber:'maklon', id:m.id});
        if(Number(m.bekatul||0)>0) rows.push({tanggal:m.tglSelesai||m.tgl, item:'Bekatul',
          kategori:'Beras', jenis:'Masuk', qty:m.bekatul,
          keterangan:`Bekatul milik CV dari ${label}`, sumber:'maklon', id:m.id});
      }
    }
  });
  DB.mutasi.forEach(m=>{
    rows.push({tanggal:m.tanggal, item:m.item, kategori:m.kategori, jenis:m.jenis, qty:m.qty, keterangan:m.keterangan, sumber:'manual', id:m.id});
  });
  return rows.sort((a,b)=> b.tanggal.localeCompare(a.tanggal));
}

function renderGudang(target){
  target = target || document.getElementById('pageInner');
  const stokBeras = getStokProduk();
  const stokGabah = getStokGabah();
  const history = getMutasiHistory();
  const canEdit = true; // all roles can record manual mutasi (e.g. kasir noting losses)

  const stokBerasCards = Object.entries(stokBeras).map(([k,v])=>`
    <div class="kpi" style="border-left-color:${v<0?'var(--red)':'var(--rice-green)'};">
      <div class="label">Stok ${esc(k)}</div>
      <div class="value ${v<0?'neg':''}" style="font-size:1.1rem;">${fmtNum(v)} kg</div>
    </div>
  `).join('');
  const stokGabahCards = Object.entries(stokGabah).map(([k,v])=>`
    <div class="kpi" style="border-left-color:${v<0?'var(--red)':'var(--gold)'};">
      <div class="label">Stok Gabah ${esc(k)}</div>
      <div class="value ${v<0?'neg':''}" style="font-size:1.1rem;">${fmtNum(v)} kg</div>
    </div>
  `).join('');

  let rowsHtml = '';
  if(history.length===0){
    rowsHtml = `<tr><td colspan="6"><div class="empty-state"><div class="stamp">📦</div><div>Belum ada riwayat mutasi stok.</div></div></td></tr>`;
  } else {
    rowsHtml = history.map(h=>`
      <tr class="${h.sumber==='manual'?'tr-clickable':''}" ${h.sumber==='manual'?`onclick="showActionSheet(event,'Mutasi: ${esc(h.item)}',[{label:'Ubah',icon:'✏️',action:()=>editMutasi('${h.id}')},{label:'Hapus',icon:'🗑',action:()=>deleteMutasi('${h.id}'),danger:true}])"`:''}>
        <td>${fmtDate(h.tanggal)}</td>
        <td><span class="badge" style="background:var(--paper-2); color:var(--ink);">${esc(h.kategori)}</span></td>
        <td>${esc(h.item)}</td>
        <td><span class="badge ${h.jenis==='Masuk'?'lunas':'belum'}">${esc(h.jenis)}</span></td>
        <td class="num-cell">${fmtNum(h.qty)} kg</td>
        <td>${esc(h.keterangan)} ${h.sumber==='manual'?'<span style="font-size:0.72rem;color:var(--rice-green);margin-left:4px;">✏ klik untuk ubah</span>':'<span style="font-size:0.72rem;color:var(--ink-soft);margin-left:4px;">(otomatis)</span>'}</td>
      </tr>
    `).join('');
  }

  const maklonAgregat = getStokMaklonAgregat();
  const maklonMap = getStokMaklon();
  const hasMaklonAktif = maklonAgregat.gabahTitipan > 0 || maklonAgregat.berasTitipan > 0;
  const maklonPelangganCards = Object.entries(maklonMap).map(([pel,d])=>{
    const dalamProses = d.records.filter(r=>r.status!=='Selesai');
    const selesaiTunggu = d.records.filter(r=>r.status==='Selesai');
    const gabahProses   = dalamProses.reduce((s,r)=>s+Number(r.gabahMasuk||0),0);
    const berasMenunggu = selesaiTunggu.reduce((s,r)=>{
      if(r.tipe==='A') return s+Number(r.premium||0)+Number(r.medium||0)+Number(r.menir||0);
      if(r.tipe==='B') return s+Number(r.premium||0)+Number(r.medium||0);
      if(r.tipe==='C') return s+(Number(r.premium||0)+Number(r.medium||0))*(100-Number(r.berbagiHasilPct||0))/100;
      return s;
    }, 0);
    if(gabahProses===0 && berasMenunggu===0) return '';
    return `<div class="kpi" style="border-left-color:#7C3AED;">
      <div class="label">Titipan: ${esc(pel)}</div>
      ${gabahProses>0  ? `<div style="font-size:0.82rem;">Gabah: <b>${fmtNum(gabahProses)} kg</b> (proses)</div>` : ''}
      ${berasMenunggu>0? `<div style="font-size:0.82rem;">Beras: <b>${fmtNum(Math.round(berasMenunggu))} kg</b> (menunggu ambil)</div>` : ''}
    </div>`;
  }).join('');

  target.innerHTML = `
    <div class="card">
      <h3>Stok Beras &amp; Barang Jadi — Milik CV</h3>
      <div class="grid grid-4">${stokBerasCards}</div>
    </div>
    ${hasMaklonAktif ? `
    <div class="card" style="border-left:3px solid #7C3AED;">
      <h3>Stok Titipan Maklon — Milik Pelanggan <span class="tag" style="background:#EDE9FE;color:#7C3AED;">${(DB.maklon||[]).filter(m=>m.status!=='Selesai').length} aktif</span></h3>
      <p class="help-text" style="margin-top:-4px;">Gabah dan beras ini bukan milik CV. Dicatat terpisah untuk transparansi.</p>
      <div class="grid grid-4">${maklonPelangganCards||'<div class="empty-state">Tidak ada titipan aktif.</div>'}</div>
    </div>` : ''}
    <div class="card">
      <h3>Stok Gabah (Bahan Baku CV)</h3>
      <div class="grid grid-4">${stokGabahCards || '<div class="empty-state">Belum ada data pembelian gabah.</div>'}</div>
    </div>
    <div class="card">
      <h3>Riwayat Mutasi Barang (Masuk/Keluar) <span class="tag">${history.length} catatan</span></h3>
      <p class="help-text" style="margin-top:-4px;">Mutasi otomatis tercatat dari Pembelian (gabah masuk), Produksi (gabah keluar → beras masuk), dan Penjualan (beras keluar). Gunakan "+ Mutasi Manual" untuk koreksi stok, susut, atau barang rusak.</p>
      ${canEdit ? `<button class="btn btn-primary" style="width:auto;" onclick="editMutasi(null)">+ Mutasi Manual</button>` : ''}
      <button class="btn btn-secondary" style="width:auto;" onclick="printReport('printGudang','Riwayat Mutasi Stok','Total catatan: ${history.length}')">🖨 Cetak Laporan</button>
      ${dlMenuReport('printGudang','Riwayat Mutasi Stok','Total '+history.length+' catatan')}
      <button class="btn btn-secondary" style="width:auto;" onclick="exportTableToExcel('printGudang','riwayat_mutasi_stok')">📊 Unduh Excel</button>
      <div class="table-wrap" style="margin-top:14px;" id="printGudang">
        <table>
          <thead><tr><th>Tanggal</th><th>Kategori</th><th>Item</th><th>Jenis</th><th>Qty</th><th>Keterangan</th></tr></thead>
          <tbody>${rowsHtml}</tbody>
        </table>
      </div>
    </div>
  `;
}

function editMutasi(id){
  const isNew = id===null;
  const row = isNew ? {id: uid(), tanggal: todayStr(), kategori:'Beras', item:'Premium', jenis:'Keluar', qty:0, keterangan:''} : DB.mutasi.find(r=>r.id===id);

  openModal(`
    <h2>${isNew?'Mutasi Stok Manual':'Ubah Mutasi Stok'}</h2>
    <p class="help-text" style="margin-top:-4px;">Gunakan untuk mencatat penyusutan, kerusakan, koreksi stok fisik (stok opname), atau penambahan stok dari sumber luar pencatatan transaksi normal.</p>
    <div class="form-row">
      <div class="field">
        <label>Tanggal</label>
        <input type="date" id="mu_tanggal" value="${esc(row.tanggal)}">
      </div>
      <div class="field">
        <label>Kategori</label>
        <select id="mu_kategori" onchange="updateMutasiItemOptions()">
          <option value="Beras" ${row.kategori==='Beras'?'selected':''}>Beras / Barang Jadi</option>
          <option value="Gabah" ${row.kategori==='Gabah'?'selected':''}>Gabah (Bahan Baku)</option>
        </select>
      </div>
    </div>
    <div class="form-row">
      <div class="field">
        <label>Item</label>
        <select id="mu_item">${getMutasiItemOptions(row.kategori, row.item)}</select>
      </div>
      <div class="field">
        <label>Jenis Mutasi</label>
        <select id="mu_jenis">
          <option value="Masuk" ${row.jenis==='Masuk'?'selected':''}>Masuk (Tambah Stok)</option>
          <option value="Keluar" ${row.jenis==='Keluar'?'selected':''}>Keluar (Kurangi Stok)</option>
        </select>
      </div>
      <div class="field">
        <label>Qty (Kg)</label>
        <input type="number" id="mu_qty" value="${row.qty}" min="0">
      </div>
    </div>
    <div class="field">
      <label>Keterangan</label>
      <input type="text" id="mu_ket" value="${esc(row.keterangan)}" placeholder="contoh: Stok opname bulanan, susut pengeringan, dll">
    </div>
    <div class="form-actions">
      <button class="btn btn-primary" style="width:auto;" onclick="saveMutasi('${row.id}', ${isNew})">Simpan</button>
      <button class="btn btn-secondary" onclick="closeModal()">Batal</button>
    </div>
  `);
}
function getMutasiItemOptions(kategori, selected){
  const list = kategori==='Gabah' ? DB.jenisGabah : DB.jenisBeras;
  return list.map(j=>`<option value="${esc(j)}" ${j===selected?'selected':''}>${esc(j)}</option>`).join('');
}
function updateMutasiItemOptions(){
  const kategori = document.getElementById('mu_kategori').value;
  document.getElementById('mu_item').innerHTML = getMutasiItemOptions(kategori, null);
}
function saveMutasi(id, isNew){
  const tanggal = document.getElementById('mu_tanggal').value;
  const kategori = document.getElementById('mu_kategori').value;
  const item = document.getElementById('mu_item').value;
  const jenis = document.getElementById('mu_jenis').value;
  const qty = Number(document.getElementById('mu_qty').value)||0;
  const keterangan = document.getElementById('mu_ket').value.trim();

  if(!tanggal || !item || qty<=0 || !keterangan){
    alert('Tanggal, Item, Qty, dan Keterangan wajib diisi dengan benar.');
    return;
  }
  if(isNew){
    DB.mutasi.push({id, tanggal, kategori, item, jenis, qty, keterangan});
  } else {
    const row = DB.mutasi.find(r=>r.id===id);
    Object.assign(row, {tanggal, kategori, item, jenis, qty, keterangan});
  }
  saveDB();
  closeModal();
  renderGudang();
  showToast('Mutasi stok tersimpan.');
}
function deleteMutasi(id){
  if(!confirm('Hapus catatan mutasi ini?')) return;
  DB.mutasi = DB.mutasi.filter(r=>r.id!==id);
  saveDB();
  renderGudang();
  showToast('Catatan dihapus.');
}

/* ============================================================
   DISTRIBUSI & PENGIRIMAN
   Each shipment can be linked to a Penjualan (sales) record.
   ============================================================ */
const PENGIRIMAN_STATUS = ['Dijadwalkan','Dalam Pengiriman','Terkirim','Dibatalkan'];

// Total qty already delivered ("Terkirim") for a given penjualan record, across all
// linked pengiriman. Used for staged/multi-trip shipments where payment is settled
// upfront but goods leave the warehouse over several trips.
function getQtyTerkirim(penjualanId){
  return DB.pengiriman
    .filter(p=>p.penjualanId===penjualanId && p.status==='Terkirim')
    .reduce((s,p)=>s+Number(p.qty||0), 0);
}
// Remaining qty yet to be shipped for a penjualan record with staged delivery
function getSisaKirimPenjualan(penjualanRow){
  return Math.max(0, Number(penjualanRow.qty||0) - getQtyTerkirim(penjualanRow.id));
}

function renderDistribusi(target){
  target = target || document.getElementById('pageInner');
  const rows = DB.pengiriman.slice().sort((a,b)=> b.tanggal.localeCompare(a.tanggal) || b.id.localeCompare(a.id));

  const totalKirim = rows.length;
  const totalTerkirim = rows.filter(r=>r.status==='Terkirim').length;
  const totalProses = rows.filter(r=>r.status==='Dijadwalkan' || r.status==='Dalam Pengiriman').length;

  let rowsHtml = '';
  if(rows.length===0){
    rowsHtml = `<tr><td colspan="9"><div class="empty-state"><div class="stamp">🚚</div><div>Belum ada catatan pengiriman. Klik "+ Pengiriman Baru" untuk mencatat distribusi barang ke pelanggan.</div></div></td></tr>`;
  } else {
    rowsHtml = rows.map(r=>{
      const statusBadge = r.status==='Terkirim' ? 'lunas' : (r.status==='Dibatalkan' ? 'belum' : 'belum');
      const statusColor = r.status==='Terkirim' ? '#DCFCE7' : r.status==='Dalam Pengiriman' ? '#FEF3C7' : r.status==='Dibatalkan' ? '#FEE2E2' : '#EEF1F4';
      return `
      <tr class="tr-clickable" onclick="showActionSheet(event,'${esc(r.noResi)} — ${esc(r.pelanggan)}',[{label:'Surat Jalan',icon:'📄',action:()=>printSuratJalan('${r.id}')},{label:'Ubah Status/Info',icon:'✏️',action:()=>editPengiriman('${r.id}')}${SESSION.role!=='KASIR'?`,{label:'Hapus',icon:'🗑',action:()=>deletePengiriman('${r.id}'),danger:true}`:``}])">
        <td>${fmtDate(r.tanggal)}</td>
        <td class="mono">${esc(r.noResi)}</td>
        <td>${esc(r.pelanggan)}</td>
        <td>${esc(r.produk)}</td>
        <td class="num-cell">${fmtNum(r.qty)} kg</td>
        <td>${esc(r.kendaraan||'-')}</td>
        <td>${esc(r.sopir||'-')}</td>
        <td><span class="badge" style="background:${statusColor}; color:var(--ink);">${esc(r.status)}</span></td>
      </tr>
    `;}).join('');
  }

  target.innerHTML = `
    <div class="grid grid-3" style="margin-bottom:20px;">
      <div class="kpi">
        <div class="label">Total Pengiriman</div>
        <div class="value">${totalKirim}</div>
      </div>
      <div class="kpi gold">
        <div class="label">Dalam Proses / Dijadwalkan</div>
        <div class="value">${totalProses}</div>
      </div>
      <div class="kpi">
        <div class="label">Sudah Terkirim</div>
        <div class="value">${totalTerkirim}</div>
      </div>
    </div>
    <div class="card">
      <h3>Riwayat Distribusi &amp; Pengiriman <span class="tag">${rows.length} pengiriman</span></h3>
      <button class="btn btn-primary" style="width:auto;" onclick="editPengiriman(null)">+ Pengiriman Baru</button>
      <button class="btn btn-secondary" style="width:auto;" onclick="printReport('printDistribusi','Riwayat Distribusi &amp; Pengiriman','Total '+rows.length+' pengiriman')">🖨 Cetak Laporan</button>
      ${dlMenuReport('printDistribusi','Riwayat Distribusi &amp; Pengiriman','Total '+rows.length+' pengiriman')}
      <button class="btn btn-secondary" style="width:auto;" onclick="exportTableToExcel('printDistribusi','riwayat_distribusi')">📊 Unduh Excel</button>
      <div class="table-wrap" style="margin-top:14px;" id="printDistribusi">
        <table>
          <thead><tr>
            <th>Tanggal</th><th>No. Resi</th><th>Pelanggan</th><th>Produk</th><th>Qty</th><th>Kendaraan</th><th>Sopir</th><th>Status</th>
          </tr></thead>
          <tbody>${rowsHtml}</tbody>
        </table>
      </div>
    </div>
  `;
}

function editPengiriman(id){
  const isNew = id===null;
  const row = isNew ? {
    id: uid(), tanggal: todayStr(), noResi: nextCode('resi','RESI',4),
    penjualanId:'', pelanggan:'', produk:'', qty:0, kendaraan:'', sopir:'', alamat:'', status:'Dijadwalkan', keterangan:''
  } : DB.pengiriman.find(r=>r.id===id);

  // Sales transactions available to link (most recent first)
  const penjualanOpts = DB.penjualan.slice().sort((a,b)=>b.tanggal.localeCompare(a.tanggal)).map(p=>{
    let label = `${esc(p.invoice)} - ${esc(p.pelanggan)} (${esc(p.produk)}, ${fmtNum(p.qty)} kg)`;
    if(p.kirimBertahap){
      const sisa = getSisaKirimPenjualan(p) + (row.penjualanId===p.id ? Number(row.qty||0) : 0);
      label += ` &mdash; sisa kirim ${fmtNum(sisa)} kg`;
    }
    return `<option value="${p.id}" ${row.penjualanId===p.id?'selected':''}>${label}</option>`;
  }).join('');

  const kendaraanOpts = DB.kendaraan.map(k=>`<option value="${esc(k.nopol)}" ${row.kendaraan===k.nopol?'selected':''}>${esc(k.nopol)} (${esc(k.jenis)})</option>`).join('');
  const statusOpts = PENGIRIMAN_STATUS.map(s=>`<option value="${s}" ${row.status===s?'selected':''}>${s}</option>`).join('');

  openModal(`
    <h2>${isNew?'Pengiriman Baru':'Ubah Pengiriman'}</h2>
    <div class="modal-sub">No. Resi: <span class="mono">${esc(row.noResi)}</span> ${isNew?'(otomatis)':''}</div>
    <div class="form-row">
      <div class="field">
        <label>Tanggal</label>
        <input type="date" id="kr_tanggal" value="${esc(row.tanggal)}">
      </div>
      <div class="field">
        <label>Hubungkan ke Transaksi Penjualan (opsional)</label>
        <select id="kr_penjualan" onchange="autoFillPengiriman()">
          <option value="">-- Tanpa transaksi penjualan --</option>
          ${penjualanOpts}
        </select>
      </div>
    </div>
    <div class="form-row">
      <div class="field">
        <label>Pelanggan</label>
        <input type="text" id="kr_pelanggan" value="${esc(row.pelanggan)}">
      </div>
      <div class="field">
        <label>Produk</label>
        <input type="text" id="kr_produk" value="${esc(row.produk)}" placeholder="contoh: Beras Premium">
      </div>
      <div class="field">
        <label>Qty (Kg)</label>
        <input type="number" id="kr_qty" value="${row.qty}" min="0" oninput="updateKrSisaNote()">
      </div>
    </div>
    <p class="help-text" id="kr_sisa_note" style="margin-top:-4px;"></p>
    <div class="form-row">
      <div class="field">
        <label>Kendaraan</label>
        <select id="kr_kendaraan" onchange="autoFillSopir()">
          <option value="">-- Pilih Kendaraan --</option>
          ${kendaraanOpts}
        </select>
      </div>
      <div class="field">
        <label>Sopir</label>
        <input type="text" id="kr_sopir" value="${esc(row.sopir)}">
      </div>
      <div class="field">
        <label>Status Pengiriman</label>
        <select id="kr_status">${statusOpts}</select>
      </div>
    </div>
    <div class="field">
      <label>Alamat Tujuan</label>
      <input type="text" id="kr_alamat" value="${esc(row.alamat)}">
    </div>
    <div class="field">
      <label>Keterangan</label>
      <input type="text" id="kr_ket" value="${esc(row.keterangan)}" placeholder="contoh: Bukti foto diserahkan, catatan penerima, dll">
    </div>
    <div class="form-actions">
      <button class="btn btn-primary" style="width:auto;" onclick="savePengiriman('${row.id}', ${isNew})">Simpan</button>
      <button class="btn btn-secondary" onclick="closeModal()">Batal</button>
    </div>
  `);
  updateKrSisaNote();
}
function updateKrSisaNote(){
  const penjualanId = document.getElementById('kr_penjualan').value;
  const note = document.getElementById('kr_sisa_note');
  if(!penjualanId){ note.textContent = ''; return; }
  const p = DB.penjualan.find(x=>x.id===penjualanId);
  if(!p || !p.kirimBertahap){ note.textContent = ''; return; }
  const sisa = getSisaKirimPenjualan(p);
  note.innerHTML = `Penjualan ini menggunakan pengiriman bertahap. Sisa belum terkirim (selain pengiriman ini): <b>${fmtNum(sisa)} kg</b> dari total ${fmtNum(p.qty)} kg.`;
}
function autoFillPengiriman(){
  const id = document.getElementById('kr_penjualan').value;
  if(!id){ updateKrSisaNote(); return; }
  const p = DB.penjualan.find(x=>x.id===id);
  if(!p) return;
  document.getElementById('kr_pelanggan').value = p.pelanggan;
  document.getElementById('kr_produk').value = p.produk==='Premium'?'Beras Premium':p.produk==='Medium'?'Beras Medium':p.produk;
  // Default qty: remaining qty to ship for staged deliveries, otherwise full qty
  document.getElementById('kr_qty').value = p.kirimBertahap ? getSisaKirimPenjualan(p) : p.qty;
  const pelanggan = DB.pelanggan.find(c=>c.nama===p.pelanggan);
  if(pelanggan) document.getElementById('kr_alamat').value = pelanggan.alamat || '';
  updateKrSisaNote();
}
function autoFillSopir(){
  const nopol = document.getElementById('kr_kendaraan').value;
  const k = DB.kendaraan.find(x=>x.nopol===nopol);
  if(k) document.getElementById('kr_sopir').value = k.sopir || '';
}
function savePengiriman(id, isNew){
  const tanggal = document.getElementById('kr_tanggal').value;
  const penjualanId = document.getElementById('kr_penjualan').value;
  const pelanggan = document.getElementById('kr_pelanggan').value.trim();
  const produk = document.getElementById('kr_produk').value.trim();
  const qty = Number(document.getElementById('kr_qty').value)||0;
  const kendaraan = document.getElementById('kr_kendaraan').value;
  const sopir = document.getElementById('kr_sopir').value.trim();
  const status = document.getElementById('kr_status').value;
  const alamat = document.getElementById('kr_alamat').value.trim();
  const keterangan = document.getElementById('kr_ket').value.trim();

  if(!tanggal || !pelanggan || !produk || qty<=0){
    alert('Tanggal, Pelanggan, Produk, dan Qty wajib diisi dengan benar.');
    return;
  }

  // Validate qty for staged-delivery sales: a "Terkirim" shipment shouldn't push the
  // total delivered beyond the sale's qty.
  if(penjualanId && status==='Terkirim'){
    const p = DB.penjualan.find(x=>x.id===penjualanId);
    if(p && p.kirimBertahap){
      const existingQty = (!isNew && DB.pengiriman.find(r=>r.id===id)?.status==='Terkirim')
        ? Number(DB.pengiriman.find(r=>r.id===id).qty||0) : 0;
      const sisa = getSisaKirimPenjualan(p) + existingQty;
      if(qty > sisa + 0.01){
        alert(`Qty pengiriman (${fmtNum(qty)} kg) melebihi sisa yang belum terkirim untuk transaksi ${p.invoice} (sisa ${fmtNum(sisa)} kg).`);
        return;
      }
    }
  }

  if(isNew){
    DB.pengiriman.push({id, tanggal, noResi: nextCode('resi','RESI',4), penjualanId, pelanggan, produk, qty, kendaraan, sopir, alamat, status, keterangan});
  } else {
    const row = DB.pengiriman.find(r=>r.id===id);
    Object.assign(row, {tanggal, penjualanId, pelanggan, produk, qty, kendaraan, sopir, alamat, status, keterangan});
  }
  saveDB();
  closeModal();
  renderDistribusi();
  showToast('Data pengiriman tersimpan.');
}
function deletePengiriman(id){
  if(!confirm('Hapus catatan pengiriman ini?')) return;
  DB.pengiriman = DB.pengiriman.filter(r=>r.id!==id);
  saveDB();
  renderDistribusi();
  showToast('Catatan dihapus.');
}

