  if(!row.tipeBahan) row.tipeBahan = 'Gabah';

  const jenisOpts    = DB.jenisGabah.map(j=>`<option value="${esc(j)}" ${row.jenisGabah===j?'selected':''}>${esc(j)}</option>`).join('');
