  const jualSamping = DB.penjualan.filter(r=>r.kategori==='Produk Samping');
  const jualGabah   = DB.penjualan.filter(r=>r.kategori==='Gabah');

  const totalQty   = DB.penjualan.reduce((s,r)=>s+Number(r.qty||0),0);
  const totalNilai = DB.penjualan.reduce((s,r)=>s+Number(r.total||0),0);
  const totalPiutang = getTotalPiutang();

  const qtyBeras    = jualBeras.reduce((s,r)=>s+Number(r.qty||0),0);
  const nilaiBeras  = jualBeras.reduce((s,r)=>s+Number(r.total||0),0);
  const qtySamping  = jualSamping.reduce((s,r)=>s+Number(r.qty||0),0);
  const nilaiSamping= jualSamping.reduce((s,r)=>s+Number(r.total||0),0);
  const qtyGabahJ   = jualGabah.reduce((s,r)=>s+Number(r.qty||0),0);
