/* ============================================================
   LAPORAN LENGKAP (Recap Hub)
   Monthly/yearly recap across all transaction types, plus quick
   links to detailed reports.
   ============================================================ */
// Produk samping = ada di jenisSamping master ATAU kategori 'Produk Samping' ATAU 'Gabah'
const PRODUK_UTAMA = ['Premium','Medium'];
function isProdukSamping(produk, kategori){
  if(kategori === 'Produk Samping') return true;
  if(kategori === 'Gabah') return true;
  const jenisSamping = DB.jenisSamping||[];
  if(jenisSamping.includes(produk)) return true;
  return false; // jenisBeras items are all utama by default
}

function getMonthlyRecap(){
  const map = {};
  function ensure(m){
    if(!map[m]) map[m] = {
      pembelianQty:0, pembelianNilai:0,
      produksiGabah:0, produksiPK:0, produksiSekam:0,
      produksiBeras:0, produksiSamping:0, produksiTotal:0,
      penjualanQty:0, penjualanNilai:0,
      penjualanUtamaQty:0, penjualanUtamaNilai:0,
      penjualanSampingQty:0, penjualanSampingNilai:0,
      penjualanDetail:{}, // {produk: {qty, nilai}}
      beban:0
    };
    return map[m];
  }
  DB.pembelian.forEach(r=>{
    const m = r.tanggal.slice(0,7);
    const e = ensure(m);
    e.pembelianQty += Number(r.qty||0);
    e.pembelianNilai += Number(r.total||0);
  });
  DB.produksi.forEach(r=>{
    const m = (r.selesai||r.mulai).slice(0,7);
    const e = ensure(m);
    e.produksiGabah  += Number(r.gabah||0);
    e.produksiPK     += Number(r.pk||0);
    e.produksiSekam  += Number(r.sekam||0);
    e.produksiBeras  += Number(r.premium||0)+Number(r.medium||0);
    e.produksiSamping += Number(r.menir||0)+Number(r.bekatul||0);
    e.produksiTotal  += Number(r.premium||0)+Number(r.medium||0)+Number(r.menir||0)+Number(r.bekatul||0);
  });
  DB.penjualan.forEach(r=>{
    const m = r.tanggal.slice(0,7);
    const e = ensure(m);
    const qty = Number(r.qty||0);
    const nilai = Number(r.total||0);
    const produk = r.produk || (r.kategori==='Gabah'?'Gabah':'-');
    e.penjualanQty += qty;
    e.penjualanNilai += nilai;
    if(isProdukSamping(produk, r.kategori)){
      e.penjualanSampingQty += qty;
      e.penjualanSampingNilai += nilai;
    } else {
      e.penjualanUtamaQty += qty;
      e.penjualanUtamaNilai += nilai;
    }
    if(!e.penjualanDetail[produk]) e.penjualanDetail[produk] = {qty:0, nilai:0};
    e.penjualanDetail[produk].qty += qty;
    e.penjualanDetail[produk].nilai += nilai;
  });
  const bebanKategori = ['Beban Listrik','Beban Gaji Karyawan','Beban Bahan Pendukung','Beban Solar/BBM','Beban Perawatan Mesin','Beban Transportasi','Beban Lain-lain'];
  DB.kasbank.forEach(r=>{
    if(bebanKategori.includes(r.kategori)){
      const m = r.tanggal.slice(0,7);
      const e = ensure(m);
      e.beban += Number(r.keluar||0);
    }
  });
  return Object.entries(map).sort((a,b)=>a[0].localeCompare(b[0])).map(([m,v])=>({
    bulan:m, ...v, laba: v.penjualanNilai - v.pembelianNilai - v.beban
  }));
}
function getYearlyRecap(){
  const monthly = getMonthlyRecap();
  const map = {};
  monthly.forEach(m=>{
    const y = m.bulan.slice(0,4);
    if(!map[y]) map[y] = {
      pembelianQty:0, pembelianNilai:0,
      produksiGabah:0, produksiPK:0, produksiSekam:0,
      produksiBeras:0, produksiSamping:0, produksiTotal:0,
      penjualanQty:0, penjualanNilai:0,
      penjualanUtamaQty:0, penjualanUtamaNilai:0,
      penjualanSampingQty:0, penjualanSampingNilai:0,
      penjualanDetail:{},
      beban:0, laba:0
    };
    map[y].pembelianQty += m.pembelianQty;
    map[y].pembelianNilai += m.pembelianNilai;
    map[y].produksiGabah += m.produksiGabah;
    map[y].produksiBeras += m.produksiBeras;
    map[y].penjualanQty += m.penjualanQty;
    map[y].penjualanNilai += m.penjualanNilai;
    map[y].penjualanUtamaQty += m.penjualanUtamaQty;
    map[y].penjualanUtamaNilai += m.penjualanUtamaNilai;
    map[y].penjualanSampingQty += m.penjualanSampingQty;
    map[y].penjualanSampingNilai += m.penjualanSampingNilai;
    // Merge penjualanDetail
    Object.entries(m.penjualanDetail||{}).forEach(([p,v])=>{
      if(!map[y].penjualanDetail[p]) map[y].penjualanDetail[p] = {qty:0,nilai:0};
      map[y].penjualanDetail[p].qty += v.qty;
      map[y].penjualanDetail[p].nilai += v.nilai;
    });
    map[y].beban += m.beban;
    map[y].laba += m.laba;
  });
  return Object.entries(map).sort((a,b)=>a[0].localeCompare(b[0])).map(([y,v])=>({tahun:y, ...v}));
}
function fmtBulan(ym){
  const [y,m] = ym.split('-');
  const names = ['Jan','Feb','Mar','Apr','Mei','Jun','Jul','Agu','Sep','Okt','Nov','Des'];
  return `${names[parseInt(m,10)-1]} ${y}`;
}

// ISO week info for a 'YYYY-MM-DD' date string: returns {key, year, week, weekStart, weekEnd}
// Week starts on Monday (ISO 8601). 'key' is sortable as 'YYYY-Www'.
function getISOWeekInfo(dateStr){
  const d = new Date(dateStr + 'T00:00:00');
  // ISO weekday: Mon=1..Sun=7
  const isoDay = (d.getDay() + 6) % 7 + 1;
  // Move to the Monday of this week
  const monday = new Date(d);
  monday.setDate(d.getDate() - (isoDay - 1));
  const sunday = new Date(monday);
  sunday.setDate(monday.getDate() + 6);
  // ISO week number: based on the Thursday of the week
  const thursday = new Date(monday);
  thursday.setDate(monday.getDate() + 3);
  const isoYear = thursday.getFullYear();
  const jan1 = new Date(isoYear, 0, 1);
  const week = Math.floor((thursday - jan1) / (7*24*60*60*1000)) + 1;
  const pad = (n)=>String(n).padStart(2,'0');
  const fmt = (dt)=>`${dt.getFullYear()}-${pad(dt.getMonth()+1)}-${pad(dt.getDate())}`;
  return {
    key: `${isoYear}-W${String(week).padStart(2,'0')}`,
    year: isoYear, week,
    weekStart: fmt(monday), weekEnd: fmt(sunday)
  };
}
function getWeeklyRecap(){
  const map = {};
  function ensure(dateStr){
    const info = getISOWeekInfo(dateStr);
    if(!map[info.key]) map[info.key] = {
      key:info.key, year:info.year, week:info.week, weekStart:info.weekStart, weekEnd:info.weekEnd,
      pembelianQty:0, pembelianNilai:0, produksiGabah:0, produksiBeras:0,
      penjualanQty:0, penjualanNilai:0,
      penjualanUtamaQty:0, penjualanUtamaNilai:0,
      penjualanSampingQty:0, penjualanSampingNilai:0,
      penjualanDetail:{},
      beban:0
    };
    return map[info.key];
  }
  DB.pembelian.forEach(r=>{
    const e = ensure(r.tanggal);
    e.pembelianQty += Number(r.qty||0);
    e.pembelianNilai += Number(r.total||0);
  });
  DB.produksi.forEach(r=>{
    const e = ensure(r.selesai||r.mulai);
    e.produksiGabah  += Number(r.gabah||0);
    e.produksiPK     += Number(r.pk||0);
    e.produksiSekam  += Number(r.sekam||0);
    e.produksiBeras  += Number(r.premium||0)+Number(r.medium||0);
    e.produksiSamping += Number(r.menir||0)+Number(r.bekatul||0);
    e.produksiTotal  += Number(r.premium||0)+Number(r.medium||0)+Number(r.menir||0)+Number(r.bekatul||0);
  });
  DB.penjualan.forEach(r=>{
    const e = ensure(r.tanggal);
    const qty = Number(r.qty||0);
    const nilai = Number(r.total||0);
    const produk = r.produk || (r.kategori==='Gabah'?'Gabah':'-');
    e.penjualanQty += qty;
    e.penjualanNilai += nilai;
    if(isProdukSamping(produk, r.kategori)){
      e.penjualanSampingQty += qty;
      e.penjualanSampingNilai += nilai;
    } else {
      e.penjualanUtamaQty += qty;
      e.penjualanUtamaNilai += nilai;
    }
    if(!e.penjualanDetail[produk]) e.penjualanDetail[produk] = {qty:0, nilai:0};
    e.penjualanDetail[produk].qty += qty;
    e.penjualanDetail[produk].nilai += nilai;
  });
  const bebanKategori = ['Beban Listrik','Beban Gaji Karyawan','Beban Bahan Pendukung','Beban Solar/BBM','Beban Perawatan Mesin','Beban Transportasi','Beban Lain-lain'];
  DB.kasbank.forEach(r=>{
    if(bebanKategori.includes(r.kategori)){
      const e = ensure(r.tanggal);
      e.beban += Number(r.keluar||0);
    }
  });
  return Object.values(map).sort((a,b)=>a.key.localeCompare(b.key)).map(v=>({
    ...v, laba: v.penjualanNilai - v.pembelianNilai - v.beban
  }));
}
function fmtMingguan(w){
  return `Minggu ${w.week} (${fmtDate(w.weekStart)} - ${fmtDate(w.weekEnd)})`;
}

