function renderChartRendemen(){
  destroyChart('rendemen');
  const rows = DB.produksi.filter(r=>Number(r.gabah||0)>0).slice().sort((a,b)=>a.mulai.localeCompare(b.mulai));
  const labels = rows.length ? rows.map(r=>r.batch) : ['-'];
  // Rendemen T1: PK / Gabah
  const dataT1 = rows.map(r=> (r.gabah>0 && Number(r.pk||0)>0) ? (Number(r.pk)/r.gabah*100) : null);
  // Rendemen Beras (Total): (Premium+Medium) / Gabah
  const dataT2 = rows.map(r=> r.gabah>0 ? ((Number(r.premium||0)+Number(r.medium||0))/r.gabah*100) : 0);
  const hasPKData = dataT1.some(v=>v!==null);
  const ctx = document.getElementById('chartRendemen');
  // Guard pengaman: fungsi ini sebelumnya dipanggil tanpa cek elemen, menyebabkan
  // new Chart(null, ...) melempar exception dan mematahkan chain render chart
  // lain di renderDashboard(). Saat ini fungsi tidak dipanggil di manapun
  // (canvas 'chartRendemen' tidak ada di HTML manapun — yang ada 'chartRendemenBulan'),
  // tapi guard ini dipertahankan agar aman dipanggil ulang di masa depan.
  if(!ctx) return;
  const datasets = [];
  if(hasPKData){
    datasets.push({
      label:'% Rendemen PK (T1)',
      data: dataT1.map(v=>v===null?0:v),
      backgroundColor:'rgba(124,58,237,0.55)',
      borderColor:'#7C3AED', borderWidth:1,
    });
  }
  datasets.push({
    label:'% Rendemen Beras (Total)',
    data: dataT2,
    backgroundColor:'#F59E0B',
    borderColor:'#D97706', borderWidth:1,
  });
  charts.rendemen = new Chart(ctx, {
    type:'bar',
    data:{ labels, datasets },
    options:{
      responsive:true,
      plugins:{ legend:{ display: hasPKData, position:'bottom', labels:{font:{family:'Inter'}} } },
      scales:{ y:{ suggestedMax:100, ticks:{ callback:(v)=>v+'%' } } }
    }
  });
}

