/* ============================================================
   SPRINT 6 — BUSINESS INTELLIGENCE MODULE
   10 panel: Forecast Gabah · Karung · Benang · Cashflow
             Profit Batch · Profit Supplier · Profit Pelanggan
             Analisa Rendemen · Supplier Ranking · Customer Ranking
   ============================================================ */

// ── BI SERVICE LAYER ─────────────────────────────────────────

/**
 * Forecast bahan pendukung (Karung / Benang / dll).
 * Pemakaian rata-rata 3 bulan → proyeksi kebutuhan.
 */
function getForecastBahan(namaBahan){
  const bulanIni = todayStr().slice(0,7);
  const recap    = getMonthlyRecap();

  // Hitung pemakaian per bulan dari DB.pemakaianBahan
  const mapPakai = {};
  DB.pemakaianBahan.filter(r=>r.item===namaBahan).forEach(r=>{
    const m = r.tanggal.slice(0,7);
    mapPakai[m] = (mapPakai[m]||0) + Number(r.qty||0);
  });

  const tiga = Object.entries(mapPakai)
    .filter(([m])=>m<bulanIni)
    .sort((a,b)=>a[0].localeCompare(b[0]))
    .slice(-3);

  const stokSaat = getStokBahanPendukung()[namaBahan]||0;
  const master   = DB.bahanPendukung.find(b=>b.nama===namaBahan);
  const satuan   = master?.satuan||'pcs';
  const minimum  = Number(master?.stokMinimum||0);

  if(tiga.length===0){
    // Fallback: ambil dari bulan berjalan
    const pakaiBulanIni = mapPakai[bulanIni]||0;
    const hari = new Date().getDate();
    const rataHarian = hari>0 ? pakaiBulanIni/hari : 0;
    return {
      namaBahan, satuan, stokSaat, minimum,
      rataPerBulan   : Math.round(rataHarian*30),
      rataHarian     : +rataHarian.toFixed(2),
      forecast30Hari : Math.round(rataHarian*30),
      forecast7Hari  : Math.round(rataHarian*7),
      stokCukupHari  : rataHarian>0 ? Math.floor(stokSaat/rataHarian) : 999,
      perluBeli      : Math.max(0, Math.round(rataHarian*30) - stokSaat),
      bulanData      : 0,
      historikal     : [],
      metode         : 'harian',
      status         : stokSaat<=minimum?'⚠ Rendah':stokSaat<minimum*2?'⚡ Waspada':'✓ Aman',
    };
  }

  const totPakai   = tiga.reduce((s,[,v])=>s+v, 0);
  const rataPerBulan = totPakai / tiga.length;
  const rataHarian = rataPerBulan / 26;
  const stokCukupHari = rataHarian>0 ? Math.floor(stokSaat/rataHarian) : 999;

  // Histori per bulan untuk chart (6 bulan)
  const historikal = Object.entries(mapPakai)
    .sort((a,b)=>a[0].localeCompare(b[0])).slice(-6)
    .map(([bulan,qty])=>({bulan,qty}));

  return {
    namaBahan, satuan, stokSaat, minimum,
    rataPerBulan   : Math.round(rataPerBulan),
    rataHarian     : +rataHarian.toFixed(2),
    forecast30Hari : Math.round(rataPerBulan),
    forecast7Hari  : Math.round(rataHarian*7),
    stokCukupHari,
    perluBeli      : Math.max(0, Math.round(rataPerBulan) - stokSaat),
    bulanData      : tiga.length,
    historikal,
    metode         : '3bln',
    status         : stokSaat<=minimum?'⚠ Rendah':stokSaat<minimum*2?'⚡ Waspada':'✓ Aman',
  };
}

/**
 * Forecast Cashflow — proyeksi arus kas bulan depan.
 * Masuk: rata-rata penerimaan 3 bulan
 * Keluar: rata-rata pengeluaran 3 bulan (pembelian + beban)
 */
function getForecastCashflow(){
  const bulanIni = todayStr().slice(0,7);
  const recap    = getMonthlyRecap();
  const tiga     = recap.filter(r=>r.bulan<bulanIni).slice(-3);
  const bulanDepan = (()=>{
    const d = new Date(); d.setMonth(d.getMonth()+1);
    return d.toISOString().slice(0,7);
  })();

  // Histori saldo kas per bulan (running balance)
  const kasHistori = recap.map(r=>({
    bulan    : r.bulan,
    masuk    : r.penjualanNilai,
    keluar   : r.pembelianNilai + r.beban,
    net      : r.penjualanNilai - r.pembelianNilai - r.beban,
  }));

  let forecastMasuk=0, forecastKeluar=0;
  if(tiga.length>0){
    forecastMasuk  = tiga.reduce((s,r)=>s+r.penjualanNilai,0) / tiga.length;
    forecastKeluar = tiga.reduce((s,r)=>s+r.pembelianNilai+r.beban,0) / tiga.length;
  } else {
    const berjalan = recap.find(r=>r.bulan===bulanIni);
    if(berjalan){
      const hari = new Date().getDate();
      forecastMasuk  = hari>0 ? berjalan.penjualanNilai/hari*30 : 0;
      forecastKeluar = hari>0 ? (berjalan.pembelianNilai+berjalan.beban)/hari*30 : 0;
    }
  }

  const saldoKasSaat = getSaldoKasAkhir();
  const forecastNet  = forecastMasuk - forecastKeluar;
  const saldoForecast = saldoKasSaat + forecastNet;

  return {
    bulanDepan,
    forecastMasuk  : Math.round(forecastMasuk),
    forecastKeluar : Math.round(forecastKeluar),
    forecastNet    : Math.round(forecastNet),
    saldoKasSaat,
    saldoForecast  : Math.round(saldoForecast),
    kasHistori,
    bulanData      : tiga.length,
    metode         : tiga.length>0 ? '3bln' : 'harian',
  };
}

/**
 * Profit per Supplier — dari semua batch yang pakai gabah supplier itu.
 * Profit = pendapatan beras dari batch - HPP gabah dari supplier tsb.
 */
function getProfitPerSupplier(){
  const hargaAvg = {}, hargaCount = {};
  DB.penjualan.forEach(r=>{
    if(!r.produk||!r.harga) return;
    hargaAvg[r.produk]   = (hargaAvg[r.produk]||0)  + Number(r.harga);
    hargaCount[r.produk] = (hargaCount[r.produk]||0) + 1;
  });
  Object.keys(hargaAvg).forEach(k=>{ hargaAvg[k]/=hargaCount[k]; });
  const H = { Premium:12500, Medium:10500, Menir:4500, Bekatul:3500, Sekam:500 };
  const harga = p => hargaAvg[p]||H[p]||0;

  const map = {};
  DB.produksi.forEach(r=>{
    const hpp = getHppBatch(r);
    (r.sumberGabah||[]).forEach(s=>{
      const p = DB.pembelian.find(x=>x.id===s.pembelianId);
      if(!p) return;
      const sup     = p.supplier;
      if(!map[sup]) map[sup]={supplier:sup, nilaiGabah:0, tonase:0, pendapatan:0, batches:new Set()};
      const proporsi = hpp.totalQtySumber>0 ? Number(s.qty)/hpp.totalQtySumber : 1;
      const nilaiSumber = Number(s.qty)*Number(s.harga||0);
      const pendapatanPorsi =
        (Number(r.premium||0)*harga('Premium') +
         Number(r.medium||0) *harga('Medium')  +
         Number(r.menir||0)  *harga('Menir')   +
         Number(r.bekatul||0)*harga('Bekatul')  +
         Number(r.sekam||0)  *harga('Sekam'))   * proporsi;
      map[sup].nilaiGabah   += nilaiSumber;
      map[sup].tonase       += Number(s.qty);
      map[sup].pendapatan   += pendapatanPorsi;
      map[sup].batches.add(r.id);
    });
  });

  return Object.values(map).map(m=>({
    supplier   : m.supplier,
    tonase     : m.tonase,
    nilaiGabah : m.nilaiGabah,
    pendapatan : m.pendapatan,
    profit     : m.pendapatan - m.nilaiGabah,
    margin     : m.pendapatan>0 ? (m.pendapatan-m.nilaiGabah)/m.pendapatan*100 : 0,
    batches    : m.batches.size,
    hpp        : m.tonase>0 ? m.nilaiGabah/m.tonase : 0,
  })).sort((a,b)=>b.profit-a.profit);
}

/**
 * Profit per Pelanggan — dari riwayat penjualan aktual.
 */
function getProfitPerPelanggan(){
  const map = {};
  DB.penjualan.forEach(r=>{
    const p = r.pelanggan;
    if(!map[p]) map[p]={pelanggan:p, omzet:0, qty:0, transaksi:0, produkMap:{}};
    map[p].omzet     += Number(r.total||0);
    map[p].qty       += Number(r.qty||0);
    map[p].transaksi += 1;
    const k = r.produk||'-';
    if(!map[p].produkMap[k]) map[p].produkMap[k]={qty:0,nilai:0};
    map[p].produkMap[k].qty   += Number(r.qty||0);
    map[p].produkMap[k].nilai += Number(r.total||0);
  });

  // Estimasi HPP dari rata-rata sistem
  const totalBeras = DB.penjualan.filter(r=>r.kategori==='Beras'||!r.kategori)
                                  .reduce((s,r)=>s+Number(r.qty||0),0);
  const hppPerKg   = totalBeras>0 ? getTotalHPP()/totalBeras : 0;

  return Object.values(map).map(m=>({
    pelanggan  : m.pelanggan,
    omzet      : m.omzet,
    qty        : m.qty,
    transaksi  : m.transaksi,
    cogs       : hppPerKg * m.qty,
    profit     : m.omzet - hppPerKg*m.qty,
    margin     : m.omzet>0?(m.omzet-hppPerKg*m.qty)/m.omzet*100:0,
    produkMap  : m.produkMap,
  })).sort((a,b)=>b.omzet-a.omzet);
}

/**
 * Analisa Rendemen lengkap — per batch + trend bulanan.
 * Returns {batches[], trend[], avg, best, worst}
 */
function getAnalisaRendemen(){
  const batches = DB.produksi.map(r=>{
    const gabah    = Number(r.gabah||0);
    const pk       = Number(r.pk||0);
    const beras    = Number(r.premium||0)+Number(r.medium||0);
    const menir    = Number(r.menir||0);
    const bekatul  = Number(r.bekatul||0);
    const sekam    = Number(r.sekam||0);
    const outT1    = pk+sekam;
    const outT2    = beras+menir+bekatul;
    return {
      batch    : r.batch,
      tgl      : r.selesai||r.mulai,
      jenisGabah: r.jenisGabah,
      gabah,
      pk, sekam, beras, menir, bekatul,
      rendemenT1  : gabah>0&&outT1>0 ? pk/gabah*100 : null,
      rendemenT2  : pk>0&&outT2>0 ? beras/pk*100 : null,
      rendemenTotal: gabah>0 ? beras/gabah*100 : 0,
      susutT1  : gabah>0&&outT1>0 ? (gabah-outT1)/gabah*100 : null,
      susutT2  : pk>0&&outT2>0 ? (pk-outT2)/pk*100 : null,
    };
  }).sort((a,b)=>b.tgl.localeCompare(a.tgl));

  const valid = batches.filter(b=>b.rendemenTotal>0);
  const avg   = valid.length ? valid.reduce((s,b)=>s+b.rendemenTotal,0)/valid.length : 0;
  const best  = valid.reduce((m,b)=>b.rendemenTotal>m.rendemenTotal?b:m, valid[0]||{});
  const worst = valid.reduce((m,b)=>b.rendemenTotal<m.rendemenTotal?b:m, valid[0]||{});

  // Trend bulanan
  const mapBulan = {};
  batches.forEach(b=>{
    const m = b.tgl.slice(0,7);
    if(!mapBulan[m]) mapBulan[m]={bulan:m,gabah:0,beras:0,cnt:0};
    mapBulan[m].gabah += b.gabah;
    mapBulan[m].beras += b.beras;
    mapBulan[m].cnt   += 1;
  });
  const trend = Object.values(mapBulan)
    .sort((a,b)=>a.bulan.localeCompare(b.bulan))
    .map(r=>({...r, rendemen: r.gabah>0?r.beras/r.gabah*100:0}));

  return { batches, trend, avg, best, worst };
}

/**
 * Supplier Ranking — multi-dimensi: tonase, harga, rendemen, profit.
 */
function getSupplierRanking(){
  const profitMap = {};
  getProfitPerSupplier().forEach(p=>{ profitMap[p.supplier]=p; });

  return DB.suppliers.map(s=>{
    const pembelian = DB.pembelian.filter(r=>r.supplier===s.nama);
    if(!pembelian.length) return null;
    const tonase   = pembelian.reduce((x,r)=>x+Number(r.qty||0),0);
    const nilaiTotal= pembelian.reduce((x,r)=>x+Number(r.total||0),0);
    const hargaAvg = tonase>0 ? nilaiTotal/tonase : 0;
    const profit   = profitMap[s.nama];
    const jumlahTx = pembelian.length;
    // Skor komposit (0-100): tonase 35pt + harga murah 30pt + profit margin 35pt
    const maxTonase = Math.max(...DB.suppliers.map(x=>
      DB.pembelian.filter(r=>r.supplier===x.nama).reduce((a,r)=>a+Number(r.qty||0),0)));
    const skor_tonase  = maxTonase>0 ? (tonase/maxTonase)*35 : 0;
    const hargaMin = Math.min(...DB.pembelian.map(r=>Number(r.harga||0)).filter(x=>x>0));
    const hargaMax = Math.max(...DB.pembelian.map(r=>Number(r.harga||0)));
    const skor_harga   = hargaMax>hargaMin ? ((hargaMax-hargaAvg)/(hargaMax-hargaMin))*30 : 15;
    const skor_profit  = profit ? Math.min(35, Math.max(0, profit.margin/100*35*2)) : 0;
    const skor_total   = Math.round(skor_tonase + skor_harga + skor_profit);
    const grade = skor_total>=80?'A':skor_total>=60?'B':skor_total>=40?'C':'D';
    return {
      nama:s.nama, kode:s.kode, tonase, nilaiTotal, hargaAvg, jumlahTx,
      profit: profit?.profit||0, margin: profit?.margin||0,
      skor:skor_total, grade,
    };
  }).filter(Boolean).sort((a,b)=>b.skor-a.skor);
}

/**
 * Customer Ranking — RFM-inspired: Recency, Frequency, Monetary.
 */
function getCustomerRanking(){
  const today = todayStr();
  return DB.pelanggan.map(p=>{
    const transaksi = DB.penjualan.filter(r=>r.pelanggan===p.nama)
      .sort((a,b)=>b.tanggal.localeCompare(a.tanggal));
    if(!transaksi.length) return null;
    const omzet     = transaksi.reduce((s,r)=>s+Number(r.total||0),0);
    const qty       = transaksi.reduce((s,r)=>s+Number(r.qty||0),0);
    const hargaAvg  = qty>0 ? omzet/qty : 0;
    const lastTgl   = transaksi[0].tanggal;
    const recency   = Math.floor((new Date(today)-new Date(lastTgl))/(1000*86400));
    const freq      = transaksi.length;
    const totalBeras= DB.penjualan.filter(r=>r.kategori==='Beras'||!r.kategori)
                                   .reduce((s,r)=>s+Number(r.qty||0),0);
    const hppPerKg  = totalBeras>0 ? getTotalHPP()/totalBeras : 0;
    const cogs      = hppPerKg*qty;
    const profit    = omzet-cogs;
    const margin    = omzet>0?profit/omzet*100:0;
    const piutang   = Math.max(0,
      transaksi.reduce((s,r)=>s+Number(r.piutang||0),0) -
      // QA Final: field referensi yang benar adalah 'refId' (lihat saveKasManual),
      // bukan 'sourceId' — sebelumnya selalu menghitung piutang lebih besar dari aktual.
      DB.kasbank.filter(k=>k.kategori==='Penerimaan Pelunasan Piutang'&&
                           transaksi.some(t=>t.id===k.refId))
               .reduce((s,k)=>s+Number(k.masuk||0),0));
    // RFM score (1-5 per dimensi → total 3-15)
    const maxOmzet = Math.max(...DB.pelanggan.map(x=>
      DB.penjualan.filter(r=>r.pelanggan===x.nama).reduce((s,r)=>s+Number(r.total||0),0)));
    const r_score = recency<=7?5:recency<=30?4:recency<=90?3:recency<=180?2:1;
    const f_score = freq>=10?5:freq>=5?4:freq>=3?3:freq>=2?2:1;
    const m_score = maxOmzet>0 ? Math.ceil(omzet/maxOmzet*5) : 1;
    const rfm     = r_score+f_score+m_score;
    const segment = rfm>=13?'🏆 Champion':rfm>=10?'⭐ Loyal':rfm>=7?'🔄 Regular':rfm>=5?'👋 At Risk':'💤 Dormant';
    return {
      nama:p.nama, kode:p.kode, omzet, qty, hargaAvg, freq,
      recency, lastTgl, profit, margin, piutang,
      rfm, segment, r_score, f_score, m_score,
    };
  }).filter(Boolean).sort((a,b)=>b.omzet-a.omzet);
}

