/** Dipanggil dari renderDashboard untuk tampilkan peringatan mesin */
function renderMaintenanceAlertBanner(){
  const alarm = getMesinAlarmSummary();
  if(!alarm.length) return '';
  return `<div style="background:var(--red);color:#fff;border-radius:10px;padding:10px 14px;margin-bottom:14px;cursor:pointer;display:flex;align-items:center;gap:10px;" onclick="navigateTo('maintenance')">
    <span style="font-size:1.2rem;">⚠</span>
    <div>
      <div style="font-weight:700;font-size:0.88rem;">${alarm.length} mesin perlu service — klik untuk buka Maintenance</div>
      <div style="font-size:0.76rem;margin-top:1px;opacity:0.9;">${alarm.map(x=>`${x.mesin.nama} (${x.pct.toFixed(0)}%)`).join(' · ')}</div>
    </div>
  </div>`;
}

/* ============================================================
   SPRINT 8 — MODUL GUDANG LANJUTAN
   Mutasi Stok (existing, lihat renderGudang) + tambahan:
   Stock Opname · Lot Number · Batch Tracking · FIFO ·
   Stok Minimum · Alarm Stok · Kartu Stok
   Semua data realtime dari transaksi yang ada.
   ============================================================ */

// ── LOT / BATCH TRACKING ──────────────────────────────────────

/**
 * Auto-generate lot dari setiap event stok-masuk yang sudah ada
 * (pembelian gabah, hasil produksi T1/T2, maklon B/C, mutasi manual masuk).
 * Lot bersifat read-derived dari histori — TIDAK disimpan ganda kecuali
 * untuk pelacakan qtySisa FIFO, yang disimpan di DB.lotStok.
 *
 * Strategi: Setiap kali stok-masuk baru terdeteksi yang belum ada lotnya
 * (dicocokkan via sumber+sourceId+item), buat lot baru otomatis.
 */
function syncLotStokOtomatis(){
  if(!DB.lotStok) DB.lotStok = [];
  const existingKeys = new Set(DB.lotStok.map(l=>`${l.sumber}|${l.sourceId}|${l.item}`));

  function addLot(sumber, sourceId, item, kategori, tanggal, qty, hppPerKg, batchRef){
    const key = `${sumber}|${sourceId}|${item}`;
    if(existingKeys.has(key) || qty<=0) return;
    DB.seq.lot = (DB.seq.lot||0)+1;
    DB.lotStok.push({
      id: uid(), lotNo: 'LOT-'+String(DB.seq.lot).padStart(5,'0'),
      item, kategori, tanggalMasuk: tanggal,
      qtyAwal: qty, qtySisa: qty,
      sumber, sourceId, hpp: hppPerKg||0, batchRef: batchRef||'',
    });
    existingKeys.add(key);
  }

  // 1. Pembelian gabah → lot gabah
  DB.pembelian.forEach(r=>{
    if(r.kategori==='Beras'||r.kategori==='Produk Samping') return;
    const hppKg = getHargaEfektifPembelian(r);
    addLot('pembelian', r.id, r.jenisGabah, 'Gabah', r.tanggal, Number(r.qty||0), hppKg, r.noFaktur);
  });

  // 2. Produksi Tahap 1 → lot PK & Sekam
  DB.produksi.forEach(r=>{
    const tgl = r.selesai||r.mulai;
    const hpp = getHppBatch(r);
    if(Number(r.pk||0)>0)    addLot('produksi-t1', r.id+'-pk',    'PK',    'Produk Samping', tgl, Number(r.pk),    hpp.hppPerKgPK, r.batch);
    if(Number(r.sekam||0)>0) addLot('produksi-t1', r.id+'-sekam', 'Sekam', 'Produk Samping', tgl, Number(r.sekam), 0, r.batch);
    // Produksi Tahap 2 → lot Beras/Menir/Bekatul
    if(Number(r.premium||0)>0) addLot('produksi-t2', r.id+'-prem', 'Premium', 'Beras', tgl, Number(r.premium), hpp.hppPerKgBeras, r.batch);
    if(Number(r.medium||0)>0)  addLot('produksi-t2', r.id+'-med',  'Medium',  'Beras', tgl, Number(r.medium),  hpp.hppPerKgBeras, r.batch);
    if(Number(r.menir||0)>0)   addLot('produksi-t2', r.id+'-men',  'Menir',   'Beras', tgl, Number(r.menir),   0, r.batch);
    if(Number(r.bekatul||0)>0) addLot('produksi-t2', r.id+'-bek',  'Bekatul', 'Beras', tgl, Number(r.bekatul), 0, r.batch);
  });

  // 3. Maklon B/C → lot produk milik CV
  (DB.maklon||[]).filter(m=>m.status==='Selesai').forEach(m=>{
    const label = m.noMaklon;
    if(m.tipe==='B'){
      if(Number(m.bekatul||0)>0) addLot('maklon', m.id+'-bek', 'Bekatul', 'Beras', m.tglSelesai||m.tgl, Number(m.bekatul), 0, label);
      if(Number(m.menir||0)>0)   addLot('maklon', m.id+'-men', 'Menir',   'Beras', m.tglSelesai||m.tgl, Number(m.menir),   0, label);
      if(Number(m.sekam||0)>0)   addLot('maklon', m.id+'-sek', 'Sekam',   'Produk Samping', m.tglSelesai||m.tgl, Number(m.sekam), 0, label);
    } else if(m.tipe==='C'){
      const pct = Number(m.berbagiHasilPct||0);
      const berasCV = (Number(m.premium||0)+Number(m.medium||0))*pct/100;
      if(berasCV>0) addLot('maklon', m.id+'-bagihasil', 'Medium', 'Beras', m.tglSelesai||m.tgl, berasCV, 0, label);
    }
  });

  // 4. Mutasi manual masuk → lot manual
  DB.mutasi.filter(m=>m.jenis==='Masuk').forEach(m=>{
    addLot('manual', m.id, m.item, m.kategori, m.tanggal, Number(m.qty||0), 0, 'Manual');
  });

  // ── SINKRONISASI KELUAR (FIFO) ──────────────────────────────
  // Reset qtySisa ke qtyAwal, lalu kurangi FIFO berdasar event-keluar kronologis
  DB.lotStok.forEach(l=>{ l.qtySisa = l.qtyAwal; });
  const keluarEvents = [];

  DB.produksi.forEach(r=>{
    const tgl = r.selesai||r.mulai;
    if(Number(r.gabah||0)>0 && r.tipeBahan!=='Bahan Baku')
      keluarEvents.push({tgl, item:r.jenisGabah, kategori:'Gabah', qty:Number(r.gabah)});
    const outT2 = Number(r.premium||0)+Number(r.medium||0)+Number(r.menir||0)+Number(r.bekatul||0);
    if(Number(r.pk||0)>0 && outT2>0)
      keluarEvents.push({tgl, item:'PK', kategori:'Produk Samping', qty:Math.min(Number(r.pk),outT2)});
  });
  DB.penjualan.forEach(r=>{
    const kategoriBarang = r.kategori==='Gabah'?'Gabah':(r.kategori==='Produk Samping'?'Produk Samping':'Beras');
    const qty = r.kirimBertahap ? getQtyTerkirim(r.id) : Number(r.qty||0);
    if(qty>0) keluarEvents.push({tgl:r.tanggal, item:r.produk, kategori:kategoriBarang, qty});
  });
  DB.mutasi.filter(m=>m.jenis==='Keluar').forEach(m=>{
    keluarEvents.push({tgl:m.tanggal, item:m.item, kategori:m.kategori, qty:Number(m.qty||0)});
  });

  keluarEvents.sort((a,b)=>a.tgl.localeCompare(b.tgl));
  keluarEvents.forEach(ev=>{
    let sisaKeluar = ev.qty;
    const lots = DB.lotStok
      .filter(l=>l.item===ev.item && l.tanggalMasuk<=ev.tgl && l.qtySisa>0)
      .sort((a,b)=>a.tanggalMasuk.localeCompare(b.tanggalMasuk)); // FIFO: lot terlama dulu
    for(const lot of lots){
      if(sisaKeluar<=0) break;
      const ambil = Math.min(lot.qtySisa, sisaKeluar);
      lot.qtySisa -= ambil;
      sisaKeluar  -= ambil;
    }
  });
}

/** Ambil semua lot aktif (qtySisa>0) untuk satu item, urut FIFO (terlama dulu) */
function getLotAktif(item){
  syncLotStokOtomatis();
  return DB.lotStok
    .filter(l=>l.item===item && l.qtySisa>0.01)
    .sort((a,b)=>a.tanggalMasuk.localeCompare(b.tanggalMasuk));
}

/** Nilai stok (FIFO valuation) untuk satu item: sum(qtySisa × hpp) dari lot aktif */
function getNilaiStokFIFO(item){
  return getLotAktif(item).reduce((s,l)=>s+l.qtySisa*l.hpp, 0);
}

/** Total qty dari lot aktif untuk satu item (harus match getStokProduk/getStokGabah) */
function getQtyLotAktif(item){
  return getLotAktif(item).reduce((s,l)=>s+l.qtySisa, 0);
}

// ── KARTU STOK (per item, kronologis, saldo berjalan) ─────────

/**
 * Bangun kartu stok untuk satu item: semua transaksi masuk/keluar
 * diurutkan kronologis dengan saldo berjalan (qty & nilai FIFO).
 */
function getKartuStok(item){
  const history = getMutasiHistory().filter(h=>h.item===item)
    .sort((a,b)=>a.tanggal.localeCompare(b.tanggal));
  let saldoQty = 0;
  const rows = history.map(h=>{
    saldoQty += h.jenis==='Masuk' ? h.qty : -h.qty;
    return { ...h, saldoQty };
  });
  return rows;
}

// ── STOK MINIMUM & ALARM ──────────────────────────────────────

/** Daftar semua item dengan stok minimum terdefinisi + status alarm */
function getStokAlarmList(){
  const stokBeras = getStokProduk();
  const stokGabah = getStokGabah();
  const stokBahan = getStokBahanPendukung();
  const result = [];

  // Beras & produk samping
  Object.keys(DB.stokMinimumMaster||{}).forEach(item=>{
    let qty = null, kategori = null;
    if(item in stokBeras){ qty = stokBeras[item]; kategori='Beras/Produk Samping'; }
    else if(item in stokGabah){ qty = stokGabah[item]; kategori='Gabah'; }
    if(qty===null) return;
    const min = Number(DB.stokMinimumMaster[item]||0);
    if(min<=0) return;
    const pct = min>0 ? (qty/min*100) : 100;
    result.push({
      item, kategori, qty, minimum:min, pct,
      status: qty<=0 ? 'habis' : qty<min ? 'rendah' : qty<min*1.5 ? 'waspada' : 'aman',
    });
  });

  // Bahan Pendukung (sudah ada stokMinimum sendiri di master)
  (DB.bahanPendukung||[]).forEach(b=>{
    const qty = stokBahan[b.nama]||0;
    const min = Number(b.stokMinimum||0);
    if(min<=0) return;
    const pct = min>0 ? (qty/min*100) : 100;
    result.push({
      item:b.nama, kategori:'Bahan Pendukung', qty, minimum:min, pct, satuan:b.satuan,
      status: qty<=0 ? 'habis' : qty<min ? 'rendah' : qty<min*1.5 ? 'waspada' : 'aman',
    });
  });

  return result.sort((a,b)=>a.pct-b.pct);
}

/** Ringkasan alarm untuk banner dashboard */
function getStokAlarmSummary(){
  const all = getStokAlarmList();
  return {
    habis : all.filter(x=>x.status==='habis'),
    rendah: all.filter(x=>x.status==='rendah'),
    waspada: all.filter(x=>x.status==='waspada'),
    total : all.filter(x=>x.status==='habis'||x.status==='rendah').length,
  };
}

/** Banner alarm stok untuk dashboard (mirip pola Maintenance Sprint 7) */
function renderStokAlarmBanner(){
  const sum = getStokAlarmSummary();
  if(sum.total===0) return '';
  const items = [...sum.habis, ...sum.rendah];
  return `<div style="background:var(--red);color:#fff;border-radius:10px;padding:10px 14px;margin-bottom:14px;cursor:pointer;display:flex;align-items:center;gap:10px;" onclick="navigateTo('gudang')">
    <span style="font-size:1.2rem;">📦⚠</span>
    <div>
      <div style="font-weight:700;font-size:0.88rem;">${sum.total} item stok di bawah minimum — klik untuk buka Gudang</div>
      <div style="font-size:0.76rem;margin-top:1px;opacity:0.9;">${items.slice(0,5).map(x=>`${esc(x.item)} (${fmtNum(x.qty)})`).join(' · ')}${items.length>5?` +${items.length-5} lainnya`:''}</div>
    </div>
  </div>`;
}

// ── STOCK OPNAME ───────────────────────────────────────────────

/** Daftar semua item yang bisa di-opname (gabah + beras + bahan pendukung) */
function getOpnameItemList(){
  const stokBeras = getStokProduk();
  const stokGabah = getStokGabah();
  const stokBahan = getStokBahanPendukung();
  const items = [];
  Object.entries(stokGabah).forEach(([k,v])=>items.push({item:k, kategori:'Gabah', qtySistem:v}));
  Object.entries(stokBeras).forEach(([k,v])=>items.push({item:k, kategori:'Beras/Produk Samping', qtySistem:v}));
  Object.entries(stokBahan).forEach(([k,v])=>items.push({item:k, kategori:'Bahan Pendukung', qtySistem:v}));
  return items;
}

