function aturStokMinimum(){
  const stokBeras = getStokProduk();
  const stokGabah = getStokGabah();
  const itemsGabah = Object.keys(stokGabah);
  const itemsBeras = ['Premium','Medium','Menir','Bekatul','Sekam','PK', ...Object.keys(stokBeras).filter(k=>!['Premium','Medium','Menir','Bekatul','Sekam','PK'].includes(k))];

  const rowsGabah = itemsGabah.map(item=>`
    <div class="form-row">
      <div class="field" style="flex:2;"><label>${esc(item)} <span style="color:var(--ink-soft);font-weight:400;">(Gabah)</span></label></div>
      <div class="field"><input type="number" id="min_${esc(item).replace(/\\s/g,'_')}" value="${Number(DB.stokMinimumMaster[item]||0)}" min="0" data-item="${esc(item)}" class="sm-min-input"></div>
    </div>`).join('');

  const rowsBeras = itemsBeras.map(item=>`
    <div class="form-row">
      <div class="field" style="flex:2;"><label>${esc(item)}</label></div>
      <div class="field"><input type="number" id="min_${esc(item).replace(/\\s/g,'_')}" value="${Number(DB.stokMinimumMaster[item]||0)}" min="0" data-item="${esc(item)}" class="sm-min-input"></div>
    </div>`).join('');

  openModal(`
    <h2>Atur Stok Minimum</h2>
    <p class="help-text" style="margin-top:-4px;">Set ambang batas (Kg) untuk setiap item. Alarm akan aktif jika stok turun di bawah angka ini.</p>
    <div class="section-divider">Gabah</div>
    ${rowsGabah||'<p class="help-text">Belum ada jenis gabah.</p>'}
    <div class="section-divider">Beras &amp; Produk Samping</div>
    ${rowsBeras}
    <div class="form-actions">
      <button class="btn btn-primary" style="width:auto;" onclick="saveStokMinimum()">💾 Simpan Semua</button>
      <button class="btn btn-secondary" onclick="closeModal()">Batal</button>
    </div>
  `);
}

function saveStokMinimum(){
  document.querySelectorAll('.sm-min-input').forEach(inp=>{
    const item = inp.dataset.item;
    const val  = Number(inp.value)||0;
    if(!DB.stokMinimumMaster) DB.stokMinimumMaster = {};
    DB.stokMinimumMaster[item] = val;
  });
  saveDB(); closeModal(); renderStokMinimum();
  showToast('Stok minimum diperbarui.');
}

/* ============================================================
   SPRINT 9 — SISTEM DOKUMEN OTOMATIS
   Invoice · Surat Jalan · Purchase Order · Kartu Supplier ·
   Kartu Pelanggan · Laporan — semua PDF, semua dengan QR Code,
   nomor dokumen otomatis terpusat.
   ============================================================ */

// ── REGISTRY NOMOR DOKUMEN TERPUSAT ───────────────────────────
// Semua jenis dokumen pakai satu pola: PREFIX-YYYYMM-#### agar
// mudah dilacak per bulan, tanpa menabrak nomor existing (faktur,
// invoice, resi, dll yang sudah pakai nextCode()).

const DOC_PREFIX = {
  invoice : 'INV',
  suratjalan: 'SJ',
  po      : 'PO',
  kartusup: 'KS',
  kartupel: 'KP',
  laporan : 'LAP',
};

/**
 * Generate nomor dokumen otomatis dengan format PREFIX-YYYYMM-####.
 * Counter per-prefix-per-bulan disimpan di DB.seq.doc[prefix][yyyymm].
 */
function nextDocNumber(jenisDoc){
  const prefix = DOC_PREFIX[jenisDoc] || jenisDoc.toUpperCase();
  const yyyymm = todayStr().slice(0,7).replace('-','');
  if(!DB.seq.doc) DB.seq.doc = {};
  if(!DB.seq.doc[prefix]) DB.seq.doc[prefix] = {};
  const n = (DB.seq.doc[prefix][yyyymm]||0) + 1;
  DB.seq.doc[prefix][yyyymm] = n;
  return `${prefix}-${yyyymm}-${String(n).padStart(4,'0')}`;
}

// ── QR CODE GENERATOR UNIVERSAL ───────────────────────────────

/**
 * Render QR code ke dalam elemen DOM dengan id tertentu.
 * Dipanggil setelah dokumen di-render ke window baru (via onload).
 * Payload berisi data verifikasi dokumen dalam format ringkas.
 */
function renderQrToElement(elId, payload){
  if(typeof QRCode === 'undefined'){
    console.warn('QRCode library belum dimuat.');
    return;
  }
  const el = document.getElementById(elId);
  if(!el) return;
  el.innerHTML = '';
  new QRCode(el, {
    text: payload,
    width: 92, height: 92,
    colorDark: '#1F2430', colorLight: '#ffffff',
    correctLevel: QRCode.CorrectLevel.M,
  });
}

/**
 * Bangun payload QR untuk satu dokumen — ringkas (QR punya kapasitas
 * terbatas), berisi: tipe dokumen, nomor, tanggal, total, dan nama pihak.
 * Format: pipe-separated agar mudah di-parse ulang jika perlu (misal scan
 * untuk verifikasi cepat oleh satpam/sopir/gudang).
 */
function buildQrPayload(tipe, nomor, tanggal, pihak, nilai){
  return `CV.SETIA-DADI|${tipe}|${nomor}|${tanggal}|${esc(pihak)}|${nilai||0}`;
}

/**
 * HTML block QR + caption, siap disisipkan ke template dokumen manapun.
 * Memakai <div id="qr_xxx"> kosong, lalu di-render via script onload
 * karena QRCode.js butuh DOM yang sudah ter-attach ke document.
 */
function qrBlockHtml(qrId, tipe, nomor, tanggal, pihak, nilai){
  return `
  <div style="text-align:center;">
    <div id="${qrId}" style="display:inline-block;padding:6px;background:#fff;border:1px solid #E5E7EB;border-radius:8px;"></div>
    <div style="font-size:0.62rem;color:#9CA3AF;margin-top:4px;font-family:monospace;">${esc(nomor)}</div>
  </div>
  <script>
    window.addEventListener('load', function(){
      if(typeof QRCode !== 'undefined'){
        new QRCode(document.getElementById('${qrId}'), {
          text: ${JSON.stringify(buildQrPayload(tipe, nomor, tanggal, pihak, nilai))},
          width: 84, height: 84,
          colorDark: '#1F2430', colorLight: '#ffffff',
          correctLevel: QRCode.CorrectLevel.M,
        });
      }
    });
  <\/script>`;
}

// ── STYLE DOKUMEN BERSAMA (konsisten dengan DOC_STYLES existing) ──

