// ── 3. PURCHASE ORDER (modul baru sepenuhnya) ─────────────────
// PO adalah dokumen PERMINTAAN pembelian (sebelum barang/uang berpindah),
// berbeda dari Nota Pembelian (yang mencatat transaksi sudah terjadi).
// Disimpan di DB.purchaseOrder agar bisa dilacak status: Draft → Dikirim → Diterima.

function renderPurchaseOrder(target){
  target = target || document.getElementById('pageInner');
  const poList = (DB.purchaseOrder||[]).slice().sort((a,b)=>b.tanggal.localeCompare(a.tanggal));
  const totalNilai = poList.reduce((s,p)=>s+Number(p.totalEstimasi||0),0);
  const draft = poList.filter(p=>p.status==='Draft').length;
  const dikirim = poList.filter(p=>p.status==='Dikirim').length;

  target.innerHTML = `
  <div class="grid grid-4" style="margin-bottom:14px;">
    <div class="kpi"><div class="label">📝 Total PO</div><div class="value">${poList.length}</div></div>
    <div class="kpi gold"><div class="label">⏳ Draft</div><div class="value">${draft}</div></div>
    <div class="kpi" style="border-left-color:#1D4ED8;"><div class="label">📤 Dikirim ke Supplier</div><div class="value">${dikirim}</div></div>
    <div class="kpi" style="border-left-color:var(--rice-green);"><div class="label">💰 Total Estimasi Nilai</div><div class="value" style="font-size:1.1rem;">${fmtRp(totalNilai)}</div></div>
  </div>

  <div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:14px;">
    <button class="btn btn-primary" style="width:auto;" onclick="editPurchaseOrder(null)">+ Buat Purchase Order</button>
    <button class="btn btn-secondary" style="width:auto;" onclick="printReport('printPOList','Riwayat Purchase Order','Total ${poList.length} PO')">🖨 Cetak</button>
    ${dlMenuReport('printPOList','Riwayat Purchase Order','Total '+poList.length+' PO')}
  </div>

  <div class="card">
    <h3>Riwayat Purchase Order <span class="tag">${poList.length} dokumen</span></h3>
    <p class="help-text" style="margin-top:-4px;">PO adalah dokumen permintaan pembelian ke supplier — dibuat sebelum transaksi pembelian aktual dicatat.</p>
    <div class="table-wrap" id="printPOList">
      <table>
        <thead><tr><th>No. PO</th><th>Tanggal</th><th>Supplier</th><th>Item</th><th>Qty Estimasi</th><th>Nilai Estimasi</th><th>Status</th><th>Aksi</th></tr></thead>
        <tbody>
        ${poList.length===0
          ? `<tr><td colspan="8"><div class="empty-state"><div class="stamp">📝</div><div>Belum ada Purchase Order. Klik "+ Buat Purchase Order".</div></div></td></tr>`
          : poList.map(p=>{
            const statusBadge = p.status==='Draft'?'belum':p.status==='Dikirim'?'lunas':p.status==='Diterima'?'lunas':'belum';
            return `<tr>
              <td class="mono" style="font-size:0.78rem;">${esc(p.noPO)}</td>
              <td>${fmtDate(p.tanggal)}</td>
              <td>${esc(p.supplier)}</td>
              <td>${esc(p.item)}</td>
              <td class="num-cell">${fmtNum(p.qtyEstimasi)} kg</td>
              <td class="num-cell">${fmtRp(p.totalEstimasi)}</td>
              <td><span class="badge ${statusBadge}">${esc(p.status)}</span></td>
              <td>
                <button class="btn btn-sm btn-secondary" onclick="generatePODoc('${p.id}')">📄 PDF</button>
                ${p.status==='Draft'?`<button class="btn btn-sm btn-primary" onclick="updateStatusPO('${p.id}','Dikirim')">📤 Kirim</button>`:''}
                ${p.status==='Dikirim'?`<button class="btn btn-sm btn-primary" onclick="updateStatusPO('${p.id}','Diterima')">✓ Diterima</button>`:''}
                <button class="btn btn-sm btn-danger" onclick="deletePO('${p.id}')">🗑</button>
              </td>
            </tr>`;
          }).join('')}
        </tbody>
      </table>
    </div>
  </div>`;
}

function editPurchaseOrder(id){
  const isNew = id===null;
  const p = isNew ? {
    id:uid(), tanggal:todayStr(), supplier:'', jenisGabah:'', qtyEstimasi:0,
    hargaEstimasi:0, catatan:'', status:'Draft',
  } : (DB.purchaseOrder||[]).find(x=>x.id===id);
  if(!p){ showToast('PO tidak ditemukan.'); return; }

  const supOpts = DB.suppliers.map(s=>`<option value="${esc(s.nama)}" ${p.supplier===s.nama?'selected':''}>${esc(s.nama)}</option>`).join('');
  const jenisOpts = DB.jenisGabah.map(j=>`<option value="${esc(j)}" ${p.jenisGabah===j?'selected':''}>${esc(j)}</option>`).join('');

  openModal(`
    <h2>${isNew?'Buat Purchase Order':'Ubah Purchase Order'}</h2>
    <div class="modal-sub">No: <span class="mono">${esc(p.noPO||'(otomatis saat disimpan)')}</span></div>
    <div class="form-row">
      <div class="field"><label>Tanggal *</label><input type="date" id="po_tanggal" value="${esc(p.tanggal)}"></div>
      <div class="field"><label>Supplier *</label>
        <select id="po_supplier"><option value="">-- Pilih --</option>${supOpts}</select>
      </div>
    </div>
    <div class="form-row">
      <div class="field"><label>Jenis Gabah / Item *</label>
        <select id="po_item"><option value="">-- Pilih --</option>${jenisOpts}</select>
      </div>
      <div class="field"><label>Qty Estimasi (Kg) *</label>
        <input type="number" id="po_qty" value="${p.qtyEstimasi||0}" min="0" oninput="updatePOTotal()">
      </div>
    </div>
    <div class="form-row">
      <div class="field"><label>Harga Estimasi /Kg (Rp)</label>
        <input type="text" id="po_harga" value="${fmtNum(p.hargaEstimasi||0)}" oninput="onInputRpFormat(this);updatePOTotal()" inputmode="numeric">
      </div>
      <div class="field"><label>Total Estimasi (Rp)</label>
        <input type="text" id="po_total" value="${fmtRp((p.qtyEstimasi||0)*(p.hargaEstimasi||0))}" readonly style="background:#F9FAFB;font-weight:700;">
      </div>
    </div>
    <div class="field"><label>Catatan / Spesifikasi</label>
      <textarea id="po_catatan" rows="2" style="resize:vertical;">${esc(p.catatan||'')}</textarea>
    </div>
    <div class="form-actions">
      <button class="btn btn-primary" style="width:auto;" onclick="savePurchaseOrder('${p.id}',${isNew})">Simpan PO</button>
      <button class="btn btn-secondary" onclick="closeModal()">Batal</button>
    </div>
  `);
}

function updatePOTotal(){
  const qty   = Number(document.getElementById('po_qty')?.value)||0;
  const harga = readInputRp('po_harga');
  document.getElementById('po_total').value = fmtRp(qty*harga);
}

function savePurchaseOrder(id, isNew){
  const tanggal = document.getElementById('po_tanggal')?.value;
  const supplier= document.getElementById('po_supplier')?.value;
  const item    = document.getElementById('po_item')?.value;
  const qty     = Number(document.getElementById('po_qty')?.value)||0;
  const harga   = readInputRp('po_harga');
  const catatan = document.getElementById('po_catatan')?.value.trim()||'';

  if(!tanggal||!supplier||!item||qty<=0){ alert('Tanggal, Supplier, Item, dan Qty wajib diisi.'); return; }

  if(!DB.purchaseOrder) DB.purchaseOrder = [];

  if(isNew){
    const noPO = nextDocNumber('po');
    DB.purchaseOrder.push({
      id, noPO, tanggal, supplier, jenisGabah:item, item,
      qtyEstimasi:qty, hargaEstimasi:harga, totalEstimasi:qty*harga,
      catatan, status:'Draft',
    });
  } else {
    const row = (DB.purchaseOrder||[]).find(x=>x.id===id);
    Object.assign(row, {tanggal, supplier, jenisGabah:item, item,
      qtyEstimasi:qty, hargaEstimasi:harga, totalEstimasi:qty*harga, catatan});
  }
  saveDB(); closeModal(); renderPurchaseOrder();
  showToast(isNew?'Purchase Order dibuat.':'Purchase Order diperbarui.');
}

function updateStatusPO(id, status){
  const p = (DB.purchaseOrder||[]).find(x=>x.id===id);
  if(!p) return;
  p.status = status;
  saveDB(); renderPurchaseOrder();
  showToast(`PO ${p.noPO} status: ${status}`);
}

function deletePO(id){
  if(!confirm('Hapus Purchase Order ini?')) return;
  DB.purchaseOrder = (DB.purchaseOrder||[]).filter(x=>x.id!==id);
  saveDB(); renderPurchaseOrder();
  showToast('PO dihapus.');
}

