// ── 5. KARTU PELANGGAN (paralel dengan Kartu Supplier) ────────

function _buildKartuPelangganEvents(pelangganNama){
  const events = [];

  DB.penjualan.filter(r=>r.pelanggan===pelangganNama)
    .sort((a,b)=>a.tanggal.localeCompare(b.tanggal))
    .forEach(r=>{
      const produkLabel = r.produk==='Premium'?'Beras Premium':r.produk==='Medium'?'Beras Medium':r.produk;
      events.push({
        tgl_raw:r.tanggal, urutan:'1jual', ref:r.invoice, tipe:'penjualan',
        ket:`Penjualan ${produkLabel} (${fmtNum(r.qty)} kg @ ${fmtRp(r.harga)}/kg)`,
        debit:Number(r.total||0), kredit:0,
      });
      if(r.status==='Lunas'){
        events.push({tgl_raw:r.tanggal, urutan:'2bayar', ref:r.invoice, tipe:'bayar',
          ket:'Pembayaran lunas saat transaksi', debit:0, kredit:Number(r.total||0)});
      }
    });

  DB.kasbank.filter(k=>k.kategori==='Penerimaan Pelunasan Piutang').forEach(k=>{
    const r = DB.penjualan.find(x=>x.id===k.refId||x.id===k.sourceId);
    if(!r || r.pelanggan!==pelangganNama) return;
    events.push({tgl_raw:k.tanggal, urutan:'2bayar', ref:r.invoice, tipe:'bayar',
      ket:k.keterangan||`Pelunasan piutang (${r.invoice})`, debit:0, kredit:Number(k.masuk||0)});
  });

  events.sort((a,b)=>a.tgl_raw.localeCompare(b.tgl_raw)||a.urutan.localeCompare(b.urutan));
  let saldo=0;
  events.forEach(e=>{ saldo += e.debit-e.kredit; e.saldo=saldo; });

  const totDebit  = events.reduce((s,e)=>s+e.debit,0);
  const totKredit = events.reduce((s,e)=>s+e.kredit,0);
  return { events, totDebit, totKredit, saldoAkhir: totDebit-totKredit };
}

function showKartuPelanggan(pelangganNama){
  const pel = DB.pelanggan.find(p=>p.nama===pelangganNama);
  const { events, totDebit, totKredit, saldoAkhir } = _buildKartuPelangganEvents(pelangganNama);
  const saldoColor = saldoAkhir>0.01?'var(--red)':'var(--rice-green)';
  const saldoLabel = saldoAkhir>0.01 ? fmtRp(saldoAkhir)+' (Masih Piutang)' : 'LUNAS \u2713';

  const TIPE = { penjualan:['Penjualan','style="background:#EEF1F4;color:#374151;"'], bayar:['Pembayaran','class="badge lunas"'] };
  const rowsHtml = events.length===0
    ? `<tr><td colspan="6"><div class="empty-state"><div class="stamp">📋</div><div>Belum ada transaksi.</div></div></td></tr>`
    : events.map(e=>{
        const [lbl,battr] = TIPE[e.tipe]||['Lain','class="badge"'];
        const sc = e.saldo>0.01?'color:var(--red);':'color:var(--rice-green);';
        return `<tr>
          <td>${fmtDate(e.tgl_raw)}</td>
          <td class="mono">${esc(e.ref)}</td>
          <td><span class="badge" ${battr}>${lbl}</span></td>
          <td style="font-size:0.8rem;">${esc(e.ket)}</td>
          <td class="num-cell">${e.debit>0?fmtRp(e.debit):'-'}</td>
          <td class="num-cell" style="color:var(--rice-green);">${e.kredit>0?fmtRp(e.kredit):'-'}</td>
          <td class="num-cell"><b style="${sc}">${e.saldo>0.01?fmtRp(e.saldo):'Lunas \u2713'}</b></td>
        </tr>`;
      }).join('');

  const safeNama = esc(pelangganNama).replace(/'/g,"\\'");
  openModal(`
    <div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:14px;flex-wrap:wrap;gap:10px;">
      <div>
        <h2 style="margin-bottom:2px;">Kartu Piutang Pelanggan</h2>
        <div style="font-size:1.05rem;font-weight:700;">${esc(pelangganNama)}</div>
        ${pel?`<div style="font-size:0.8rem;color:var(--ink-soft);">${esc(pel.alamat||'')}${pel.telp?' \u00b7 '+esc(pel.telp):''}</div>`:''}
      </div>
      <div class="kpi" style="min-width:180px;border-left-color:${saldoColor};">
        <div class="label">Saldo Piutang</div>
        <div class="value" style="font-size:1rem;color:${saldoColor};">${saldoLabel}</div>
      </div>
    </div>
    <div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:14px;">
      <button class="btn btn-primary" style="width:auto;" onclick="generateKartuPelangganDoc('${safeNama}')">🖨 Cetak / PDF + QR</button>
      <button class="btn btn-secondary" onclick="closeModal()">Tutup</button>
    </div>
    <div class="grid grid-3" style="margin-bottom:14px;">
      <div class="kpi"><div class="label">Total Penjualan</div><div class="value" style="font-size:0.9rem;">${fmtRp(totDebit)}</div></div>
      <div class="kpi" style="border-left-color:var(--rice-green);"><div class="label">Total Diterima</div><div class="value" style="font-size:0.9rem;color:var(--rice-green);">${fmtRp(totKredit)}</div></div>
      <div class="kpi" style="border-left-color:${saldoColor};"><div class="label">Saldo Akhir</div><div class="value" style="font-size:0.9rem;color:${saldoColor};">${saldoLabel}</div></div>
    </div>
    <div class="table-wrap">
      <table>
        <thead><tr><th>Tanggal</th><th>Ref</th><th>Tipe</th><th>Keterangan</th><th>Penjualan</th><th>Diterima</th><th>Saldo Piutang</th></tr></thead>
        <tbody>
          ${rowsHtml}
          <tr class="total-row">
            <td colspan="4">TOTAL</td>
            <td class="num-cell">${fmtRp(totDebit)}</td>
            <td class="num-cell" style="color:var(--rice-green);">${fmtRp(totKredit)}</td>
            <td class="num-cell" style="color:${saldoColor};"><b>${saldoLabel}</b></td>
          </tr>
        </tbody>
      </table>
    </div>
  `);
}

