/* ============================================================
   SPRINT 10 — BACKUP ENTERPRISE
   Backup JSON · Restore JSON · Export Excel · Import Excel ·
   Backup Otomatis · Riwayat Backup · Validasi Restore
   Menjamin seluruh data + relasi kembali utuh saat restore.
   ============================================================ */

// ── KONSTANTA & DEFINISI SKEMA ────────────────────────────────

/** Daftar lengkap 29 tabel DB beserta tipe & kunci relasi (untuk validasi) */
const DB_SCHEMA = {
  users:          { tipe:'array', relasi:[] },
  suppliers:      { tipe:'array', relasi:[] },
  pelanggan:      { tipe:'array', relasi:[] },
  jenisGabah:     { tipe:'array', relasi:[] },
  jenisBeras:     { tipe:'array', relasi:[] },
  jenisSamping:   { tipe:'array', relasi:[] },
  jenisBahanBaku: { tipe:'array', relasi:[] },
  kendaraan:      { tipe:'array', relasi:[] },
  bahanPendukung: { tipe:'array', relasi:[] },
  pembelianBahan: { tipe:'array', relasi:[{field:'item', ref:'bahanPendukung', refField:'nama'}] },
  pemakaianBahan: { tipe:'array', relasi:[{field:'item', ref:'bahanPendukung', refField:'nama'}] },
  mutasi:         { tipe:'array', relasi:[] },
  kuitansi:       { tipe:'array', relasi:[{field:'supplier', ref:'suppliers', refField:'nama'}] },
  pengiriman:     { tipe:'array', relasi:[{field:'pelanggan', ref:'pelanggan', refField:'nama'},{field:'penjualanId', ref:'penjualan', refField:'id'}] },
  pembelian:      { tipe:'array', relasi:[{field:'supplier', ref:'suppliers', refField:'nama'}] },
  produksi:       { tipe:'array', relasi:[] },
  penjualan:      { tipe:'array', relasi:[{field:'pelanggan', ref:'pelanggan', refField:'nama'}] },
  kasbank:        { tipe:'array', relasi:[] },
  saldoAwalKas:   { tipe:'number', relasi:[] },
  neracaAsumsi:   { tipe:'object', relasi:[] },
  maklon:         { tipe:'array', relasi:[{field:'pelanggan', ref:'pelanggan', refField:'nama'}] },
  jurnal:         { tipe:'array', relasi:[] },
  lotStok:        { tipe:'array', relasi:[] },
  stockOpname:    { tipe:'array', relasi:[] },
  stokMinimumMaster:{ tipe:'object', relasi:[] },
  purchaseOrder:  { tipe:'array', relasi:[{field:'supplier', ref:'suppliers', refField:'nama'}] },
  backupHistory:  { tipe:'array', relasi:[] },
  mesin:          { tipe:'array', relasi:[] },
  serviceLog:     { tipe:'array', relasi:[{field:'mesinId', ref:'mesin', refField:'id'}] },
  seq:            { tipe:'object', relasi:[] },
};

const BACKUP_AUTO_INTERVAL_MIN = 15;     // backup otomatis tiap 15 menit jika ada perubahan
const BACKUP_AUTO_MAX_SNAPSHOT = 10;     // rotasi: simpan maksimal 10 snapshot otomatis
const AUTO_BACKUP_KEY = 'erp_padi_autobackup_snapshots';

// ── UTILITAS ───────────────────────────────────────────────────

/** Hitung checksum sederhana (non-kriptografis) untuk deteksi korupsi data */
function simpleChecksum(str){
  let hash = 0;
  for(let i=0;i<str.length;i++){
    hash = ((hash<<5)-hash + str.charCodeAt(i))|0;
  }
  return Math.abs(hash).toString(16);
}

/** Hitung total record di seluruh DB (untuk ringkasan & validasi) */
function countAllRecords(dbObj){
  let total = 0;
  Object.keys(DB_SCHEMA).forEach(k=>{
    if(Array.isArray(dbObj[k])) total += dbObj[k].length;
  });
  return total;
}

function fmtBytes(bytes){
  if(bytes < 1024) return bytes+' B';
  if(bytes < 1024*1024) return (bytes/1024).toFixed(1)+' KB';
  return (bytes/1024/1024).toFixed(2)+' MB';
}

// ── VALIDASI RESTORE (KRITIS) ─────────────────────────────────

/**
 * Validasi menyeluruh sebelum restore: struktur, tipe data, dan
 * integritas relasi (foreign-key-like checks) antar tabel.
 * @returns {valid, errors[], warnings[], summary}
 */
function validateRestoreData(data){
  const errors = [];
  const warnings = [];

  if(!data || typeof data !== 'object'){
    return { valid:false, errors:['File bukan objek JSON yang valid.'], warnings:[], summary:null };
  }

  // 1. Cek semua tabel wajib ada & tipe benar
  Object.entries(DB_SCHEMA).forEach(([key, schema])=>{
    if(!(key in data)){
      warnings.push(`Tabel "${key}" tidak ada di file — akan dibuat kosong/default.`);
      return;
    }
    const val = data[key];
    if(schema.tipe==='array' && !Array.isArray(val)){
      errors.push(`Tabel "${key}" seharusnya array, ditemukan: ${typeof val}.`);
    }
    if(schema.tipe==='object' && (typeof val!=='object' || Array.isArray(val))){
      errors.push(`Tabel "${key}" seharusnya object, ditemukan: ${typeof val}.`);
    }
    if(schema.tipe==='number' && typeof val!=='number'){
      warnings.push(`Tabel "${key}" seharusnya number, ditemukan: ${typeof val}. Akan dikonversi.`);
    }
  });
  if(errors.length>0){
    return { valid:false, errors, warnings, summary:null };
  }

  // 2. Cek wajib minimal: users dan minimal satu transaksi inti
  if(!Array.isArray(data.users) || data.users.length===0){
    errors.push('Tabel "users" kosong — minimal harus ada 1 user untuk login.');
  }

  // 3. Cek duplikasi ID dalam tabel yang sama (data korup jika ada)
  Object.entries(DB_SCHEMA).forEach(([key, schema])=>{
    if(schema.tipe!=='array' || !Array.isArray(data[key])) return;
    const ids = data[key].map(r=>r && r.id).filter(Boolean);
    const uniqueIds = new Set(ids);
    if(ids.length !== uniqueIds.size){
      errors.push(`Tabel "${key}" memiliki ID duplikat (${ids.length - uniqueIds.size} duplikat) — data kemungkinan korup.`);
    }
  });

  // 4. Cek integritas relasi (foreign-key-like) — WARNING saja, tidak blocking
  //    karena nama supplier/pelanggan/item bisa berubah tapi transaksi tetap valid historis.
  let relasiBermasalah = 0;
  Object.entries(DB_SCHEMA).forEach(([key, schema])=>{
    if(!Array.isArray(data[key]) || schema.relasi.length===0) return;
    schema.relasi.forEach(rel=>{
      const refTable = data[rel.ref];
      if(!Array.isArray(refTable)) return;
      const refValues = new Set(refTable.map(r=>r && r[rel.refField]).filter(Boolean));
      let missingCount = 0;
      data[key].forEach(row=>{
        const val = row && row[rel.field];
        if(val && !refValues.has(val)) missingCount++;
      });
      if(missingCount>0){
        relasiBermasalah += missingCount;
        warnings.push(`${missingCount} baris di "${key}" mereferensikan "${rel.field}" yang tidak ditemukan di "${rel.ref}" (kemungkinan data master sudah dihapus/diubah namanya — transaksi historis tetap aman).`);
      }
    });
  });

  // 5. Cek seq counter tidak lebih kecil dari jumlah data aktual (mencegah nomor dokumen tabrakan)
  if(data.seq){
    const seqChecks = [
      {key:'faktur', table:'pembelian'}, {key:'invoice', table:'penjualan'},
      {key:'batch', table:'produksi'}, {key:'resi', table:'pengiriman'},
    ];
    seqChecks.forEach(c=>{
      if(Array.isArray(data[c.table]) && typeof data.seq[c.key]==='number'){
        if(data.seq[c.key] < data[c.table].length){
          warnings.push(`Counter seq.${c.key} (${data.seq[c.key]}) lebih kecil dari jumlah data ${c.table} (${data[c.table].length}) — nomor dokumen baru berisiko tabrakan. Akan disesuaikan otomatis.`);
        }
      }
    });
  }

  const summary = {
    totalRecord: countAllRecords(data),
    tabelCount: Object.keys(DB_SCHEMA).filter(k=>k in data).length,
    relasiBermasalah,
    users: (data.users||[]).length,
    suppliers: (data.suppliers||[]).length,
    pelanggan: (data.pelanggan||[]).length,
    pembelian: (data.pembelian||[]).length,
    penjualan: (data.penjualan||[]).length,
    produksi: (data.produksi||[]).length,
    jurnal: (data.jurnal||[]).length,
  };

  return { valid: errors.length===0, errors, warnings, summary };
}

/**
 * Perbaiki otomatis hal-hal minor sebelum commit restore:
 * - Backfill tabel yang hilang dengan default kosong
 * - Sesuaikan seq counter agar tidak lebih kecil dari data aktual
 */
function repairDataBeforeRestore(data){
  const def = defaultData();
  Object.keys(def).forEach(k=>{
    if(!(k in data)) data[k] = def[k];
  });
  if(!data.seq) data.seq = {};
  Object.keys(def.seq).forEach(k=>{
    if(!(k in data.seq)) data.seq[k] = def.seq[k];
  });
  // Sesuaikan seq agar >= jumlah data (cegah nomor dokumen tabrakan)
  const seqAutoFix = [
    {key:'faktur', table:'pembelian'}, {key:'invoice', table:'penjualan'},
    {key:'batch', table:'produksi'}, {key:'resi', table:'pengiriman'},
    {key:'fakturBahan', table:'pembelianBahan'}, {key:'kuitansi', table:'kuitansi'},
    {key:'maklon', table:'maklon'}, {key:'opname', table:'stockOpname'},
    {key:'lot', table:'lotStok'},
  ];
  seqAutoFix.forEach(c=>{
    if(Array.isArray(data[c.table]) && data.seq[c.key] < data[c.table].length){
      data.seq[c.key] = data[c.table].length;
    }
  });
  return data;
}

// ── BACKUP JSON (manual, dengan riwayat) ──────────────────────

/**
 * Backup JSON lengkap + catat ke riwayat backup.
 * Mengganti exportData() lama secara fungsional tapi lebih lengkap;
 * exportData() asli TETAP ada dan tidak diubah untuk kompatibilitas.
 */
function backupJSON(catatan){
  const json = JSON.stringify(DB, null, 2);
  const checksum = simpleChecksum(json);
  const ukuran = new Blob([json]).size;
  const totalRecord = countAllRecords(DB);
  const tanggal = new Date().toISOString();

  const entry = {
    id: uid(), tanggal, jenis:'JSON', ukuran, jumlahRecord: totalRecord,
    checksum, catatan: catatan||'Backup manual', otomatis:false,
  };
  if(!DB.backupHistory) DB.backupHistory = [];
  DB.backupHistory.unshift(entry);
  // batasi riwayat manual maksimal 50 entri agar DB tidak membengkak
  if(DB.backupHistory.length>50) DB.backupHistory = DB.backupHistory.slice(0,50);
  saveDB();

  const blob = new Blob([json], {type:'application/json'});
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `cv-setiadadi-backup-${todayStr()}-${checksum}.json`;
  a.click();
  URL.revokeObjectURL(url);
  showToast(`Backup JSON berhasil (${fmtBytes(ukuran)}, ${totalRecord} record).`);
  return entry;
}

// ── RESTORE JSON (dengan validasi penuh) ──────────────────────

function restoreJSONFile(ev){
  const file = ev.target.files[0];
  if(!file) return;
  const reader = new FileReader();
  reader.onload = (e)=>{
    let data;
    try{
      data = JSON.parse(e.target.result);
    }catch(err){
      alert('File rusak atau bukan format JSON yang valid.');
      ev.target.value = '';
      return;
    }
    const validation = validateRestoreData(data);
    showRestorePreview(data, validation, file.name, file.size);
  };
  reader.readAsText(file);
  ev.target.value = '';
}

/** Modal preview hasil validasi sebelum commit restore — mencegah kehilangan data tanpa sadar */
function showRestorePreview(data, validation, filename, filesize){
  const { valid, errors, warnings, summary } = validation;

  openModal(`
    <h2>${valid?'✓ Validasi Berhasil':'✗ Validasi Gagal'} — Pratinjau Restore</h2>
    <div class="modal-sub">File: ${esc(filename)} (${fmtBytes(filesize)})</div>

    ${!valid?`
    <div style="background:#FEE2E2;border:1px solid #FCA5A5;border-radius:8px;padding:12px;margin:12px 0;">
      <div style="font-weight:700;color:#B91C1C;margin-bottom:6px;">⛔ ${errors.length} Error — Restore Dibatalkan</div>
      ${errors.map(e=>`<div style="font-size:0.82rem;color:#991B1B;margin-bottom:3px;">• ${esc(e)}</div>`).join('')}
    </div>`:''}

    ${valid?`
    <div class="grid grid-4" style="margin:12px 0;">
      <div class="kpi"><div class="label">Total Record</div><div class="value">${fmtNum(summary.totalRecord)}</div></div>
      <div class="kpi"><div class="label">Tabel Terisi</div><div class="value">${summary.tabelCount}/${Object.keys(DB_SCHEMA).length}</div></div>
      <div class="kpi"><div class="label">Pembelian / Penjualan</div><div class="value" style="font-size:1rem;">${summary.pembelian} / ${summary.penjualan}</div></div>
      <div class="kpi ${summary.relasiBermasalah>0?'gold':''}"><div class="label">Relasi Bermasalah</div><div class="value">${summary.relasiBermasalah}</div></div>
    </div>

    <div class="grid grid-3" style="margin-bottom:12px;">
      <div class="kpi"><div class="label">Users</div><div class="value">${summary.users}</div></div>
      <div class="kpi"><div class="label">Supplier / Pelanggan</div><div class="value" style="font-size:1rem;">${summary.suppliers} / ${summary.pelanggan}</div></div>
      <div class="kpi"><div class="label">Batch Produksi / Jurnal</div><div class="value" style="font-size:1rem;">${summary.produksi} / ${summary.jurnal}</div></div>
    </div>` : ''}

    ${warnings.length>0?`
    <div style="background:#FEF3C7;border:1px solid #FCD34D;border-radius:8px;padding:12px;margin-bottom:12px;max-height:200px;overflow-y:auto;">
      <div style="font-weight:700;color:#92400E;margin-bottom:6px;">⚠ ${warnings.length} Peringatan (tidak menghalangi restore)</div>
      ${warnings.map(w=>`<div style="font-size:0.78rem;color:#9A3412;margin-bottom:3px;">• ${esc(w)}</div>`).join('')}
    </div>`:''}

    ${valid?`
    <div style="background:#DBEAFE;border:1px solid #93C5FD;border-radius:8px;padding:12px;margin-bottom:14px;font-size:0.84rem;color:#1E40AF;">
      💡 Data Anda saat ini (${fmtNum(countAllRecords(DB))} record) akan otomatis di-backup terlebih dahulu sebelum ditimpa, jadi Anda bisa membatalkan jika perlu.
    </div>`:''}

    <div class="form-actions">
      ${valid?`<button class="btn btn-primary" style="width:auto;background:var(--red);" onclick="commitRestore()">⚠ Ya, Timpa Data Sekarang</button>`:''}
      <button class="btn btn-secondary" onclick="closeModal()">Batal</button>
    </div>
  `);

  // Simpan data sementara untuk commitRestore()
  window._pendingRestoreData = data;
}

/** Eksekusi restore setelah dikonfirmasi — backup otomatis dulu sebelum timpa */
function commitRestore(){
  const data = window._pendingRestoreData;
  if(!data){ showToast('Data restore tidak ditemukan. Ulangi proses.'); return; }

  // Safety net: backup data SAAT INI sebelum ditimpa
  try{
    const safetyJson = JSON.stringify(DB);
    saveAutoBackupSnapshot('Sebelum Restore (Safety Net)', safetyJson);
  }catch(e){ console.warn('Gagal membuat safety backup', e); }

  // Perbaiki minor issues (seq counter, tabel hilang) lalu commit
  const repaired = repairDataBeforeRestore(data);
  DB = repaired;

  // Catat di riwayat backup bahwa restore terjadi
  if(!DB.backupHistory) DB.backupHistory = [];
  DB.backupHistory.unshift({
    id: uid(), tanggal: new Date().toISOString(), jenis:'RESTORE',
    ukuran: new Blob([JSON.stringify(DB)]).size, jumlahRecord: countAllRecords(DB),
    checksum: simpleChecksum(JSON.stringify(DB)),
    catatan: 'Data dipulihkan dari file backup', otomatis:false,
  });

  saveDB();
  // Re-run loadDB() agar SEMUA migrasi (fix double-entry kasbank, backfill jenisSamping, dll)
  // ikut dijalankan terhadap data yang baru di-restore — krusial agar relasi tetap konsisten.
  loadDB();

  delete window._pendingRestoreData;
  closeModal();
  showToast(`✓ Restore berhasil! ${countAllRecords(DB)} record dipulihkan.`);
  enterApp(); // re-render seluruh app dari awal
}

// ── EXPORT EXCEL MULTI-SHEET (semua tabel sekaligus) ──────────

function exportExcelLengkap(){
  if(typeof XLSX === 'undefined'){
    showToast('Fitur Excel membutuhkan koneksi internet untuk memuat library.');
    return;
  }
  showToast('Membuat file Excel lengkap...');

  const wb = XLSX.utils.book_new();
  const sheetTables = [
    {key:'pembelian', name:'Pembelian'}, {key:'produksi', name:'Produksi'},
    {key:'penjualan', name:'Penjualan'}, {key:'kasbank', name:'KasBank'},
    {key:'maklon', name:'Maklon'}, {key:'suppliers', name:'Supplier'},
    {key:'pelanggan', name:'Pelanggan'}, {key:'mutasi', name:'MutasiStok'},
    {key:'pengiriman', name:'Pengiriman'}, {key:'purchaseOrder', name:'PurchaseOrder'},
    {key:'jurnal', name:'Jurnal'}, {key:'mesin', name:'Mesin'},
    {key:'serviceLog', name:'ServiceLog'}, {key:'stockOpname', name:'StockOpname'},
    {key:'lotStok', name:'LotStok'}, {key:'bahanPendukung', name:'BahanPendukung'},
    {key:'pembelianBahan', name:'PembelianBahan'}, {key:'pemakaianBahan', name:'PemakaianBahan'},
    {key:'kuitansi', name:'Kuitansi'}, {key:'users', name:'Users'},
  ];

  sheetTables.forEach(t=>{
    const rows = DB[t.key];
    if(!Array.isArray(rows)) return;
    if(rows.length===0){
      const ws = XLSX.utils.aoa_to_sheet([['(tidak ada data)']]);
      XLSX.utils.book_append_sheet(wb, ws, t.name.slice(0,31));
      return;
    }
    // Flatten array fields (mis. sumberGabah, hasil_cv) jadi JSON string agar tidak pecah kolom
    const flatRows = rows.map(r=>{
      const flat = {};
      Object.entries(r).forEach(([k,v])=>{
        flat[k] = (typeof v==='object' && v!==null) ? JSON.stringify(v) : v;
      });
      return flat;
    });
    const ws = XLSX.utils.json_to_sheet(flatRows);
    XLSX.utils.book_append_sheet(wb, ws, t.name.slice(0,31));
  });

  // Sheet ringkasan di paling depan
  const summaryData = [
    ['CV. Setia Dadi — Export Data Lengkap'],
    ['Tanggal Export', new Date().toLocaleString('id-ID')],
    ['Total Record', countAllRecords(DB)],
    [''],
    ['Tabel', 'Jumlah Record'],
    ...sheetTables.map(t=>[t.name, (DB[t.key]||[]).length]),
  ];
  const wsSummary = XLSX.utils.aoa_to_sheet(summaryData);
  XLSX.utils.book_append_sheet(wb, wsSummary, 'Ringkasan');
  // Pindahkan Ringkasan ke posisi pertama
  wb.SheetNames.unshift(wb.SheetNames.pop());

  const filename = `cv-setiadadi-export-lengkap-${todayStr()}.xlsx`;
  XLSX.writeFile(wb, filename);

  // Catat ke riwayat backup
  if(!DB.backupHistory) DB.backupHistory = [];
  DB.backupHistory.unshift({
    id: uid(), tanggal: new Date().toISOString(), jenis:'EXCEL',
    ukuran: 0, jumlahRecord: countAllRecords(DB), checksum:'-',
    catatan: `Export Excel lengkap (${sheetTables.length} sheet)`, otomatis:false,
  });
  saveDB();
  showToast(`Excel lengkap berhasil diunduh (${sheetTables.length} sheet).`);
}

// ── IMPORT EXCEL ───────────────────────────────────────────────
// Strategi: Excel TIDAK menggantikan seluruh DB (berbeda dari restore JSON).
// Import Excel hanya MENAMBAH/MEMPERBARUI tabel tertentu (mis. update master
// supplier/pelanggan secara massal, atau menambah data pembelian dari template).
// Ini lebih aman karena tidak berisiko menghapus relasi/riwayat yang ada.

const IMPORT_EXCEL_TARGETS = {
  suppliers: {
    label: 'Master Supplier', requiredCols: ['nama'],
    mapRow: row => ({ kode: row.kode || nextCode('_tmp','SUP',3), nama: row.nama, alamat: row.alamat||'', telp: row.telp||'' }),
    matchKey: 'nama',
  },
  pelanggan: {
    label: 'Master Pelanggan', requiredCols: ['nama'],
    mapRow: row => ({ kode: row.kode || nextCode('_tmp','CUS',3), nama: row.nama, alamat: row.alamat||'', telp: row.telp||'' }),
    matchKey: 'nama',
  },
};

function renderImportExcelPicker(){
  const opts = Object.entries(IMPORT_EXCEL_TARGETS).map(([k,v])=>`<option value="${k}">${esc(v.label)}</option>`).join('');
  openModal(`
    <h2>Import Excel</h2>
    <p class="help-text" style="margin-top:-4px;">
      Import Excel akan <b>menambah/memperbarui</b> data master (tidak menimpa seluruh database).
      File harus punya header kolom sesuai target yang dipilih. Baris dengan key (nama) yang sudah ada akan diperbarui; baris baru akan ditambahkan.
    </p>
    <div class="field">
      <label>Target Tabel *</label>
      <select id="imp_target">${opts}</select>
    </div>
    <div class="field">
      <label>File Excel (.xlsx)</label>
      <input type="file" id="imp_file" accept=".xlsx,.xls">
    </div>
    <div id="imp_preview"></div>
    <div class="form-actions">
      <button class="btn btn-primary" style="width:auto;" onclick="previewImportExcel()">🔍 Pratinjau</button>
      <button class="btn btn-secondary" onclick="closeModal()">Batal</button>
    </div>
  `);
}

function previewImportExcel(){
  const target = document.getElementById('imp_target')?.value;
  const fileInput = document.getElementById('imp_file');
  const file = fileInput?.files[0];
  if(!file){ showToast('Pilih file Excel terlebih dahulu.'); return; }
  if(typeof XLSX === 'undefined'){ showToast('Library Excel belum dimuat. Coba lagi.'); return; }

  const reader = new FileReader();
  reader.onload = (e)=>{
    try{
      const wb = XLSX.read(e.target.result, {type:'binary'});
      const ws = wb.Sheets[wb.SheetNames[0]];
      const rows = XLSX.utils.sheet_to_json(ws, {defval:''});
      if(rows.length===0){ showToast('File Excel kosong atau format tidak terbaca.'); return; }

      const config = IMPORT_EXCEL_TARGETS[target];
      const missingCols = config.requiredCols.filter(c=>!(c in rows[0]));
      if(missingCols.length>0){
        document.getElementById('imp_preview').innerHTML = `
          <div style="background:#FEE2E2;border:1px solid #FCA5A5;border-radius:8px;padding:10px;margin-top:10px;color:#B91C1C;font-size:0.84rem;">
            ⛔ Kolom wajib tidak ditemukan: ${missingCols.join(', ')}. Kolom yang ada: ${Object.keys(rows[0]).join(', ')}
          </div>`;
        return;
      }

      window._pendingImportExcel = { target, rows };
      const existingList = DB[target]||[];
      const existingKeys = new Set(existingList.map(r=>r[config.matchKey]));
      let baru=0, update=0;
      rows.forEach(row=>{
        if(existingKeys.has(row[config.matchKey])) update++; else baru++;
      });

      document.getElementById('imp_preview').innerHTML = `
        <div class="grid grid-3" style="margin-top:10px;">
          <div class="kpi"><div class="label">Total Baris</div><div class="value">${rows.length}</div></div>
          <div class="kpi" style="border-left-color:var(--rice-green);"><div class="label">Data Baru</div><div class="value">${baru}</div></div>
          <div class="kpi gold"><div class="label">Akan Diperbarui</div><div class="value">${update}</div></div>
        </div>
        <button class="btn btn-primary" style="width:auto;margin-top:10px;" onclick="commitImportExcel()">✓ Proses Import (${rows.length} baris)</button>
      `;
    }catch(err){
      console.error(err);
      showToast('Gagal membaca file Excel. Pastikan format .xlsx valid.');
    }
  };
  reader.readAsBinaryString(file);
}

function commitImportExcel(){
  const pending = window._pendingImportExcel;
  if(!pending){ showToast('Tidak ada data untuk diimpor.'); return; }
  const config = IMPORT_EXCEL_TARGETS[pending.target];
  if(!DB[pending.target]) DB[pending.target] = [];

  let baru=0, update=0;
  pending.rows.forEach(row=>{
    const mapped = config.mapRow(row);
    const existing = DB[pending.target].find(r=>r[config.matchKey]===mapped[config.matchKey]);
    if(existing){
      Object.assign(existing, mapped);
      update++;
    } else {
      DB[pending.target].push({ id: uid(), ...mapped });
      baru++;
    }
  });

  if(!DB.backupHistory) DB.backupHistory = [];
  DB.backupHistory.unshift({
    id: uid(), tanggal: new Date().toISOString(), jenis:'IMPORT_EXCEL',
    ukuran:0, jumlahRecord: pending.rows.length, checksum:'-',
    catatan: `Import Excel ke "${config.label}": ${baru} baru, ${update} diperbarui`, otomatis:false,
  });

  saveDB();
  delete window._pendingImportExcel;
  closeModal();
  showToast(`Import selesai: ${baru} data baru, ${update} diperbarui.`);
  navigateTo(currentPage);
}

// ── BACKUP OTOMATIS (rotating snapshot di localStorage terpisah) ──
// Snapshot otomatis TIDAK masuk ke DB.backupHistory (agar tidak membengkak
// kuota localStorage utama). Disimpan di key terpisah dengan rotasi N snapshot.

function getAutoBackupSnapshots(){
  try{
    const raw = localStorage.getItem(AUTO_BACKUP_KEY);
    return raw ? JSON.parse(raw) : [];
  }catch(e){ return []; }
}

function saveAutoBackupSnapshot(catatan, jsonOverride){
  try{
    const json = jsonOverride || JSON.stringify(DB);
    const snapshots = getAutoBackupSnapshots();
    const entry = {
      id: uid(), tanggal: new Date().toISOString(),
      checksum: simpleChecksum(json), ukuran: new Blob([json]).size,
      jumlahRecord: countAllRecords(DB), catatan: catatan||'Backup otomatis',
      data: json,
    };
    snapshots.unshift(entry);
    // Rotasi: simpan maksimal N snapshot terbaru
    const trimmed = snapshots.slice(0, BACKUP_AUTO_MAX_SNAPSHOT);
    localStorage.setItem(AUTO_BACKUP_KEY, JSON.stringify(trimmed));
    return entry;
  }catch(e){
    console.warn('Gagal menyimpan backup otomatis (kemungkinan kuota localStorage penuh)', e);
    return null;
  }
}

let _lastAutoBackupHash = null;
let _autoBackupTimer = null;

/** Jalankan backup otomatis HANYA jika data berubah sejak backup terakhir (hemat kuota) */
function runAutoBackupCheck(){
  try{
    const json = JSON.stringify(DB);
    const hash = simpleChecksum(json);
    if(hash === _lastAutoBackupHash) return; // tidak ada perubahan, skip
    _lastAutoBackupHash = hash;
    saveAutoBackupSnapshot('Backup otomatis terjadwal', json);
    console.log(`[AutoBackup] Snapshot tersimpan (${fmtBytes(new Blob([json]).size)})`);
  }catch(e){ console.warn('AutoBackup check gagal', e); }
}

function startAutoBackupScheduler(){
  if(_autoBackupTimer) clearInterval(_autoBackupTimer);
  _autoBackupTimer = setInterval(runAutoBackupCheck, BACKUP_AUTO_INTERVAL_MIN*60*1000);
  // Jalankan sekali di awal juga (baseline)
  _lastAutoBackupHash = simpleChecksum(JSON.stringify(DB));
}

/** Restore dari snapshot otomatis tertentu */
function restoreFromAutoSnapshot(snapshotId){
  const snapshots = getAutoBackupSnapshots();
  const snap = snapshots.find(s=>s.id===snapshotId);
  if(!snap){ showToast('Snapshot tidak ditemukan.'); return; }
  if(!confirm(`Pulihkan dari snapshot otomatis ${fmtDate(snap.tanggal.slice(0,10))} ${new Date(snap.tanggal).toLocaleTimeString('id-ID')}? Data saat ini akan di-backup dulu sebagai safety net.`)) return;

  try{
    const data = JSON.parse(snap.data);
    const validation = validateRestoreData(data);
    if(!validation.valid){
      alert('Snapshot ini tidak valid dan tidak bisa dipulihkan:\\n'+validation.errors.join('\\n'));
      return;
    }
    window._pendingRestoreData = data;
    commitRestore();
  }catch(e){
    showToast('Gagal memulihkan snapshot — data mungkin korup.');
  }
}

function deleteAutoSnapshot(snapshotId){
  if(!confirm('Hapus snapshot otomatis ini?')) return;
  const snapshots = getAutoBackupSnapshots().filter(s=>s.id!==snapshotId);
  localStorage.setItem(AUTO_BACKUP_KEY, JSON.stringify(snapshots));
  renderBackupEnterprise();
  showToast('Snapshot dihapus.');
}

